let rawPending = flow.get(rawPendingKey);
if (!rawPending || typeof rawPending !== "object") rawPending = { active: false };

const pendingAge = Date.now() - Number(rawPending.ts || 0);

if (rawPending.active === true && pendingAge > 15000) {
  rawPending = { active: false };
  flow.set(rawPendingKey, rawPending);
