if (msg._raw_manual === true) {
  data.diag.raw_command = rawCommand || pendingCommand || "";
  data.diag._last_raw_command_ts = Date.now();

  rawPending = {
    active: true,
    command: rawCommand || pendingCommand || "",
    ts: Date.now()
  };
  flow.set(rawPendingKey, rawPending);
}
else if (
  rawPending.active === true &&
  (rawResponse || rawResponseHex) &&
  pendingCommand &&
  rawCommand &&
  rawCommand === pendingCommand
) {
  data.diag.raw_command = pendingCommand;
  data.diag._last_raw_command_ts = Number(rawPending.ts || Date.now());

  if (rawResponse) {
    data.diag.raw_response = rawResponse;
    data.diag._last_raw_response_ts = Date.now();
  }

  if (rawResponseHex) {
    data.diag.raw_response_hex = rawResponseHex;
    data.diag._last_raw_response_hex_ts = Date.now();
