if (qpiri.max_ac_charging_current === undefined) {
  delete qpiri.max_ac_charging_current;
}
if (qpiri.max_charging_current === undefined) {
  delete qpiri.max_charging_current;
}

ensure(qpiri, "max_discharging_current");
ensure(qpiri, "ts", 0);

ensure(qdop, "battery_recharge_capacity_pct");
ensure(qdop, "battery_redischarge_capacity_pct");
