  if (!data.bms || typeof data.bms !== "object") data.bms = {};
  if (!data.q1 || typeof data.q1 !== "object") data.q1 = {};
  if (!data.diag || typeof data.diag !== "object") data.diag = {};

  // -------------------------------------------------
  // BMS : on garde uniquement ce qui est demandé
  // -------------------------------------------------
  const cleanBms = {
