            candidates: [
                // priorité voulue : tester d'abord MUCHGC0002 / format 4 digits
                { key: "MUCHGC_4", build: (v) => `MUCHGC${String(Math.trunc(Number(v))).padStart(4, "0")}` },

                // puis fallback formats alternatifs
                { key: "MUCHGC_3", build: (v) => `MUCHGC${String(Math.trunc(Number(v))).padStart(3, "0")}` },
                { key: "MUCHGC_2", build: (v) => `MUCHGC${String(Math.trunc(Number(v))).padStart(2, "0")}` },
                { key: "MUCHGC_RAW", build: (v) => `MUCHGC${Math.trunc(Number(v))}` },
                { key: "PBCCHGC", build: (v) => `PBCCHGC${pad3(v)}` }
            ]
        },

        output_source_priority: {
            kind: "enum_profile_detect",
            statePath: "params.qpiri.output_source_priority_code",
            family: "POP",
            defaultProfile: "pop_01_03",
            applyByProfile: {
                pop_00_02: {
                    0: { command: "POP00", expectedCode: 0 },
                    1: { command: "POP01", expectedCode: 1 },
                    2: { command: "POP02", expectedCode: 2 }
                },
                pop_01_03: {
                    0: { command: "POP01", expectedCode: 1 },
                    1: { command: "POP02", expectedCode: 2 },
                    2: { command: "POP03", expectedCode: 3 }
                }
            },
            detect: {
                low: { command: "POP00", expectedCode: 0, profileKey: "pop_00_02" },
                high: { command: "POP03", expectedCode: 3, profileKey: "pop_01_03" }
            }
        },

        charger_source_priority: {
            kind: "enum_profile_detect",
            statePath: "params.qpiri.charger_source_priority_code",
            family: "PCP",
            defaultProfile: "pcp_01_03",
            applyByProfile: {
                pcp_00_02: {
                    0: { command: "PCP00", expectedCode: 0 },
                    1: { command: "PCP01", expectedCode: 1 },
                    2: { command: "PCP02", expectedCode: 2 }
                },
                pcp_01_03: {
                    0: { command: "PCP01", expectedCode: 1 },
                    1: { command: "PCP02", expectedCode: 2 },
                    2: { command: "PCP03", expectedCode: 3 }
                }
            },
            detect: {
                low: { command: "PCP00", expectedCode: 0, profileKey: "pcp_00_02" },
                high: { command: "PCP03", expectedCode: 3, profileKey: "pcp_01_03" }
            }
        }
    };
}

// -------------------------------------------------
// Session
// -------------------------------------------------
const sessionKey = `learn_session_inv${inv}`;
const pendingLearnKey = `learn_pending_inv${inv}`;

let session = flow.get(sessionKey);
if (!session || session.active !== true) return null;

const registry = getRegistry(inv);
const cfg = registry[session.param];
if (!cfg) return null;

// -------------------------------------------------
// Helpers fail msg
// -------------------------------------------------
function buildFailMsg(reason) {
    return {
        inverterNum: inv,
        topic: `voltronic/${inv}/learning/status`,
        payload: {
            active: false,
            success: false,
            reason,
            param: session.param,
            requested_value: session.requestedValue ?? null,
            requested_slot: session.requestedSlot ?? null,
            fingerprint: session.fingerprint,
            finished_at: new Date().toISOString()
        },
        _learn_complete: true,
        _learn_success: false
    };
}

// -------------------------------------------------
// Anti boucle dure
// -------------------------------------------------
function antiLoopCheck(cmd, label) {
    const now = Date.now();
    const prev = session._loopGuard || {
        lastCommand: null,
        count: 0,
        firstTs: 0
    };

    if (prev.lastCommand === cmd && (now - Number(prev.firstTs || 0)) < 8000) {
        prev.count = Number(prev.count || 0) + 1;
    } else {
        prev.lastCommand = cmd;
        prev.count = 1;
        prev.firstTs = now;
    }

    session._loopGuard = prev;

    if (prev.count > 3) {
        session.phase = "failed";
        flow.set(sessionKey, session);
        flow.set(pendingLearnKey, null);

        node.status({
            fill: "red",
            shape: "ring",
            text: `loop stop ${label || session.param}`
        });

        return buildFailMsg(`same_command_loop_${cmd}`);
    }

    return null;
}

// -------------------------------------------------
// MODE NUMERIQUE
// -------------------------------------------------
if (session.kind === "number") {
    const currentIndex = Number(session.index);
    session.index = (Number.isFinite(currentIndex) ? currentIndex : -1) + 1;
    session.updatedAt = Date.now();

    if (!Array.isArray(session.candidateKeys)) {
        return [null, buildFailMsg("invalid_candidate_list")];
    }

    if (session.index >= session.candidateKeys.length) {
        node.status({
            fill: "red",
            shape: "ring",
            text: `learn fail ${session.param}`
        });
        return [null, buildFailMsg("no_candidate_left")];
    }

    const wanted = session.candidateKeys[session.index];
    const candidate = Array.isArray(cfg.candidates)
        ? cfg.candidates.find(c => c.key === wanted.key)
        : null;

    if (!candidate || typeof candidate.build !== "function") {
        flow.set(sessionKey, session);
        return [{
            inverterNum: inv,
            _learn_action: "next_candidate",
            _learn: { sessionId: session.sessionId }
        }, null];
    }

    const cmd = candidate.build(session.requestedValue);

    const loopFail = antiLoopCheck(cmd, candidate.key);
    if (loopFail) return [null, loopFail];

    session.currentCandidate = {
        mode: "number",
        key: candidate.key,
        source: wanted.source,
        command: cmd,
        sentAt: Date.now()
    };

    session.phase = "wait_ack";
    session.lastAck = null;

    flow.set(sessionKey, session);
    flow.set(pendingLearnKey, {
        sessionId: session.sessionId,
        param: session.param,
        cmd: cmd,
        phase: "wait_ack",
        ts: Date.now()
    });

    flow.set(`inv${inv}_poll_pause_until`, Date.now() + 2500);

    const out = {
        inverterNum: inv,
        command: cmd,
        _cmd: cmd,
        _raw_command: cmd,
        payload: cmd,
        _burst: false,
        _origin: "learn_retry",
        _ha_param: session.paramRaw || session.param,
        _ha_value: session.requestedRaw,
        _learn: {
            sessionId: session.sessionId,
            param: session.param,
            requestedValue: session.requestedValue,
            candidateKey: candidate.key,
            source: wanted.source,
            phase: "candidate"
        }
    };

    node.status({
        fill: "yellow",
        shape: "dot",
        text: `learn try ${candidate.key}`
    });

    return [out, null];
}

// -------------------------------------------------
// MODE DETECTION / REAPPLY PROFIL ENUM
// -------------------------------------------------
if (session.kind === "enum_profile_detect") {
    const detectState = session.detectState || {
        phase: "normal",
        preferredProfile: cfg.defaultProfile || null,
        resolvedProfile: null,
        lastVerifiedCode: null,
        probeHighAck: false,
        probeHighNak: false,
        probeLowAck: false,
        probeLowNak: false
    };

    let cmd = null;
    let expectedCode = null;
    let profileKey = null;
    let candidateLabel = null;

    if (detectState.phase === "normal") {
        const requestedSlot = Number(session.requestedSlot);
        const preferred =
            detectState.resolvedProfile ||
            detectState.preferredProfile ||
            cfg.defaultProfile ||
            null;

        if (
            preferred &&
            cfg.applyByProfile?.[preferred] &&
            cfg.applyByProfile[preferred][requestedSlot]
        ) {
            const slotCfg = cfg.applyByProfile[preferred][requestedSlot];
            cmd = slotCfg.command;
            expectedCode = Number(slotCfg.expectedCode);
            profileKey = preferred;
            candidateLabel = `normal_${preferred}`;
        } else {
            return [null, buildFailMsg("invalid_requested_slot")];
        }

        session.currentCandidate = {
            mode: "profile_detect",
            phase: "normal",
            command: cmd,
            expectedCode,
            profileKey,
            requestedSlot,
            sentAt: Date.now()
        };
    }

    else if (detectState.phase === "probe_low") {
        cmd = cfg.detect.low.command;
        expectedCode = cfg.detect.low.expectedCode;
        profileKey = cfg.detect.low.profileKey;
        candidateLabel = "probe_low_00";

        session.currentCandidate = {
            mode: "profile_detect",
            phase: "probe_low",
            command: cmd,
            expectedCode,
            profileKey,
            requestedSlot: session.requestedSlot,
            sentAt: Date.now()
        };
    }

    else if (detectState.phase === "probe_high") {
        if (isBanned(session, cfg.detect.high.command)) {
            return [null, buildFailMsg("high_probe_banned")];
        }

        cmd = cfg.detect.high.command;
        expectedCode = cfg.detect.high.expectedCode;
        profileKey = cfg.detect.high.profileKey;
        candidateLabel = "probe_high_03";

        session.currentCandidate = {
            mode: "profile_detect",
            phase: "probe_high",
            command: cmd,
            expectedCode,
            profileKey,
            requestedSlot: session.requestedSlot,
            sentAt: Date.now()
        };
    }

    else if (detectState.phase === "reapply_final") {
        const resolved = detectState.resolvedProfile;
        const requestedSlot = Number(session.requestedSlot);
        const slotCfg = cfg.applyByProfile?.[resolved]?.[requestedSlot];

        if (!resolved || !slotCfg) {
            return [null, buildFailMsg("invalid_reapply_profile")];
        }

        cmd = slotCfg.command;
        expectedCode = Number(slotCfg.expectedCode);
        profileKey = resolved;
        candidateLabel = "reapply_final_value";

        session.currentCandidate = {
            mode: "profile_detect",
            phase: "reapply_final",
            command: cmd,
            expectedCode,
            profileKey,
            requestedSlot,
            sentAt: Date.now()
        };
    }

    else {
        return [null, buildFailMsg("invalid_detect_phase")];
    }

    const loopFail = antiLoopCheck(cmd, candidateLabel);
    if (loopFail) return [null, loopFail];

    session.phase = "wait_ack";
    session.lastAck = null;
    session.updatedAt = Date.now();

    flow.set(sessionKey, session);
    flow.set(pendingLearnKey, {
        sessionId: session.sessionId,
        param: session.param,
        cmd: cmd,
        phase: "wait_ack",
        ts: Date.now()
    });

    flow.set(`inv${inv}_poll_pause_until`, Date.now() + 2500);

    const out = {
        inverterNum: inv,
        command: cmd,
        _cmd: cmd,
        _raw_command: cmd,
        payload: cmd,
        _burst: false,
        _origin: "learn_retry",
        _ha_param: session.paramRaw || session.param,
        _ha_value: session.requestedRaw,
        _learn: {
            sessionId: session.sessionId,
            param: session.param,
            requestedSlot: session.requestedSlot,
            detectPhase: detectState.phase,
            expectedCode,
            profileKey,
            candidateLabel,
            phase: "candidate"
        }
    };

    node.status({
        fill: "yellow",
        shape: "dot",
        text: `learn try ${candidateLabel}`
    });

    return [out, null];
}

return null;

// ====== LEARNING - RX FEEDBACK ======
// Entrées possibles:
// - Parser sortie 2
// - Queue Pump timeout sortie 2
//
// Sortie 1 = enqueue QPIRI verify
// Sortie 2 = next candidate / fail

const inv = msg.inverterNum ?? 1;
const sessionKey = `learn_session_inv${inv}`;
const pendingLearnKey = `learn_pending_inv${inv}`;

function cleanUpper(v) {
    return String(v ?? "").trim().toUpperCase();
}

function cleanResp(v) {
    return String(v ?? "")
        .trim()
        .replace(/^\(/, "")
        .trim()
        .toUpperCase();
}

function ensureArray(arr) {
    return Array.isArray(arr) ? arr : [];
}

function addUnique(arr, value) {
    const v = cleanUpper(value);
    const out = ensureArray(arr).map(x => cleanUpper(x));
    if (v && !out.includes(v)) out.push(v);
    return out;
}

function buildFailMsg(session, reason) {
    return {
        inverterNum: inv,
        topic: `voltronic/${inv}/learning/status`,
        payload: {
            active: false,
            success: false,
            reason,
            param: session.param,
            requested_slot: session.requestedSlot ?? null,
            requested_value: session.requestedValue ?? null,
            fingerprint: session.fingerprint,
            finished_at: new Date().toISOString()
        },
        _learn_complete: true,
        _learn_success: false
    };
}

let session = flow.get(sessionKey);
if (!session || session.active !== true) return null;

const pending = flow.get(pendingLearnKey) || null;

const currentCmd = cleanUpper(session.currentCandidate?.command || "");
const msgCmd = cleanUpper(
    msg._raw_command ||
    msg.command ||
    msg._cmd ||
    msg.payload?.raw_command ||
    msg.payload?.command
);

const pendingCmd = cleanUpper(pending?.cmd || "");

const rawResp = cleanResp(
    msg._raw_response ??
    msg.raw_response ??
    msg.payload?.raw_response ??
    msg.payload?.raw ??
    ""
);

const isTimeout = (msg._learn_timeout === true || msg.payload?.timeout === true);

const isNak =
    msg.payload?.nak === true ||
    rawResp.startsWith("NAK");

const isAck =
    !isTimeout &&
    !isNak &&
    (
        rawResp.startsWith("ACK") ||
        msg.payload?.nak === false
    );

function markResolvedProfile(session, profileKey) {
    const ds = session.detectState || {};
    ds.resolvedProfile = profileKey;

    if (profileKey === "pop_00_02" || profileKey === "pcp_00_02") {
        session.rangeStart = 0;
        session.rangeEnd = 2;
    } else if (profileKey === "pop_01_03" || profileKey === "pcp_01_03") {
        session.rangeStart = 1;
        session.rangeEnd = 3;
    }

    session.detectState = ds;
}

function advanceDetectPhaseOnFailure(session, reasonType = "") {
    if (session.kind !== "enum_profile_detect") {
        session.phase = "build";
        return { type: "next" };
    }

    const detectState = session.detectState || {
        phase: "normal",
        preferredProfile: null,
        resolvedProfile: null,
        lastVerifiedCode: null,
        probeHighAck: false,
        probeHighNak: false,
        probeLowAck: false,
        probeLowNak: false
    };

    const currentCommand = cleanUpper(session.currentCandidate?.command || "");
    const phase = cleanUpper(session.currentCandidate?.phase || detectState.phase || "");

    // -------------------------------------------------
    // Si le 03 échoue => plage basse
    // -------------------------------------------------
    if ((isNak || isTimeout) && (currentCommand === "POP03" || currentCommand === "PCP03")) {
        session.bannedCommands = addUnique(session.bannedCommands, currentCommand);
        detectState.probeHighNak = true;

        if (currentCommand === "POP03") {
            markResolvedProfile(session, "pop_00_02");
        } else if (currentCommand === "PCP03") {
            markResolvedProfile(session, "pcp_00_02");
        }

        detectState.phase = "reapply_final";
        session.detectState = detectState;
        session.phase = "build";
        return { type: "next" };
    }

    // -------------------------------------------------
    // Si le 00 échoue => plage haute
    // -------------------------------------------------
    if ((isNak || isTimeout) && (currentCommand === "POP00" || currentCommand === "PCP00")) {
        detectState.probeLowNak = true;

        if (currentCommand === "POP00") {
            markResolvedProfile(session, "pop_01_03");
        } else if (currentCommand === "PCP00") {
            markResolvedProfile(session, "pcp_01_03");
        }

        detectState.phase = "reapply_final";
        session.detectState = detectState;
        session.phase = "build";
        return { type: "next" };
    }

    // -------------------------------------------------
    // Si la tentative normale échoue, on force une vraie détection :
    // 1) probe_low (00)
    // 2) probe_high (03)
    // -------------------------------------------------
    if (phase === "NORMAL" || detectState.phase === "normal") {
        detectState.phase = "probe_low";
        session.detectState = detectState;
        session.phase = "build";
        return { type: "next" };
    }

    if (phase === "PROBE_LOW" || detectState.phase === "probe_low") {
        detectState.phase = "probe_high";
        session.detectState = detectState;
        session.phase = "build";
        return { type: "next" };
    }

    if (phase === "PROBE_HIGH" || detectState.phase === "probe_high") {
        session.detectState = detectState;
        session.phase = "failed";
        return { type: "fail", reason: reasonType || "probe_high_failed" };
    }

    if (phase === "REAPPLY_FINAL" || detectState.phase === "reapply_final") {
        session.detectState = detectState;
        session.phase = "failed";
        return { type: "fail", reason: reasonType || "reapply_failed" };
    }

    session.phase = "failed";
    return { type: "fail", reason: reasonType || "invalid_detect_phase" };
}

// -------------------------
// PHASE 1 : wait_ack
// -------------------------
if (session.phase === "wait_ack") {
    let cmdMatches = false;

    if (pendingCmd && msgCmd && pendingCmd === msgCmd) {
        cmdMatches = true;
    } else if (currentCmd && msgCmd && currentCmd === msgCmd) {
        cmdMatches = true;
    }

    if (isTimeout) {
        if (pendingCmd && currentCmd && pendingCmd === currentCmd) {
            cmdMatches = true;
        } else if (!pendingCmd && currentCmd) {
            cmdMatches = true;
        }
    }

    if (!cmdMatches) return null;

    if (isTimeout) {
        session.lastAck = "TIMEOUT";
        session.updatedAt = Date.now();

        const step = advanceDetectPhaseOnFailure(session, "candidate_timeout");

        flow.set(sessionKey, session);
        flow.set(pendingLearnKey, null);

        if (step.type === "fail") {
            node.status({ fill: "red", shape: "ring", text: `learn fail ${session.param}` });
            return [null, buildFailMsg(session, step.reason || "candidate_timeout")];
        }

        node.status({ fill: "red", shape: "ring", text: `learn timeout ${session.param}` });

        return [null, {
            inverterNum: inv,
            _learn_action: "next_candidate",
            _learn: { sessionId: session.sessionId }
        }];
    }

    if (isNak) {
        session.lastAck = "NAK";
        session.updatedAt = Date.now();

        const currentCommand = cleanUpper(session.currentCandidate?.command || "");
        if (currentCommand === "POP03" || currentCommand === "PCP03") {
            session.bannedCommands = addUnique(session.bannedCommands, currentCommand);
        }

        const step = advanceDetectPhaseOnFailure(session, "candidate_nak");

        flow.set(sessionKey, session);
        flow.set(pendingLearnKey, null);

        if (step.type === "fail") {
            node.status({ fill: "red", shape: "ring", text: `learn fail ${session.param}` });
            return [null, buildFailMsg(session, step.reason || "candidate_nak")];
        }

        node.status({
            fill: "yellow",
            shape: "ring",
            text: `learn NAK ${session.currentCandidate?.command || session.param}`
        });

        return [null, {
            inverterNum: inv,
            _learn_action: "next_candidate",
            _learn: { sessionId: session.sessionId }
        }];
    }

    if (isAck) {
        session.lastAck = "ACK";
        session.phase = "wait_state";
        session.verifySentAt = Date.now();
        session.updatedAt = Date.now();

        const currentCommand = cleanUpper(session.currentCandidate?.command || "");
        const currentPhase = cleanUpper(session.currentCandidate?.phase || "");

        const ds = session.detectState || {};
        if (currentCommand === "POP03" || currentCommand === "PCP03") ds.probeHighAck = true;
        if (currentCommand === "POP00" || currentCommand === "PCP00") ds.probeLowAck = true;
        session.detectState = ds;

        flow.set(sessionKey, session);
        flow.set(pendingLearnKey, {
            sessionId: session.sessionId,
            param: session.param,
            cmd: "QPIRI",
            phase: "wait_state",
            ts: Date.now()
        });

        const verifyMsg = {
            inverterNum: inv,
            command: "QPIRI",
            _cmd: "QPIRI",
            _raw_command: "QPIRI",
            payload: "QPIRI",
            _burst: false,
            _origin: "learn_retry",
            _learn: {
                sessionId: session.sessionId,
                param: session.param,
                requestedValue: session.requestedValue ?? null,
                requestedSlot: session.requestedSlot ?? null,
                candidateKey: session.currentCandidate?.key || null,
                profileKey: session.currentCandidate?.profileKey || null,
                detectPhase: currentPhase || session.detectState?.phase || null,
                phase: "verify"
            }
        };

        node.status({
            fill: "blue",
            shape: "dot",
            text: `learn verify ${session.param}`
        });

        return [verifyMsg, null];
    }

    return null;
}

// -------------------------
// PHASE 2 : wait_state
// -------------------------
if (session.phase === "wait_state") {
    const waitingForQpiri = (pendingCmd === "QPIRI");
    if (!waitingForQpiri) return null;

    if (isTimeout) {
        session.lastAck = "QPIRI_TIMEOUT";
        session.updatedAt = Date.now();

        const step = advanceDetectPhaseOnFailure(session, "verify_timeout");

        flow.set(sessionKey, session);
        flow.set(pendingLearnKey, null);

        if (step.type === "fail") {
            node.status({ fill: "red", shape: "ring", text: `learn fail ${session.param}` });
            return [null, buildFailMsg(session, step.reason || "verify_timeout")];
        }

        node.status({
            fill: "red",
            shape: "ring",
            text: `verify timeout ${session.param}`
        });

        return [null, {
            inverterNum: inv,
            _learn_action: "next_candidate",
            _learn: { sessionId: session.sessionId }
        }];
    }

    return null;
}

return null;

// ====== LEARNING - STATE FEEDBACK ======
// Sortie 1 = complete success
// Sortie 2 = next candidate / next detect phase

const inv = msg.inverterNum ?? 1;
const sessionKey = `learn_session_inv${inv}`;
const pendingLearnKey = `learn_pending_inv${inv}`;

function getByPath(obj, path) {
    if (!obj || !path) return undefined;
    return path.split(".").reduce((acc, k) => acc && acc[k], obj);
}

function toNum(v) {
    const n = Number(v);
    return Number.isFinite(n) ? n : null;
}

function isEqual(a, b, tol) {
    const na = toNum(a);
    const nb = toNum(b);
    if (na == null || nb == null) return false;
    return Math.abs(na - nb) <= tol;
}

function addNumUnique(arr, value) {
    const out = Array.isArray(arr) ? [...arr] : [];
    const n = Number(value);
    if (Number.isFinite(n) && !out.includes(n)) out.push(n);
    return out.sort((a, b) => a - b);
}

function markResolvedProfile(session, profileKey) {
    const ds = session.detectState || {};
    ds.resolvedProfile = profileKey;

    if (profileKey === "pop_00_02" || profileKey === "pcp_00_02") {
        session.rangeStart = 0;
        session.rangeEnd = 2;
    } else if (profileKey === "pop_01_03" || profileKey === "pcp_01_03") {
        session.rangeStart = 1;
        session.rangeEnd = 3;
    }

    session.detectState = ds;
}

const session = flow.get(sessionKey);
if (!session || session.active !== true) return null;

if (session.phase !== "wait_state") return null;

const pending = flow.get(pendingLearnKey) || null;
const pendingCmd = String(pending?.cmd || "").trim().toUpperCase();
if (pendingCmd !== "QPIRI") return null;

const state = msg.payload;
if (!state || typeof state !== "object") return null;

const ageSinceVerify = Date.now() - Number(session.verifySentAt || 0);
if (ageSinceVerify < 1200) {
    return null;
}

// -------------------------
// MODE NUMERIQUE
// -------------------------
if (session.kind === "number") {
    const actualValue = getByPath(state, session.statePath);

    if (isEqual(actualValue, session.requestedValue, session.tolerance)) {
        flow.set(pendingLearnKey, null);

        const okMsg = {
            inverterNum: inv,
            topic: `voltronic/${inv}/learning/status`,
            payload: {
                active: false,
                success: true,
                param: session.param,
                candidate_key: session.currentCandidate?.key || null,
                command: session.currentCandidate?.command || null,
                requested_value: session.requestedValue,
                verified_value: actualValue,
                fingerprint: session.fingerprint,
                finished_at: new Date().toISOString()
            },
            _learn_complete: true,
            _learn_success: true
        };

        node.status({ fill: "green", shape: "dot", text: `learn OK ${session.param}` });
        return [okMsg, null];
    }

    flow.set(pendingLearnKey, null);

    node.status({ fill: "yellow", shape: "ring", text: `learn next ${session.param}` });
    return [null, {
        inverterNum: inv,
        _learn_action: "next_candidate",
        _learn: { sessionId: session.sessionId }
    }];
}

// -------------------------
// MODE DETECTION PROFIL ENUM + REAPPLY
// -------------------------
if (session.kind === "enum_profile_detect") {
    const actualCode = toNum(getByPath(state, session.statePath));
    const detectState = session.detectState || {
        phase: "normal",
        preferredProfile: null,
        resolvedProfile: null,
        lastVerifiedCode: null,
        probeHighAck: false,
        probeHighNak: false,
        probeLowAck: false,
        probeLowNak: false
    };

    detectState.lastVerifiedCode = actualCode;
    session.detectState = detectState;
    session.supportedCodes = addNumUnique(session.supportedCodes, actualCode);

    const currentPhase = String(session.currentCandidate?.phase || detectState.phase || "").trim().toLowerCase();
    const expectedCode = toNum(session.currentCandidate?.expectedCode);

    // -------------------------------------------------
    // normal:
    // si le code correspond, succès direct
    // sinon on lance une vraie détection par 00
    // -------------------------------------------------
    if (currentPhase === "normal") {
        if (actualCode != null && expectedCode != null && actualCode === expectedCode) {
            markResolvedProfile(
                session,
                session.currentCandidate?.profileKey ||
                detectState.resolvedProfile ||
                detectState.preferredProfile ||
                null
            );

            flow.set(sessionKey, session);
            flow.set(pendingLearnKey, null);

            const okMsg = {
                inverterNum: inv,
                topic: `voltronic/${inv}/learning/status`,
                payload: {
                    active: false,
                    success: true,
                    param: session.param,
                    profile_key: session.detectState?.resolvedProfile || null,
                    command: session.currentCandidate?.command || null,
                    requested_slot: session.requestedSlot,
                    verified_code: actualCode,
                    expected_code: expectedCode,
                    fingerprint: session.fingerprint,
                    finished_at: new Date().toISOString()
                },
                _learn_complete: true,
                _learn_success: true
            };

            node.status({ fill: "green", shape: "dot", text: `learn OK ${session.param}` });
            return [okMsg, null];
        }

        detectState.phase = "probe_low";
        session.detectState = detectState;
        session.updatedAt = Date.now();

        flow.set(sessionKey, session);
        flow.set(pendingLearnKey, null);

        node.status({ fill: "yellow", shape: "ring", text: `probe low ${session.param}` });
        return [null, {
            inverterNum: inv,
            _learn_action: "next_candidate",
            _learn: { sessionId: session.sessionId }
        }];
    }

    // -------------------------------------------------
    // probe_low:
    // si QPIRI lit 0 => plage basse confirmée
    // sinon on tente probe_high
    // -------------------------------------------------
    if (currentPhase === "probe_low") {
        if (actualCode === 0) {
            markResolvedProfile(
                session,
                session.currentCandidate?.profileKey || detectState.resolvedProfile || "pop_00_02"
            );
            detectState.phase = "reapply_final";

            session.detectState = detectState;
            session.updatedAt = Date.now();

            flow.set(sessionKey, session);
            flow.set(pendingLearnKey, null);

            node.status({ fill: "blue", shape: "dot", text: `reapply ${session.param}` });
            return [null, {
                inverterNum: inv,
                _learn_action: "next_candidate",
                _learn: { sessionId: session.sessionId }
            }];
        }

        detectState.phase = "probe_high";
        session.detectState = detectState;
        session.updatedAt = Date.now();

        flow.set(sessionKey, session);
        flow.set(pendingLearnKey, null);

        node.status({ fill: "yellow", shape: "ring", text: `probe high ${session.param}` });
        return [null, {
            inverterNum: inv,
            _learn_action: "next_candidate",
            _learn: { sessionId: session.sessionId }
        }];
    }

    // -------------------------------------------------
    // probe_high:
    // si QPIRI lit 3 => plage haute confirmée
    // sinon échec
    // -------------------------------------------------
    if (currentPhase === "probe_high") {
        if (actualCode === 3) {
            markResolvedProfile(
                session,
                session.currentCandidate?.profileKey || detectState.resolvedProfile || "pop_01_03"
            );
            detectState.phase = "reapply_final";

            session.detectState = detectState;
            session.updatedAt = Date.now();

            flow.set(sessionKey, session);
            flow.set(pendingLearnKey, null);

            node.status({ fill: "blue", shape: "dot", text: `reapply ${session.param}` });
            return [null, {
                inverterNum: inv,
                _learn_action: "next_candidate",
                _learn: { sessionId: session.sessionId }
            }];
        }

        flow.set(pendingLearnKey, null);

        node.status({ fill: "red", shape: "ring", text: `learn fail ${session.param}` });
        return [null, {
            inverterNum: inv,
            topic: `voltronic/${inv}/learning/status`,
            payload: {
                active: false,
                success: false,
                reason: "profile_not_resolved",
                param: session.param,
                requested_slot: session.requestedSlot,
                fingerprint: session.fingerprint,
                finished_at: new Date().toISOString()
            },
            _learn_complete: true,
            _learn_success: false
        }];
    }

    // -------------------------------------------------
    // reapply_final:
    // on valide que la vraie commande du slot demandé
    // donne bien le code attendu
    // -------------------------------------------------
    if (currentPhase === "reapply_final") {
        if (actualCode != null && expectedCode != null && actualCode === expectedCode) {
            flow.set(pendingLearnKey, null);

            const okMsg = {
                inverterNum: inv,
                topic: `voltronic/${inv}/learning/status`,
