// ====== LEARNING - PREPROCESS ======
// Sortie 1 = apprentissage
// Sortie 2 = bypass direct

const inv = msg.inverterNum ?? 1;

function cleanString(v) {
    return String(v ?? "").trim();
}

function toNum(x) {
    if (x == null) return null;
    if (typeof x === "string") {
        const s = cleanString(x);
        const m = s.match(/-?\d+(\.\d+)?/);
        if (!m) return null;
        x = m[0];
    }
    const n = Number(x);
    return Number.isFinite(n) ? n : null;
}

function clone(obj) {
    return JSON.parse(JSON.stringify(obj || {}));
}

function getByPath(obj, path) {
    if (!obj || !path) return undefined;
    return path.split(".").reduce((acc, k) => acc && acc[k], obj);
}

function getFingerprint(state) {
    const model = cleanString(state?.diag?.model);
    const serial = cleanString(state?.diag?.serial);
    const fw = cleanString(state?.diag?.fw_main);

    if (serial) return `SERIAL:${serial}`;
    if (model && fw) return `MODELFW:${model}|${fw}`;
    if (model) return `MODEL:${model}`;
    if (fw) return `FW:${fw}`;

    return "";
}

function canonParam(p) {
    const map = {
        battery_bulk_voltage: "battery_bulk_voltage",
        battery_float_voltage: "battery_float_voltage",

        battery_cutoff_voltage: "battery_under_voltage",
        battery_under_voltage: "battery_under_voltage",

        back_to_grid_voltage: "battery_recharge_voltage",
        battery_recharge_voltage: "battery_recharge_voltage",

        back_to_battery_voltage: "battery_re_discharge_voltage",
        battery_re_discharge_voltage: "battery_re_discharge_voltage",

        max_charging_current: "max_charging_current",

        grid_charging_current: "max_ac_charging_current",
        max_ac_charging_current: "max_ac_charging_current",

        charger_source_priority: "charger_source_priority",
        output_source_priority: "output_source_priority"
    };

    return map[cleanString(p)] || cleanString(p);
}

function getRegistry() {
    return {
        battery_bulk_voltage: {
            kind: "number",
            statePath: "params.qpiri.battery_bulk_voltage",
            tolerance: 0.05
        },
        battery_float_voltage: {
            kind: "number",
            statePath: "params.qpiri.battery_float_voltage",
