    if (requestedValue == null) {
        node.status({ fill: "red", shape: "ring", text: `learn invalid ${param}` });
        return [null, null];
    }

    if (isEqual(currentValue, requestedValue, cfg.tolerance)) {
        node.status({
            fill: "green",
            shape: "dot",
            text: `already ${param}=${requestedValue}`
        });
        return [null, null];
