        fingerprint,
        statePath: cfg.statePath,
        tolerance: cfg.tolerance,
        kind: "number",
        createdAt: Date.now(),
        updatedAt: Date.now()
    };

    node.status({
        fill: "blue",
        shape: "dot",
        text: `learn ${param} -> ${requestedValue}`
    });

