        fingerprint,
        statePath: cfg.statePath,
        kind: "enum_profile",
        createdAt: Date.now(),
        updatedAt: Date.now()
    };

    node.status({
        fill: "blue",
        shape: "dot",
        text: `learn ${param} slot ${requestedSlot}`
    });

    return [msg, null];
}

return [null, msg];

