            kind: "number",
            candidates: [
                { key: "FLOAT_PBFT", build: (v) => `PBFT${fixed1(v)}` }
            ]
        },

        battery_under_voltage: {
            kind: "number",
            candidates: [
                { key: "UNDER_PSDV", build: (v) => `PSDV${fixed1(v)}` }
            ]
        },

        battery_recharge_voltage: {
            kind: "number",
            candidates: [
                { key: "BACK_GRID_PBCV", build: (v) => `PBCV${fixed1(v)}` }
            ]
        },

        battery_re_discharge_voltage: {
            kind: "number",
            candidates: [
                { key: "BACK_BATT_PBDV", build: (v) => `PBDV${fixed1(v)}` }
            ]
        },

        max_charging_current: {
            kind: "number",
            candidates: [
                { key: "MNCHGC_3", build: (v) => `MNCHGC${pad3(v)}` },
                { key: "MNCHGC_MACHINE", build: (v) => `MNCHGC${machine}${pad3(v)}` },
                { key: "MNCHGC_RAW", build: (v) => `MNCHGC${Math.trunc(Number(v))}` },
                { key: "PBDCHGC", build: (v) => `PBDCHGC${pad3(v)}` }
            ]
        },

        max_ac_charging_current: {
            kind: "number",
            candidates: [
                // Ne pas casser les autres onduleurs :
                // on garde plusieurs formats, l'apprentissage choisira le bon
                { key: "MUCHGC_4", build: (v) => `MUCHGC${String(Math.trunc(Number(v))).padStart(4, "0")}` },
                { key: "MUCHGC_3", build: (v) => `MUCHGC${String(Math.trunc(Number(v))).padStart(3, "0")}` },
                { key: "MUCHGC_2", build: (v) => `MUCHGC${String(Math.trunc(Number(v))).padStart(2, "0")}` },
                { key: "MUCHGC_RAW", build: (v) => `MUCHGC${Math.trunc(Number(v))}` },
                { key: "PBCCHGC", build: (v) => `PBCCHGC${pad3(v)}` }
            ]
        },

        output_source_priority: {
            kind: "enum_profile_detect",
            statePath: "params.qpiri.output_source_priority_code",
            family: "POP",
            defaultProfile: "pop_01_03",
            applyByProfile: {
                pop_00_02: {
                    0: { command: "POP00", expectedCode: 0 },
                    1: { command: "POP01", expectedCode: 1 },
                    2: { command: "POP02", expectedCode: 2 }
                },
                pop_01_03: {
                    0: { command: "POP01", expectedCode: 1 },
                    1: { command: "POP02", expectedCode: 2 },
                    2: { command: "POP03", expectedCode: 3 }
                }
            },
            detect: {
                low: { command: "POP00", expectedCode: 0, profileKey: "pop_00_02" },
                high: { command: "POP03", expectedCode: 3, profileKey: "pop_01_03" }
            }
        },

        charger_source_priority: {
            kind: "enum_profile_detect",
            statePath: "params.qpiri.charger_source_priority_code",
            family: "PCP",
            defaultProfile: "pcp_01_03",
            applyByProfile: {
                pcp_00_02: {
                    0: { command: "PCP00", expectedCode: 0 },
                    1: { command: "PCP01", expectedCode: 1 },
                    2: { command: "PCP02", expectedCode: 2 }
                },
                pcp_01_03: {
                    0: { command: "PCP01", expectedCode: 1 },
                    1: { command: "PCP02", expectedCode: 2 },
                    2: { command: "PCP03", expectedCode: 3 }
                }
            },
            detect: {
                low: { command: "PCP00", expectedCode: 0, profileKey: "pcp_00_02" },
                high: { command: "PCP03", expectedCode: 3, profileKey: "pcp_01_03" }
            }
        }
    };
}

const registry = getRegistry(inv);
const param = cleanString(msg._learn.param);
const cfg = registry[param];
if (!cfg) return null;

// garde anti-reset de session
let existing = flow.get(sessionKey);
if (
    msg._learn_action === "next_candidate" &&
    existing &&
    existing.active === true &&
    existing.sessionId === msg._learn.sessionId
) {
    return msg;
}

const learnedAll = global.get("learned_commands") || {};
const fp = normalizeFingerprint(msg._learn.fingerprint);
const learnedForFp = (fp && learnedAll[fp]) ? learnedAll[fp] : {};
const learnedEntry = learnedForFp[param] || null;

const session = {
    active: true,
    sessionId: msg._learn.sessionId,
    inverterNum: inv,
    param,
    paramRaw: cleanString(msg._learn.paramRaw),
    requestedRaw: msg._learn.requestedRaw,
    baselineValue: msg._learn.baselineValue,
    fingerprint: fp,
    statePath: msg._learn.statePath,
    kind: msg._learn.kind,
    createdAt: msg._learn.createdAt || Date.now(),
    updatedAt: Date.now(),
    index: -1,
    currentCandidate: null,
    phase: "build",
    lastAck: null,
    verifySentAt: 0,

    bannedCommands: Array.isArray(learnedEntry?.bannedCommands) ? [...learnedEntry.bannedCommands] : [],
    supportedCodes: Array.isArray(learnedEntry?.supportedCodes) ? [...learnedEntry.supportedCodes] : [],
    rangeStart: Number.isFinite(Number(learnedEntry?.rangeStart)) ? Number(learnedEntry.rangeStart) : null,
    rangeEnd: Number.isFinite(Number(learnedEntry?.rangeEnd)) ? Number(learnedEntry.rangeEnd) : null
};

// -------------------------------------------------
// MODE NUMERIQUE
// -------------------------------------------------
if (msg._learn.kind === "number") {
    session.requestedValue = msg._learn.requestedValue;
    session.tolerance = msg._learn.tolerance;

    let ordered = [];

    // si une commande a déjà été apprise pour ce fingerprint, on la tente d'abord
    if (learnedEntry && learnedEntry.key) {
        ordered.push({
            kind: "number_candidate",
            key: learnedEntry.key,
            source: "learned"
        });
    }

    // puis le registre complet
    for (const c of cfg.candidates) {
        if (!ordered.some(x => x.key === c.key)) {
            ordered.push({
                kind: "number_candidate",
                key: c.key,
                source: "registry"
            });
        }
    }

    session.candidateKeys = ordered;
}

// -------------------------------------------------
// MODE ENUM PROFILE
// -------------------------------------------------
if (msg._learn.kind === "enum_profile") {
    session.kind = "enum_profile_detect";
    session.requestedSlot = msg._learn.requestedSlot;

    let preferred = null;

    if (
        learnedEntry &&
        learnedEntry.mode === "profile" &&
        typeof learnedEntry.profileKey === "string" &&
        cleanString(learnedEntry.profileKey)
    ) {
        preferred = cleanString(learnedEntry.profileKey);
    }

    if (!preferred && typeof cfg.defaultProfile === "string" && cleanString(cfg.defaultProfile)) {
        preferred = cleanString(cfg.defaultProfile);
    }

    session.detectState = {
        phase: "normal",
        preferredProfile: preferred,
        resolvedProfile: null,
        lastVerifiedCode: null,
        probeHighAck: false,
        probeHighNak: false,
        probeLowAck: false,
        probeLowNak: false
    };
}

flow.set(sessionKey, session);

node.status({
    fill: "blue",
    shape: "dot",
    text: session.kind === "enum_profile_detect"
        ? `learn decision ${param} (${session.detectState?.preferredProfile || "auto"})`
        : `learn decision ${param}`
});

msg._learn_action = "next_candidate";
return msg;

// ====== LEARNING - RX FEEDBACK ======
// Entrées possibles:
// - Parser sortie 2
// - Queue Pump timeout sortie 2
//
// Sortie 1 = enqueue QPIRI verify
// Sortie 2 = next candidate / fail

const inv = msg.inverterNum ?? 1;
const sessionKey = `learn_session_inv${inv}`;
const pendingLearnKey = `learn_pending_inv${inv}`;

function cleanUpper(v) {
    return String(v ?? "").trim().toUpperCase();
}

function cleanResp(v) {
    return String(v ?? "")
        .trim()
        .replace(/^\(/, "")
        .trim()
        .toUpperCase();
}

function ensureArray(arr) {
    return Array.isArray(arr) ? arr : [];
}

function addUnique(arr, value) {
    const v = cleanUpper(value);
    const out = ensureArray(arr).map(x => cleanUpper(x));
    if (v && !out.includes(v)) out.push(v);
    return out;
}

function buildFailMsg(session, reason) {
    return {
        inverterNum: inv,
        topic: `voltronic/${inv}/learning/status`,
        payload: {
            active: false,
            success: false,
            reason,
            param: session.param,
            requested_slot: session.requestedSlot ?? null,
            requested_value: session.requestedValue ?? null,
            fingerprint: session.fingerprint,
            finished_at: new Date().toISOString()
        },
        _learn_complete: true,
        _learn_success: false
    };
}

let session = flow.get(sessionKey);
if (!session || session.active !== true) return null;

const pending = flow.get(pendingLearnKey) || null;

const currentCmd = cleanUpper(session.currentCandidate?.command || "");
const msgCmd = cleanUpper(
    msg._raw_command ||
    msg.command ||
    msg._cmd ||
    msg.payload?.raw_command ||
    msg.payload?.command
);

const pendingCmd = cleanUpper(pending?.cmd || "");

const rawResp = cleanResp(
    msg._raw_response ??
    msg.raw_response ??
    msg.payload?.raw_response ??
    msg.payload?.raw ??
    ""
);

const isTimeout = (msg._learn_timeout === true || msg.payload?.timeout === true);

const isNak =
    msg.payload?.nak === true ||
    rawResp.startsWith("NAK");

const isAck =
    !isTimeout &&
    !isNak &&
    (
        rawResp.startsWith("ACK") ||
        msg.payload?.nak === false
    );

function markResolvedProfile(session, profileKey) {
    const ds = session.detectState || {};
    ds.resolvedProfile = profileKey;

    if (profileKey === "pop_00_02" || profileKey === "pcp_00_02") {
        session.rangeStart = 0;
        session.rangeEnd = 2;
    } else if (profileKey === "pop_01_03" || profileKey === "pcp_01_03") {
        session.rangeStart = 1;
        session.rangeEnd = 3;
    }

    session.detectState = ds;
}

function advanceDetectPhaseOnFailure(session, reasonType = "") {
    if (session.kind !== "enum_profile_detect") {
        session.phase = "build";
        return { type: "next" };
    }

    const detectState = session.detectState || {
        phase: "normal",
        preferredProfile: null,
        resolvedProfile: null,
        lastVerifiedCode: null,
        probeHighAck: false,
        probeHighNak: false,
        probeLowAck: false,
        probeLowNak: false
    };

    const currentCommand = cleanUpper(session.currentCandidate?.command || "");
    const phase = cleanUpper(session.currentCandidate?.phase || detectState.phase || "");

    // -------------------------------------------------
    // Si le 03 échoue => plage basse
    // -------------------------------------------------
    if ((isNak || isTimeout) && (currentCommand === "POP03" || currentCommand === "PCP03")) {
        session.bannedCommands = addUnique(session.bannedCommands, currentCommand);
        detectState.probeHighNak = true;

        if (currentCommand === "POP03") {
            markResolvedProfile(session, "pop_00_02");
        } else if (currentCommand === "PCP03") {
            markResolvedProfile(session, "pcp_00_02");
        }

        detectState.phase = "reapply_final";
        session.detectState = detectState;
        session.phase = "build";
        return { type: "next" };
    }

    // -------------------------------------------------
    // Si le 00 échoue => plage haute
    // -------------------------------------------------
    if ((isNak || isTimeout) && (currentCommand === "POP00" || currentCommand === "PCP00")) {
        detectState.probeLowNak = true;

        if (currentCommand === "POP00") {
            markResolvedProfile(session, "pop_01_03");
        } else if (currentCommand === "PCP00") {
            markResolvedProfile(session, "pcp_01_03");
        }

        detectState.phase = "reapply_final";
        session.detectState = detectState;
        session.phase = "build";
        return { type: "next" };
    }

    // -------------------------------------------------
    // Si la tentative normale échoue, on force une vraie détection :
    // 1) probe_low (00)
    // 2) probe_high (03)
    // -------------------------------------------------
    if (phase === "NORMAL" || detectState.phase === "normal") {
        detectState.phase = "probe_low";
        session.detectState = detectState;
        session.phase = "build";
        return { type: "next" };
    }

    if (phase === "PROBE_LOW" || detectState.phase === "probe_low") {
        detectState.phase = "probe_high";
        session.detectState = detectState;
        session.phase = "build";
        return { type: "next" };
    }

    if (phase === "PROBE_HIGH" || detectState.phase === "probe_high") {
        session.detectState = detectState;
        session.phase = "failed";
        return { type: "fail", reason: reasonType || "probe_high_failed" };
    }

    if (phase === "REAPPLY_FINAL" || detectState.phase === "reapply_final") {
        session.detectState = detectState;
        session.phase = "failed";
        return { type: "fail", reason: reasonType || "reapply_failed" };
    }

    session.phase = "failed";
    return { type: "fail", reason: reasonType || "invalid_detect_phase" };
}

// -------------------------
// PHASE 1 : wait_ack
// -------------------------
if (session.phase === "wait_ack") {
    let cmdMatches = false;

    if (pendingCmd && msgCmd && pendingCmd === msgCmd) {
        cmdMatches = true;
    } else if (currentCmd && msgCmd && currentCmd === msgCmd) {
        cmdMatches = true;
    }

    if (isTimeout) {
        if (pendingCmd && currentCmd && pendingCmd === currentCmd) {
            cmdMatches = true;
        } else if (!pendingCmd && currentCmd) {
            cmdMatches = true;
        }
    }

    if (!cmdMatches) return null;

    if (isTimeout) {
        session.lastAck = "TIMEOUT";
        session.updatedAt = Date.now();

        const step = advanceDetectPhaseOnFailure(session, "candidate_timeout");

        flow.set(sessionKey, session);
        flow.set(pendingLearnKey, null);

        if (step.type === "fail") {
            node.status({ fill: "red", shape: "ring", text: `learn fail ${session.param}` });
            return [null, buildFailMsg(session, step.reason || "candidate_timeout")];
        }

        node.status({ fill: "red", shape: "ring", text: `learn timeout ${session.param}` });

        return [null, {
            inverterNum: inv,
            _learn_action: "next_candidate",
            _learn: { sessionId: session.sessionId }
        }];
    }

    if (isNak) {
        session.lastAck = "NAK";
        session.updatedAt = Date.now();

        const currentCommand = cleanUpper(session.currentCandidate?.command || "");
        if (currentCommand === "POP03" || currentCommand === "PCP03") {
            session.bannedCommands = addUnique(session.bannedCommands, currentCommand);
        }

        const step = advanceDetectPhaseOnFailure(session, "candidate_nak");

        flow.set(sessionKey, session);
        flow.set(pendingLearnKey, null);

        if (step.type === "fail") {
            node.status({ fill: "red", shape: "ring", text: `learn fail ${session.param}` });
            return [null, buildFailMsg(session, step.reason || "candidate_nak")];
        }

        node.status({
            fill: "yellow",
            shape: "ring",
            text: `learn NAK ${session.currentCandidate?.command || session.param}`
        });

        return [null, {
            inverterNum: inv,
            _learn_action: "next_candidate",
            _learn: { sessionId: session.sessionId }
        }];
    }

    if (isAck) {
        session.lastAck = "ACK";
        session.phase = "wait_state";
        session.verifySentAt = Date.now();
        session.updatedAt = Date.now();

        const currentCommand = cleanUpper(session.currentCandidate?.command || "");
        const currentPhase = cleanUpper(session.currentCandidate?.phase || "");

        const ds = session.detectState || {};
        if (currentCommand === "POP03" || currentCommand === "PCP03") ds.probeHighAck = true;
        if (currentCommand === "POP00" || currentCommand === "PCP00") ds.probeLowAck = true;
        session.detectState = ds;

        flow.set(sessionKey, session);
        flow.set(pendingLearnKey, {
            sessionId: session.sessionId,
            param: session.param,
            cmd: "QPIRI",
            phase: "wait_state",
            ts: Date.now()
        });

        const verifyMsg = {
            inverterNum: inv,
            command: "QPIRI",
            _cmd: "QPIRI",
            _raw_command: "QPIRI",
            payload: "QPIRI",
            _burst: false,
            _origin: "learn_retry",
            _learn: {
                sessionId: session.sessionId,
                param: session.param,
                requestedValue: session.requestedValue ?? null,
                requestedSlot: session.requestedSlot ?? null,
                candidateKey: session.currentCandidate?.key || null,
                profileKey: session.currentCandidate?.profileKey || null,
                detectPhase: currentPhase || session.detectState?.phase || null,
                phase: "verify"
            }
        };

        node.status({
            fill: "blue",
            shape: "dot",
            text: `learn verify ${session.param}`
        });

        return [verifyMsg, null];
    }

    return null;
}

// -------------------------
// PHASE 2 : wait_state
// -------------------------
if (session.phase === "wait_state") {
    const waitingForQpiri = (pendingCmd === "QPIRI");
    if (!waitingForQpiri) return null;

    if (isTimeout) {
        session.lastAck = "QPIRI_TIMEOUT";
        session.updatedAt = Date.now();

        const step = advanceDetectPhaseOnFailure(session, "verify_timeout");

        flow.set(sessionKey, session);
        flow.set(pendingLearnKey, null);

        if (step.type === "fail") {
            node.status({ fill: "red", shape: "ring", text: `learn fail ${session.param}` });
            return [null, buildFailMsg(session, step.reason || "verify_timeout")];
        }

        node.status({
            fill: "red",
            shape: "ring",
            text: `verify timeout ${session.param}`
        });

        return [null, {
            inverterNum: inv,
            _learn_action: "next_candidate",
            _learn: { sessionId: session.sessionId }
        }];
    }

    return null;
}

return null;

// ====== LEARNING - BUILD CANDIDATE ======
// Sortie 1 = queue enqueue
// Sortie 2 = complete fail

const inv = msg.inverterNum ?? 1;

// -------------------------------------------------
// Helpers
// -------------------------------------------------
function getParallelId(inv) {
    let machine = flow.get(`inv${inv}_parallel_id`);
    if (machine === undefined || machine === null || machine === "") machine = 0;
    machine = Number(machine);
    if (!Number.isFinite(machine) || machine < 0 || machine > 9) machine = 0;
    return machine;
}

function pad3(x) {
    return String(Math.trunc(Number(x))).padStart(3, "0");
}

function fixed1(x) {
    return Number(x).toFixed(1);
}

function isBanned(session, cmd) {
    const banned = Array.isArray(session?.bannedCommands) ? session.bannedCommands : [];
    return banned.includes(String(cmd || "").trim().toUpperCase());
}

function getRegistry(inv) {
    const machine = getParallelId(inv);

    return {
        battery_bulk_voltage: {
            kind: "number",
            candidates: [
                { key: "BULK_PCVV", build: (v) => `PCVV${fixed1(v)}` }
            ]
        },

        battery_float_voltage: {
            kind: "number",
            candidates: [
                { key: "FLOAT_PBFT", build: (v) => `PBFT${fixed1(v)}` }
            ]
        },

        battery_under_voltage: {
            kind: "number",
            candidates: [
                { key: "UNDER_PSDV", build: (v) => `PSDV${fixed1(v)}` }
            ]
        },

        battery_recharge_voltage: {
            kind: "number",
            candidates: [
                { key: "BACK_GRID_PBCV", build: (v) => `PBCV${fixed1(v)}` }
            ]
        },

        battery_re_discharge_voltage: {
            kind: "number",
            candidates: [
                { key: "BACK_BATT_PBDV", build: (v) => `PBDV${fixed1(v)}` }
            ]
        },

        max_charging_current: {
            kind: "number",
            candidates: [
                { key: "MNCHGC_3", build: (v) => `MNCHGC${pad3(v)}` },
                { key: "MNCHGC_MACHINE", build: (v) => `MNCHGC${machine}${pad3(v)}` },
                { key: "MNCHGC_RAW", build: (v) => `MNCHGC${Math.trunc(Number(v))}` },
                { key: "PBDCHGC", build: (v) => `PBDCHGC${pad3(v)}` }
            ]
        },

        max_ac_charging_current: {
            kind: "number",
            candidates: [
                // priorité voulue : tester d'abord MUCHGC0002 / format 4 digits
                { key: "MUCHGC_4", build: (v) => `MUCHGC${String(Math.trunc(Number(v))).padStart(4, "0")}` },

                // puis fallback formats alternatifs
                { key: "MUCHGC_3", build: (v) => `MUCHGC${String(Math.trunc(Number(v))).padStart(3, "0")}` },
                { key: "MUCHGC_2", build: (v) => `MUCHGC${String(Math.trunc(Number(v))).padStart(2, "0")}` },
                { key: "MUCHGC_RAW", build: (v) => `MUCHGC${Math.trunc(Number(v))}` },
                { key: "PBCCHGC", build: (v) => `PBCCHGC${pad3(v)}` }
            ]
        },

        output_source_priority: {
            kind: "enum_profile_detect",
            statePath: "params.qpiri.output_source_priority_code",
            family: "POP",
            defaultProfile: "pop_01_03",
            applyByProfile: {
                pop_00_02: {
                    0: { command: "POP00", expectedCode: 0 },
                    1: { command: "POP01", expectedCode: 1 },
                    2: { command: "POP02", expectedCode: 2 }
                },
                pop_01_03: {
                    0: { command: "POP01", expectedCode: 1 },
                    1: { command: "POP02", expectedCode: 2 },
                    2: { command: "POP03", expectedCode: 3 }
                }
            },
            detect: {
                low: { command: "POP00", expectedCode: 0, profileKey: "pop_00_02" },
                high: { command: "POP03", expectedCode: 3, profileKey: "pop_01_03" }
            }
        },

        charger_source_priority: {
            kind: "enum_profile_detect",
            statePath: "params.qpiri.charger_source_priority_code",
            family: "PCP",
            defaultProfile: "pcp_01_03",
            applyByProfile: {
                pcp_00_02: {
                    0: { command: "PCP00", expectedCode: 0 },
                    1: { command: "PCP01", expectedCode: 1 },
                    2: { command: "PCP02", expectedCode: 2 }
                },
                pcp_01_03: {
                    0: { command: "PCP01", expectedCode: 1 },
                    1: { command: "PCP02", expectedCode: 2 },
                    2: { command: "PCP03", expectedCode: 3 }
                }
            },
            detect: {
                low: { command: "PCP00", expectedCode: 0, profileKey: "pcp_00_02" },
                high: { command: "PCP03", expectedCode: 3, profileKey: "pcp_01_03" }
            }
        }
    };
}

// -------------------------------------------------
// Session
// -------------------------------------------------
const sessionKey = `learn_session_inv${inv}`;
const pendingLearnKey = `learn_pending_inv${inv}`;

let session = flow.get(sessionKey);
if (!session || session.active !== true) return null;

const registry = getRegistry(inv);
const cfg = registry[session.param];
if (!cfg) return null;

// -------------------------------------------------
// Helpers fail msg
// -------------------------------------------------
function buildFailMsg(reason) {
    return {
        inverterNum: inv,
        topic: `voltronic/${inv}/learning/status`,
        payload: {
            active: false,
            success: false,
            reason,
            param: session.param,
            requested_value: session.requestedValue ?? null,
            requested_slot: session.requestedSlot ?? null,
            fingerprint: session.fingerprint,
            finished_at: new Date().toISOString()
        },
        _learn_complete: true,
        _learn_success: false
    };
}

// -------------------------------------------------
// Anti boucle dure
// -------------------------------------------------
function antiLoopCheck(cmd, label) {
    const now = Date.now();
    const prev = session._loopGuard || {
        lastCommand: null,
        count: 0,
        firstTs: 0
    };

    if (prev.lastCommand === cmd && (now - Number(prev.firstTs || 0)) < 8000) {
        prev.count = Number(prev.count || 0) + 1;
    } else {
        prev.lastCommand = cmd;
        prev.count = 1;
        prev.firstTs = now;
    }

    session._loopGuard = prev;

    if (prev.count > 3) {
        session.phase = "failed";
        flow.set(sessionKey, session);
        flow.set(pendingLearnKey, null);

        node.status({
            fill: "red",
            shape: "ring",
            text: `loop stop ${label || session.param}`
        });

        return buildFailMsg(`same_command_loop_${cmd}`);
    }

    return null;
}

// -------------------------------------------------
// MODE NUMERIQUE
// -------------------------------------------------
if (session.kind === "number") {
    const currentIndex = Number(session.index);
    session.index = (Number.isFinite(currentIndex) ? currentIndex : -1) + 1;
    session.updatedAt = Date.now();

    if (!Array.isArray(session.candidateKeys)) {
        return [null, buildFailMsg("invalid_candidate_list")];
    }

    if (session.index >= session.candidateKeys.length) {
        node.status({
            fill: "red",
            shape: "ring",
            text: `learn fail ${session.param}`
        });
        return [null, buildFailMsg("no_candidate_left")];
    }

    const wanted = session.candidateKeys[session.index];
    const candidate = Array.isArray(cfg.candidates)
        ? cfg.candidates.find(c => c.key === wanted.key)
        : null;

    if (!candidate || typeof candidate.build !== "function") {
        flow.set(sessionKey, session);
        return [{
            inverterNum: inv,
            _learn_action: "next_candidate",
            _learn: { sessionId: session.sessionId }
        }, null];
    }

    const cmd = candidate.build(session.requestedValue);

    const loopFail = antiLoopCheck(cmd, candidate.key);
    if (loopFail) return [null, loopFail];

    session.currentCandidate = {
        mode: "number",
        key: candidate.key,
        source: wanted.source,
        command: cmd,
        sentAt: Date.now()
    };

    session.phase = "wait_ack";
    session.lastAck = null;

    flow.set(sessionKey, session);
    flow.set(pendingLearnKey, {
        sessionId: session.sessionId,
        param: session.param,
        cmd: cmd,
        phase: "wait_ack",
        ts: Date.now()
    });

    flow.set(`inv${inv}_poll_pause_until`, Date.now() + 2500);

    const out = {
        inverterNum: inv,
        command: cmd,
        _cmd: cmd,
        _raw_command: cmd,
        payload: cmd,
        _burst: false,
        _origin: "learn_retry",
        _ha_param: session.paramRaw || session.param,
        _ha_value: session.requestedRaw,
        _learn: {
            sessionId: session.sessionId,
            param: session.param,
            requestedValue: session.requestedValue,
            candidateKey: candidate.key,
            source: wanted.source,
            phase: "candidate"
        }
    };

    node.status({
        fill: "yellow",
        shape: "dot",
        text: `learn try ${candidate.key}`
    });

    return [out, null];
}

// -------------------------------------------------
// MODE DETECTION / REAPPLY PROFIL ENUM
// -------------------------------------------------
if (session.kind === "enum_profile_detect") {
    const detectState = session.detectState || {
        phase: "normal",
        preferredProfile: cfg.defaultProfile || null,
        resolvedProfile: null,
        lastVerifiedCode: null,
        probeHighAck: false,
        probeHighNak: false,
        probeLowAck: false,
        probeLowNak: false
    };

    let cmd = null;
    let expectedCode = null;
    let profileKey = null;
    let candidateLabel = null;

    if (detectState.phase === "normal") {
        const requestedSlot = Number(session.requestedSlot);
        const preferred =
            detectState.resolvedProfile ||
            detectState.preferredProfile ||
            cfg.defaultProfile ||
            null;

        if (
            preferred &&
            cfg.applyByProfile?.[preferred] &&
            cfg.applyByProfile[preferred][requestedSlot]
        ) {
            const slotCfg = cfg.applyByProfile[preferred][requestedSlot];
            cmd = slotCfg.command;
            expectedCode = Number(slotCfg.expectedCode);
            profileKey = preferred;
            candidateLabel = `normal_${preferred}`;
        } else {
            return [null, buildFailMsg("invalid_requested_slot")];
        }

        session.currentCandidate = {
            mode: "profile_detect",
            phase: "normal",
            command: cmd,
            expectedCode,
            profileKey,
            requestedSlot,
            sentAt: Date.now()
        };
    }

    else if (detectState.phase === "probe_low") {
        cmd = cfg.detect.low.command;
        expectedCode = cfg.detect.low.expectedCode;
        profileKey = cfg.detect.low.profileKey;
        candidateLabel = "probe_low_00";

        session.currentCandidate = {
            mode: "profile_detect",
            phase: "probe_low",
            command: cmd,
            expectedCode,
            profileKey,
            requestedSlot: session.requestedSlot,
            sentAt: Date.now()
        };
    }

    else if (detectState.phase === "probe_high") {
        if (isBanned(session, cfg.detect.high.command)) {
            return [null, buildFailMsg("high_probe_banned")];
        }

        cmd = cfg.detect.high.command;
        expectedCode = cfg.detect.high.expectedCode;
        profileKey = cfg.detect.high.profileKey;
        candidateLabel = "probe_high_03";

        session.currentCandidate = {
            mode: "profile_detect",
            phase: "probe_high",
            command: cmd,
            expectedCode,
            profileKey,
            requestedSlot: session.requestedSlot,
            sentAt: Date.now()
        };
    }

    else if (detectState.phase === "reapply_final") {
        const resolved = detectState.resolvedProfile;
        const requestedSlot = Number(session.requestedSlot);
        const slotCfg = cfg.applyByProfile?.[resolved]?.[requestedSlot];

        if (!resolved || !slotCfg) {
            return [null, buildFailMsg("invalid_reapply_profile")];
        }

        cmd = slotCfg.command;
        expectedCode = Number(slotCfg.expectedCode);
        profileKey = resolved;
        candidateLabel = "reapply_final_value";

        session.currentCandidate = {
            mode: "profile_detect",
            phase: "reapply_final",
            command: cmd,
            expectedCode,
            profileKey,
            requestedSlot,
            sentAt: Date.now()
        };
    }

    else {
        return [null, buildFailMsg("invalid_detect_phase")];
    }

    const loopFail = antiLoopCheck(cmd, candidateLabel);
    if (loopFail) return [null, loopFail];

    session.phase = "wait_ack";
    session.lastAck = null;
    session.updatedAt = Date.now();

    flow.set(sessionKey, session);
    flow.set(pendingLearnKey, {
        sessionId: session.sessionId,
        param: session.param,
        cmd: cmd,
        phase: "wait_ack",
        ts: Date.now()
    });

    flow.set(`inv${inv}_poll_pause_until`, Date.now() + 2500);

    const out = {
        inverterNum: inv,
        command: cmd,
        _cmd: cmd,
        _raw_command: cmd,
        payload: cmd,
        _burst: false,
        _origin: "learn_retry",
        _ha_param: session.paramRaw || session.param,
        _ha_value: session.requestedRaw,
        _learn: {
            sessionId: session.sessionId,
            param: session.param,
            requestedSlot: session.requestedSlot,
            detectPhase: detectState.phase,
            expectedCode,
            profileKey,
            candidateLabel,
            phase: "candidate"
        }
    };

    node.status({
        fill: "yellow",
        shape: "dot",
        text: `learn try ${candidateLabel}`
    });

    return [out, null];
}

return null;

// ====== LEARNING - STATE FEEDBACK ======
// Sortie 1 = complete success
// Sortie 2 = next candidate / next detect phase

const inv = msg.inverterNum ?? 1;
const sessionKey = `learn_session_inv${inv}`;
const pendingLearnKey = `learn_pending_inv${inv}`;

function getByPath(obj, path) {
    if (!obj || !path) return undefined;
    return path.split(".").reduce((acc, k) => acc && acc[k], obj);
}

function toNum(v) {
    const n = Number(v);
    return Number.isFinite(n) ? n : null;
}

function isEqual(a, b, tol) {
    const na = toNum(a);
    const nb = toNum(b);
    if (na == null || nb == null) return false;
    return Math.abs(na - nb) <= tol;
}

function addNumUnique(arr, value) {
    const out = Array.isArray(arr) ? [...arr] : [];
    const n = Number(value);
    if (Number.isFinite(n) && !out.includes(n)) out.push(n);
    return out.sort((a, b) => a - b);
}

function markResolvedProfile(session, profileKey) {
    const ds = session.detectState || {};
    ds.resolvedProfile = profileKey;

    if (profileKey === "pop_00_02" || profileKey === "pcp_00_02") {
        session.rangeStart = 0;
        session.rangeEnd = 2;
    } else if (profileKey === "pop_01_03" || profileKey === "pcp_01_03") {
        session.rangeStart = 1;
        session.rangeEnd = 3;
    }

    session.detectState = ds;
}

const session = flow.get(sessionKey);
if (!session || session.active !== true) return null;

if (session.phase !== "wait_state") return null;

const pending = flow.get(pendingLearnKey) || null;
const pendingCmd = String(pending?.cmd || "").trim().toUpperCase();
if (pendingCmd !== "QPIRI") return null;

const state = msg.payload;
if (!state || typeof state !== "object") return null;

const ageSinceVerify = Date.now() - Number(session.verifySentAt || 0);
if (ageSinceVerify < 1200) {
    return null;
}

// -------------------------
// MODE NUMERIQUE
// -------------------------
if (session.kind === "number") {
    const actualValue = getByPath(state, session.statePath);

    if (isEqual(actualValue, session.requestedValue, session.tolerance)) {
        flow.set(pendingLearnKey, null);

        const okMsg = {
            inverterNum: inv,
            topic: `voltronic/${inv}/learning/status`,
            payload: {
                active: false,
                success: true,
                param: session.param,
                candidate_key: session.currentCandidate?.key || null,
                command: session.currentCandidate?.command || null,
                requested_value: session.requestedValue,
                verified_value: actualValue,
                fingerprint: session.fingerprint,
                finished_at: new Date().toISOString()
            },
            _learn_complete: true,
            _learn_success: true
        };

        node.status({ fill: "green", shape: "dot", text: `learn OK ${session.param}` });
        return [okMsg, null];
    }

    flow.set(pendingLearnKey, null);

    node.status({ fill: "yellow", shape: "ring", text: `learn next ${session.param}` });
    return [null, {
        inverterNum: inv,
        _learn_action: "next_candidate",
        _learn: { sessionId: session.sessionId }
    }];
}

// -------------------------
// MODE DETECTION PROFIL ENUM + REAPPLY
// -------------------------
if (session.kind === "enum_profile_detect") {
    const actualCode = toNum(getByPath(state, session.statePath));
    const detectState = session.detectState || {
        phase: "normal",
        preferredProfile: null,
        resolvedProfile: null,
        lastVerifiedCode: null,
        probeHighAck: false,
        probeHighNak: false,
        probeLowAck: false,
        probeLowNak: false
    };

    detectState.lastVerifiedCode = actualCode;
    session.detectState = detectState;
    session.supportedCodes = addNumUnique(session.supportedCodes, actualCode);

    const currentPhase = String(session.currentCandidate?.phase || detectState.phase || "").trim().toLowerCase();
    const expectedCode = toNum(session.currentCandidate?.expectedCode);

    // -------------------------------------------------
    // normal:
    // si le code correspond, succès direct
    // sinon on lance une vraie détection par 00
    // -------------------------------------------------
    if (currentPhase === "normal") {
        if (actualCode != null && expectedCode != null && actualCode === expectedCode) {
            markResolvedProfile(
                session,
                session.currentCandidate?.profileKey ||
                detectState.resolvedProfile ||
                detectState.preferredProfile ||
                null
            );

            flow.set(sessionKey, session);
            flow.set(pendingLearnKey, null);

            const okMsg = {
                inverterNum: inv,
                topic: `voltronic/${inv}/learning/status`,
                payload: {
                    active: false,
                    success: true,
                    param: session.param,
                    profile_key: session.detectState?.resolvedProfile || null,
                    command: session.currentCandidate?.command || null,
                    requested_slot: session.requestedSlot,
                    verified_code: actualCode,
                    expected_code: expectedCode,
                    fingerprint: session.fingerprint,
                    finished_at: new Date().toISOString()
                },
                _learn_complete: true,
                _learn_success: true
            };

            node.status({ fill: "green", shape: "dot", text: `learn OK ${session.param}` });
            return [okMsg, null];
        }

        detectState.phase = "probe_low";
        session.detectState = detectState;
        session.updatedAt = Date.now();

        flow.set(sessionKey, session);
        flow.set(pendingLearnKey, null);

        node.status({ fill: "yellow", shape: "ring", text: `probe low ${session.param}` });
        return [null, {
            inverterNum: inv,
            _learn_action: "next_candidate",
            _learn: { sessionId: session.sessionId }
        }];
    }

    // -------------------------------------------------
    // probe_low:
    // si QPIRI lit 0 => plage basse confirmée
    // sinon on tente probe_high
    // -------------------------------------------------
    if (currentPhase === "probe_low") {
        if (actualCode === 0) {
            markResolvedProfile(
                session,
                session.currentCandidate?.profileKey || detectState.resolvedProfile || "pop_00_02"
            );
            detectState.phase = "reapply_final";

            session.detectState = detectState;
            session.updatedAt = Date.now();

            flow.set(sessionKey, session);
            flow.set(pendingLearnKey, null);

            node.status({ fill: "blue", shape: "dot", text: `reapply ${session.param}` });
            return [null, {
                inverterNum: inv,
                _learn_action: "next_candidate",
                _learn: { sessionId: session.sessionId }
            }];
        }

        detectState.phase = "probe_high";
        session.detectState = detectState;
        session.updatedAt = Date.now();

        flow.set(sessionKey, session);
        flow.set(pendingLearnKey, null);

        node.status({ fill: "yellow", shape: "ring", text: `probe high ${session.param}` });
        return [null, {
            inverterNum: inv,
            _learn_action: "next_candidate",
            _learn: { sessionId: session.sessionId }
        }];
    }

    // -------------------------------------------------
    // probe_high:
    // si QPIRI lit 3 => plage haute confirmée
    // sinon échec
    // -------------------------------------------------
    if (currentPhase === "probe_high") {
        if (actualCode === 3) {
            markResolvedProfile(
                session,
                session.currentCandidate?.profileKey || detectState.resolvedProfile || "pop_01_03"
            );
            detectState.phase = "reapply_final";

            session.detectState = detectState;
            session.updatedAt = Date.now();

            flow.set(sessionKey, session);
            flow.set(pendingLearnKey, null);

            node.status({ fill: "blue", shape: "dot", text: `reapply ${session.param}` });
            return [null, {
                inverterNum: inv,
                _learn_action: "next_candidate",
                _learn: { sessionId: session.sessionId }
            }];
        }

        flow.set(pendingLearnKey, null);

        node.status({ fill: "red", shape: "ring", text: `learn fail ${session.param}` });
        return [null, {
            inverterNum: inv,
            topic: `voltronic/${inv}/learning/status`,
            payload: {
                active: false,
                success: false,
                reason: "profile_not_resolved",
                param: session.param,
                requested_slot: session.requestedSlot,
                fingerprint: session.fingerprint,
                finished_at: new Date().toISOString()
            },
            _learn_complete: true,
            _learn_success: false
        }];
    }

    // -------------------------------------------------
    // reapply_final:
    // on valide que la vraie commande du slot demandé
    // donne bien le code attendu
    // -------------------------------------------------
    if (currentPhase === "reapply_final") {
        if (actualCode != null && expectedCode != null && actualCode === expectedCode) {
            flow.set(pendingLearnKey, null);

            const okMsg = {
                inverterNum: inv,
                topic: `voltronic/${inv}/learning/status`,
                payload: {
                    active: false,
                    success: true,
                    param: session.param,
                    profile_key: detectState.resolvedProfile,
                    command: session.currentCandidate?.command || null,
                    requested_slot: session.requestedSlot,
                    verified_code: actualCode,
                    expected_code: expectedCode,
                    fingerprint: session.fingerprint,
                    finished_at: new Date().toISOString()
                },
                _learn_complete: true,
                _learn_success: true
            };

            node.status({ fill: "green", shape: "dot", text: `learn OK ${session.param}` });
            return [okMsg, null];
        }

        flow.set(pendingLearnKey, null);

        node.status({ fill: "red", shape: "ring", text: `reapply fail ${session.param}` });
        return [null, {
            inverterNum: inv,
            topic: `voltronic/${inv}/learning/status`,
            payload: {
                active: false,
                success: false,
                reason: "reapply_failed",
                param: session.param,
                requested_slot: session.requestedSlot,
                fingerprint: session.fingerprint,
                finished_at: new Date().toISOString()
            },
            _learn_complete: true,
            _learn_success: false
        }];
    }
}

return null;

// ====== LEARNING - COMPLETE ======

const inv = msg.inverterNum ?? 1;
const sessionKey = `learn_session_inv${inv}`;
const pendingLearnKey = `learn_pending_inv${inv}`;

let session =
    flow.get(sessionKey) ||
    flow.get(sessionKey, "persistent") ||
    null;

if (!msg._learn_complete) {
    return null;
}

const success = (msg._learn_success === true);

function clone(obj) {
    return JSON.parse(JSON.stringify(obj || {}));
}

function uniqNums(arr) {
    const out = [];
    for (const v of (Array.isArray(arr) ? arr : [])) {
        const n = Number(v);
        if (Number.isFinite(n) && !out.includes(n)) out.push(n);
    }
    return out.sort((a, b) => a - b);
}

function uniqUpper(arr) {
    const out = [];
    for (const v of (Array.isArray(arr) ? arr : [])) {
        const s = String(v ?? "").trim().toUpperCase();
        if (s && !out.includes(s)) out.push(s);
    }
    return out.sort();
}

function cleanString(v) {
    return String(v ?? "").trim();
}

function normalizeFingerprint(fp) {
    const s = cleanString(fp);
    return s || "";
}

function getLearnedAll() {
    let all = clone(global.get("learned_commands") || {});
    if (!all || typeof all !== "object" || Array.isArray(all)) all = {};

    const persistentAll = clone(global.get("learned_commands", "persistent") || {});
    if (persistentAll && typeof persistentAll === "object" && !Array.isArray(persistentAll)) {
        for (const fp of Object.keys(persistentAll)) {
            if (!all[fp] || typeof all[fp] !== "object") {
                all[fp] = clone(persistentAll[fp]);
            }
        }
    }

    const backupAll = clone(global.get("learned_commands_backup", "persistent") || {});
    if (backupAll && typeof backupAll === "object" && !Array.isArray(backupAll)) {
        for (const fp of Object.keys(backupAll)) {
            if (!all[fp] || typeof all[fp] !== "object") {
                all[fp] = clone(backupAll[fp]);
            }
        }
    }

    return all;
}

function saveLearnedAll(all) {
    global.set("learned_commands", all);
    global.set("learned_commands", all, "persistent");
    global.set("learned_commands_backup", all, "persistent");
}

try {
    const fp = normalizeFingerprint(
        session?.fingerprint ||
        msg.payload?.fingerprint ||
        ""
    );

    const param = cleanString(
        session?.param ||
        msg.payload?.param ||
        ""
    );

    if (success && session && session.active === true && fp && param) {
        const all = getLearnedAll();
        if (!all[fp]) all[fp] = {};

        const prev = all[fp][param] || {};

        if (session.kind === "number" && session.currentCandidate?.key) {
            all[fp][param] = {
                key: session.currentCandidate.key,
                learnedAt: Date.now(),
                successCount: Number(prev.successCount || 0) + 1,
                failCount: 0,
                lastValue: session.requestedValue,
                lastCommandExample: session.currentCandidate.command
            };
        }

        if (session.kind === "enum_profile_detect") {
            const resolvedProfile =
                session.detectState?.resolvedProfile ||
                msg.payload?.profile_key ||
                null;

            const verifiedCode = Number(
                msg.payload?.verified_code ??
                session.detectState?.lastVerifiedCode
            );

            const prevCodes = uniqNums(prev.provenCodes || []);
            const newCodes = uniqNums([...prevCodes, verifiedCode]);

            const confidence =
                (newCodes.includes(0) || newCodes.includes(3))
                    ? "confirmed"
                    : "tentative";

            if (resolvedProfile) {
                all[fp][param] = {
                    mode: "profile",
                    profileKey: resolvedProfile,
                    confidence,
                    provenCodes: newCodes,
                    bannedCommands: uniqUpper(session.bannedCommands || prev.bannedCommands || []),
                    supportedCodes: uniqNums(session.supportedCodes || prev.supportedCodes || []),
                    rangeStart: Number.isFinite(Number(session.rangeStart)) ? Number(session.rangeStart) : null,
                    rangeEnd: Number.isFinite(Number(session.rangeEnd)) ? Number(session.rangeEnd) : null,
                    learnedAt: Date.now(),
                    successCount: Number(prev.successCount || 0) + 1,
                    failCount: 0,
                    lastSlot: session.requestedSlot,
                    lastExpectedCode: verifiedCode,
                    lastCommandExample: session.currentCandidate?.command || null
                };
            }
        }

        saveLearnedAll(all);
    }

    if (!success && fp && param) {
        const all = getLearnedAll();
        if (!all[fp]) all[fp] = {};

        const prev = all[fp][param] || {};

        all[fp][param] = {
            ...prev,
            bannedCommands: uniqUpper(session?.bannedCommands || prev.bannedCommands || []),
            supportedCodes: uniqNums(session?.supportedCodes || prev.supportedCodes || []),
            rangeStart: Number.isFinite(Number(session?.rangeStart)) ? Number(session?.rangeStart) : prev.rangeStart ?? null,
            rangeEnd: Number.isFinite(Number(session?.rangeEnd)) ? Number(session?.rangeEnd) : prev.rangeEnd ?? null,
            failCount: Number(prev.failCount || 0) + 1,
            lastFailAt: Date.now()
        };

        if (
            all[fp][param].failCount >= 3 &&
            !all[fp][param].profileKey &&
            !all[fp][param].key
        ) {
            delete all[fp][param];
        }

        saveLearnedAll(all);
    }
} finally {
    flow.set(pendingLearnKey, null);
    flow.set(sessionKey, null);
}

const historyKey = `learn_history_inv${inv}`;
let hist =
    flow.get(historyKey, "persistent") ||
    flow.get(historyKey) ||
    [];

if (!Array.isArray(hist)) hist = [];

hist.unshift({
    ts: Date.now(),
    success,
    kind: session?.kind || null,
    param: session?.param || msg.payload?.param || null,
    candidate_key: session?.currentCandidate?.key || msg.payload?.candidate_key || null,
    profile_key:
        session?.detectState?.resolvedProfile ||
        session?.currentCandidate?.profileKey ||
        msg.payload?.profile_key ||
        null,
    command: session?.currentCandidate?.command || msg.payload?.command || null,
    requested_value: session?.requestedValue ?? msg.payload?.requested_value ?? null,
    requested_slot: session?.requestedSlot ?? msg.payload?.requested_slot ?? null,
    expected_code:
        session?.currentCandidate?.expectedCode ??
        msg.payload?.expected_code ??
        null,
    verified_code:
        msg.payload?.verified_code ??
        session?.detectState?.lastVerifiedCode ??
        null,
    range_start: session?.rangeStart ?? null,
    range_end: session?.rangeEnd ?? null,
    banned_commands: uniqUpper(session?.bannedCommands || []),
    supported_codes: uniqNums(session?.supportedCodes || []),
    fingerprint: session?.fingerprint || msg.payload?.fingerprint || null
});

if (hist.length > 50) hist = hist.slice(0, 50);

flow.set(historyKey, hist, "persistent");
flow.set(historyKey, hist);

node.status({
    fill: success ? "green" : "red",
    shape: success ? "dot" : "ring",
    text: success ? "learn saved" : "learn failed"
});

const retryGuardKey = `learn_retry_guard_inv${inv}`;
let retryGuard = flow.get(retryGuardKey);
if (!retryGuard || typeof retryGuard !== "object") retryGuard = {};

const guardValue =
    session?.requestedRaw ??
    session?.requestedValue ??
    session?.requestedSlot ??
    msg.payload?.requested_value ??
    msg.payload?.requested_slot ??
    null;

const guardFingerprint = cleanString(
    session?.fingerprint ||
    msg.payload?.fingerprint ||
    ""
);

const guardParam = cleanString(
    session?.param ||
    msg.payload?.param ||
    ""
);

const guardId = `${guardFingerprint}|${guardParam}|${JSON.stringify(guardValue)}`;

if (!success) {
    retryGuard[guardId] = {
        failedAt: Date.now(),
        blockUntil: Date.now() + 15000
    };
} else {
    delete retryGuard[guardId];
}

flow.set(retryGuardKey, retryGuard);

return msg;

// ====== LEARNING - PREPROCESS ======
// Sortie 1 = apprentissage
// Sortie 2 = bypass direct

const inv = msg.inverterNum ?? 1;

function cleanString(v) {
    return String(v ?? "").trim();
}

function toNum(x) {
    if (x == null) return null;
    if (typeof x === "string") {
        const s = cleanString(x);
        const m = s.match(/-?\d+(\.\d+)?/);
        if (!m) return null;
        x = m[0];
    }
    const n = Number(x);
    return Number.isFinite(n) ? n : null;
}

function clone(obj) {
    return JSON.parse(JSON.stringify(obj || {}));
}

function getByPath(obj, path) {
    if (!obj || !path) return undefined;
    return path.split(".").reduce((acc, k) => acc && acc[k], obj);
}

function getFingerprint(state) {
    const model = cleanString(state?.diag?.model);
    const serial = cleanString(state?.diag?.serial);
    const fw = cleanString(state?.diag?.fw_main);

    if (serial) return `SERIAL:${serial}`;
    if (model && fw) return `MODELFW:${model}|${fw}`;
    if (model) return `MODEL:${model}`;
    if (fw) return `FW:${fw}`;

    return "";
}

function canonParam(p) {
    const map = {
        battery_bulk_voltage: "battery_bulk_voltage",
        battery_float_voltage: "battery_float_voltage",

        battery_cutoff_voltage: "battery_under_voltage",
        battery_under_voltage: "battery_under_voltage",

        back_to_grid_voltage: "battery_recharge_voltage",
        battery_recharge_voltage: "battery_recharge_voltage",

        back_to_battery_voltage: "battery_re_discharge_voltage",
        battery_re_discharge_voltage: "battery_re_discharge_voltage",

        max_charging_current: "max_charging_current",

        grid_charging_current: "max_ac_charging_current",
        max_ac_charging_current: "max_ac_charging_current",

        charger_source_priority: "charger_source_priority",
        output_source_priority: "output_source_priority"
    };

    return map[cleanString(p)] || cleanString(p);
}

function getRegistry() {
    return {
        battery_bulk_voltage: {
            kind: "number",
            statePath: "params.qpiri.battery_bulk_voltage",
            tolerance: 0.05
        },
        battery_float_voltage: {
            kind: "number",
            statePath: "params.qpiri.battery_float_voltage",
            tolerance: 0.05
        },
        battery_under_voltage: {
            kind: "number",
            statePath: "params.qpiri.battery_under_voltage",
            tolerance: 0.05
        },
        battery_recharge_voltage: {
            kind: "number",
            statePath: "params.qpiri.battery_recharge_voltage",
            tolerance: 0.05
        },
        battery_re_discharge_voltage: {
            kind: "number",
            statePath: "params.qpiri.battery_re_discharge_voltage",
            tolerance: 0.05
        },
        max_charging_current: {
            kind: "number",
            statePath: "params.qpiri.max_charging_current",
            tolerance: 0.5
        },
        max_ac_charging_current: {
            kind: "number",
            statePath: "params.qpiri.max_ac_charging_current",
            tolerance: 0.5
        },
        charger_source_priority: {
            kind: "enum_profile",
            statePath: "params.qpiri.charger_source_priority_code"
        },
        output_source_priority: {
            kind: "enum_profile",
            statePath: "params.qpiri.output_source_priority_code"
        }
    };
}

function isEqual(a, b, tol) {
    const na = Number(a);
    const nb = Number(b);
    if (!Number.isFinite(na) || !Number.isFinite(nb)) return false;
    return Math.abs(na - nb) <= tol;
}

function isTwoChoiceOutputPriorityEnabled(inv) {
    return global.get(`inverter_${inv}.output_priority_2choices`) === true;
}

function getLearnedAll() {
    let all = clone(global.get("learned_commands") || {});
    if (!all || typeof all !== "object" || Array.isArray(all)) all = {};

    const persistentAll = clone(global.get("learned_commands", "persistent") || {});
    if (persistentAll && typeof persistentAll === "object" && !Array.isArray(persistentAll)) {
        for (const fp of Object.keys(persistentAll)) {
            if (!all[fp] || typeof all[fp] !== "object") {
                all[fp] = clone(persistentAll[fp]);
            }
        }
    }

    const backupAll = clone(global.get("learned_commands_backup", "persistent") || {});
    if (backupAll && typeof backupAll === "object" && !Array.isArray(backupAll)) {
        for (const fp of Object.keys(backupAll)) {
            if (!all[fp] || typeof all[fp] !== "object") {
                all[fp] = clone(backupAll[fp]);
            }
        }
    }

    return all;
}

const paramRaw = cleanString(msg._ha_param || msg.topic || "");
const valueRaw = msg._ha_value ?? msg.payload;
const param = canonParam(paramRaw);

const registry = getRegistry();
const cfg = registry[param];

// param non géré par apprentissage => bypass
if (!cfg) {
    return [null, msg];
}

// output_source_priority en mode 2 choix forcé => bypass
if (param === "output_source_priority" && isTwoChoiceOutputPriorityEnabled(inv)) {
    node.status({
        fill: "blue",
        shape: "dot",
        text: "bypass forced 2-choice"
    });
    return [null, msg];
}

const sessionKey = `learn_session_inv${inv}`;
const pendingLearnKey = `learn_pending_inv${inv}`;
const retryGuardKey = `learn_retry_guard_inv${inv}`;

let existing = flow.get(sessionKey);

// purge session morte
if (existing && existing.active === true) {
    const lastTs = Number(existing.updatedAt || existing.createdAt || 0);
    const age = lastTs > 0 ? (Date.now() - lastTs) : 999999;

    if (age > 60000) {
        flow.set(sessionKey, null);
        flow.set(pendingLearnKey, null);
        existing = null;

        node.status({
            fill: "grey",
            shape: "dot",
            text: "learn stale cleared"
        });
    }
}

if (existing && existing.active === true) {
    node.status({
        fill: "yellow",
        shape: "ring",
        text: `learn busy ${existing.param}`
    });
    return [null, null];
}

// état normalisé : RAM puis secours persistent
const state =
    flow.get(`inv${inv}_normalized_state`) ||
    flow.get(`inv${inv}_normalized_state`, "persistent") ||
    global.get(`inv${inv}_normalized_state`) ||
    global.get(`inv${inv}_normalized_state`, "persistent") ||
    {};

const fingerprint = getFingerprint(state);

// si fingerprint absent, bypass
if (!fingerprint) {
    node.status({
        fill: "yellow",
        shape: "dot",
        text: "learn bypass no fingerprint"
    });
    return [null, msg];
}

const currentValue = getByPath(state, cfg.statePath);

// -------------------------------------------------
// Anti-réarmement après échec
// -------------------------------------------------
let retryGuard = flow.get(retryGuardKey);
if (!retryGuard || typeof retryGuard !== "object") retryGuard = {};

const guardId = `${fingerprint}|${param}|${JSON.stringify(valueRaw)}`;
const guard = retryGuard[guardId] || null;

if (guard && guard.blockUntil && Date.now() < Number(guard.blockUntil)) {
    node.status({
        fill: "red",
        shape: "ring",
        text: `learn blocked ${param}`
    });
    return [null, null];
}

// -------------------------------------------------
// MODE NUMERIQUE
// -------------------------------------------------
if (cfg.kind === "number") {
    const requestedValue = toNum(valueRaw);
    if (requestedValue == null) {
        node.status({ fill: "red", shape: "ring", text: `learn invalid ${param}` });
        return [null, null];
    }

    if (isEqual(currentValue, requestedValue, cfg.tolerance)) {
        node.status({
            fill: "green",
            shape: "dot",
            text: `already ${param}=${requestedValue}`
        });
        return [null, null];
    }

    msg._learn = {
        active: true,
        sessionId: `inv${inv}_${param}_${Date.now()}`,
        inverterNum: inv,
        param,
        paramRaw: cleanString(msg._ha_param_raw || msg._ha_param || param),
        requestedValue,
        requestedRaw: msg._ha_value_raw ?? valueRaw,
        baselineValue: currentValue,
        fingerprint,
        statePath: cfg.statePath,
        tolerance: cfg.tolerance,
        kind: "number",
        createdAt: Date.now(),
        updatedAt: Date.now()
    };

    node.status({
        fill: "blue",
        shape: "dot",
        text: `learn ${param} -> ${requestedValue}`
    });

    return [msg, null];
}

// -------------------------------------------------
// MODE ENUM PROFILE
// -------------------------------------------------
if (cfg.kind === "enum_profile") {
    const requestedSlot = Number(valueRaw);
    if (!Number.isInteger(requestedSlot) || requestedSlot < 0 || requestedSlot > 2) {
        node.status({ fill: "red", shape: "ring", text: `learn invalid slot ${param}` });
        return [null, null];
    }

    const currentNum = Number(currentValue);
    if (Number.isInteger(currentNum)) {
        const learnedAll = getLearnedAll();
        const learned = learnedAll[fingerprint]?.[param] || null;
        const profileKey = learned?.profileKey || null;

        if (param === "output_source_priority") {
            if (profileKey === "pop_00_02" && currentNum === requestedSlot) {
                node.status({ fill: "green", shape: "dot", text: `already ${param} slot ${requestedSlot}` });
                return [null, null];
            }
            if (profileKey === "pop_01_03" && currentNum === (requestedSlot + 1)) {
                node.status({ fill: "green", shape: "dot", text: `already ${param} slot ${requestedSlot}` });
                return [null, null];
            }
        }

        if (param === "charger_source_priority") {
            if (profileKey === "pcp_00_02" && currentNum === requestedSlot) {
                node.status({ fill: "green", shape: "dot", text: `already ${param} slot ${requestedSlot}` });
                return [null, null];
            }
            if (profileKey === "pcp_01_03" && currentNum === (requestedSlot + 1)) {
                node.status({ fill: "green", shape: "dot", text: `already ${param} slot ${requestedSlot}` });
                return [null, null];
            }
        }
    }

    msg._learn = {
        active: true,
        sessionId: `inv${inv}_${param}_${Date.now()}`,
        inverterNum: inv,
        param,
        paramRaw: cleanString(msg._ha_param_raw || msg._ha_param || param),
        requestedSlot,
        requestedRaw: msg._ha_value_raw ?? valueRaw,
        baselineValue: currentValue,
        fingerprint,
        statePath: cfg.statePath,
        kind: "enum_profile",
        createdAt: Date.now(),
        updatedAt: Date.now()
    };

    node.status({
        fill: "blue",
        shape: "dot",
        text: `learn ${param} slot ${requestedSlot}`
    });

    return [msg, null];
}

return [null, msg];

// ====== LEARNING - DECISION ======

const inv = msg.inverterNum ?? 1;
if (!msg._learn || typeof msg._learn !== "object") return null;

const sessionKey = `learn_session_inv${inv}`;

function cleanString(v) {
    return String(v ?? "").trim();
}

function normalizeFingerprint(fp) {
    return cleanString(fp);
}

function getParallelId(inv) {
    let machine = flow.get(`inv${inv}_parallel_id`);
    if (machine === undefined || machine === null || machine === "") machine = 0;
    machine = Number(machine);
    if (!Number.isFinite(machine) || machine < 0 || machine > 9) machine = 0;
    return machine;
}

function pad3(x) {
    return String(Math.trunc(Number(x))).padStart(3, "0");
}

function fixed1(x) {
    return Number(x).toFixed(1);
}

function getRegistry(inv) {
    const machine = getParallelId(inv);

    return {
        battery_bulk_voltage: {
            kind: "number",
            candidates: [
                { key: "BULK_PCVV", build: (v) => `PCVV${fixed1(v)}` }
            ]
        },

        battery_float_voltage: {
            kind: "number",
            candidates: [
                { key: "FLOAT_PBFT", build: (v) => `PBFT${fixed1(v)}` }
            ]
        },

        battery_under_voltage: {
            kind: "number",
            candidates: [
                { key: "UNDER_PSDV", build: (v) => `PSDV${fixed1(v)}` }
            ]
        },

        battery_recharge_voltage: {
            kind: "number",
            candidates: [
                { key: "BACK_GRID_PBCV", build: (v) => `PBCV${fixed1(v)}` }
            ]
        },

        battery_re_discharge_voltage: {
            kind: "number",
            candidates: [
                { key: "BACK_BATT_PBDV", build: (v) => `PBDV${fixed1(v)}` }
            ]
        },

        max_charging_current: {
            kind: "number",
            candidates: [
                { key: "MNCHGC_3", build: (v) => `MNCHGC${pad3(v)}` },
                { key: "MNCHGC_MACHINE", build: (v) => `MNCHGC${machine}${pad3(v)}` },
                { key: "MNCHGC_RAW", build: (v) => `MNCHGC${Math.trunc(Number(v))}` },
                { key: "PBDCHGC", build: (v) => `PBDCHGC${pad3(v)}` }
            ]
        },

        max_ac_charging_current: {
            kind: "number",
            candidates: [
                // Ne pas casser les autres onduleurs :
                // on garde plusieurs formats, l'apprentissage choisira le bon
                { key: "MUCHGC_4", build: (v) => `MUCHGC${String(Math.trunc(Number(v))).padStart(4, "0")}` },
                { key: "MUCHGC_3", build: (v) => `MUCHGC${String(Math.trunc(Number(v))).padStart(3, "0")}` },
                { key: "MUCHGC_2", build: (v) => `MUCHGC${String(Math.trunc(Number(v))).padStart(2, "0")}` },
                { key: "MUCHGC_RAW", build: (v) => `MUCHGC${Math.trunc(Number(v))}` },
                { key: "PBCCHGC", build: (v) => `PBCCHGC${pad3(v)}` }
            ]
        },

        output_source_priority: {
            kind: "enum_profile_detect",
            statePath: "params.qpiri.output_source_priority_code",
            family: "POP",
            defaultProfile: "pop_01_03",
            applyByProfile: {
                pop_00_02: {
                    0: { command: "POP00", expectedCode: 0 },
                    1: { command: "POP01", expectedCode: 1 },
                    2: { command: "POP02", expectedCode: 2 }
                },
                pop_01_03: {
                    0: { command: "POP01", expectedCode: 1 },
                    1: { command: "POP02", expectedCode: 2 },
                    2: { command: "POP03", expectedCode: 3 }
                }
            },
            detect: {
                low: { command: "POP00", expectedCode: 0, profileKey: "pop_00_02" },
                high: { command: "POP03", expectedCode: 3, profileKey: "pop_01_03" }
            }
        },

        charger_source_priority: {
            kind: "enum_profile_detect",
            statePath: "params.qpiri.charger_source_priority_code",
            family: "PCP",
            defaultProfile: "pcp_01_03",
            applyByProfile: {
                pcp_00_02: {
                    0: { command: "PCP00", expectedCode: 0 },
                    1: { command: "PCP01", expectedCode: 1 },
                    2: { command: "PCP02", expectedCode: 2 }
                },
                pcp_01_03: {
                    0: { command: "PCP01", expectedCode: 1 },
                    1: { command: "PCP02", expectedCode: 2 },
                    2: { command: "PCP03", expectedCode: 3 }
                }
            },
            detect: {
                low: { command: "PCP00", expectedCode: 0, profileKey: "pcp_00_02" },
                high: { command: "PCP03", expectedCode: 3, profileKey: "pcp_01_03" }
            }
        }
    };
}

const registry = getRegistry(inv);
const param = cleanString(msg._learn.param);
const cfg = registry[param];
if (!cfg) return null;

// garde anti-reset de session
let existing = flow.get(sessionKey);
if (
    msg._learn_action === "next_candidate" &&
    existing &&
    existing.active === true &&
    existing.sessionId === msg._learn.sessionId
) {
    return msg;
}

const learnedAll = global.get("learned_commands") || {};
const fp = normalizeFingerprint(msg._learn.fingerprint);
const learnedForFp = (fp && learnedAll[fp]) ? learnedAll[fp] : {};
const learnedEntry = learnedForFp[param] || null;

const session = {
    active: true,
    sessionId: msg._learn.sessionId,
    inverterNum: inv,
    param,
    paramRaw: cleanString(msg._learn.paramRaw),
    requestedRaw: msg._learn.requestedRaw,
    baselineValue: msg._learn.baselineValue,
    fingerprint: fp,
    statePath: msg._learn.statePath,
    kind: msg._learn.kind,
    createdAt: msg._learn.createdAt || Date.now(),
    updatedAt: Date.now(),
    index: -1,
    currentCandidate: null,
    phase: "build",
    lastAck: null,
    verifySentAt: 0,

    bannedCommands: Array.isArray(learnedEntry?.bannedCommands) ? [...learnedEntry.bannedCommands] : [],
    supportedCodes: Array.isArray(learnedEntry?.supportedCodes) ? [...learnedEntry.supportedCodes] : [],
    rangeStart: Number.isFinite(Number(learnedEntry?.rangeStart)) ? Number(learnedEntry.rangeStart) : null,
    rangeEnd: Number.isFinite(Number(learnedEntry?.rangeEnd)) ? Number(learnedEntry.rangeEnd) : null
};

// -------------------------------------------------
// MODE NUMERIQUE
// -------------------------------------------------
if (msg._learn.kind === "number") {
    session.requestedValue = msg._learn.requestedValue;
    session.tolerance = msg._learn.tolerance;

    let ordered = [];

    // si une commande a déjà été apprise pour ce fingerprint, on la tente d'abord
    if (learnedEntry && learnedEntry.key) {
        ordered.push({
            kind: "number_candidate",
            key: learnedEntry.key,
            source: "learned"
        });
    }

    // puis le registre complet
    for (const c of cfg.candidates) {
        if (!ordered.some(x => x.key === c.key)) {
            ordered.push({
                kind: "number_candidate",
                key: c.key,
                source: "registry"
            });
        }
    }

    session.candidateKeys = ordered;
}

// -------------------------------------------------
// MODE ENUM PROFILE
// -------------------------------------------------
if (msg._learn.kind === "enum_profile") {
    session.kind = "enum_profile_detect";
    session.requestedSlot = msg._learn.requestedSlot;

    let preferred = null;

    if (
        learnedEntry &&
        learnedEntry.mode === "profile" &&
        typeof learnedEntry.profileKey === "string" &&
        cleanString(learnedEntry.profileKey)
    ) {
        preferred = cleanString(learnedEntry.profileKey);
    }

    if (!preferred && typeof cfg.defaultProfile === "string" && cleanString(cfg.defaultProfile)) {
        preferred = cleanString(cfg.defaultProfile);
    }

    session.detectState = {
        phase: "normal",
        preferredProfile: preferred,
        resolvedProfile: null,
        lastVerifiedCode: null,
        probeHighAck: false,
        probeHighNak: false,
        probeLowAck: false,
        probeLowNak: false
    };
}

flow.set(sessionKey, session);

node.status({
    fill: "blue",
    shape: "dot",
    text: session.kind === "enum_profile_detect"
        ? `learn decision ${param} (${session.detectState?.preferredProfile || "auto"})`
        : `learn decision ${param}`
});

msg._learn_action = "next_candidate";
return msg;

// ====== LEARNING - RX FEEDBACK ======
// Entrées possibles:
// - Parser sortie 2
// - Queue Pump timeout sortie 2
//
// Sortie 1 = enqueue QPIRI verify
// Sortie 2 = next candidate / fail

const inv = msg.inverterNum ?? 1;
const sessionKey = `learn_session_inv${inv}`;
const pendingLearnKey = `learn_pending_inv${inv}`;

function cleanUpper(v) {
    return String(v ?? "").trim().toUpperCase();
}

function cleanResp(v) {
    return String(v ?? "")
        .trim()
        .replace(/^\(/, "")
        .trim()
        .toUpperCase();
}

function ensureArray(arr) {
    return Array.isArray(arr) ? arr : [];
}

function addUnique(arr, value) {
    const v = cleanUpper(value);
    const out = ensureArray(arr).map(x => cleanUpper(x));
    if (v && !out.includes(v)) out.push(v);
    return out;
}

function buildFailMsg(session, reason) {
    return {
        inverterNum: inv,
        topic: `voltronic/${inv}/learning/status`,
        payload: {
            active: false,
            success: false,
            reason,
            param: session.param,
            requested_slot: session.requestedSlot ?? null,
            requested_value: session.requestedValue ?? null,
            fingerprint: session.fingerprint,
            finished_at: new Date().toISOString()
        },
        _learn_complete: true,
        _learn_success: false
    };
}

let session = flow.get(sessionKey);
if (!session || session.active !== true) return null;

const pending = flow.get(pendingLearnKey) || null;

const currentCmd = cleanUpper(session.currentCandidate?.command || "");
const msgCmd = cleanUpper(
    msg._raw_command ||
    msg.command ||
    msg._cmd ||
    msg.payload?.raw_command ||
    msg.payload?.command
);

const pendingCmd = cleanUpper(pending?.cmd || "");

const rawResp = cleanResp(
    msg._raw_response ??
    msg.raw_response ??
    msg.payload?.raw_response ??
    msg.payload?.raw ??
    ""
);

const isTimeout = (msg._learn_timeout === true || msg.payload?.timeout === true);

const isNak =
    msg.payload?.nak === true ||
    rawResp.startsWith("NAK");

const isAck =
    !isTimeout &&
    !isNak &&
    (
        rawResp.startsWith("ACK") ||
        msg.payload?.nak === false
    );

function markResolvedProfile(session, profileKey) {
    const ds = session.detectState || {};
    ds.resolvedProfile = profileKey;

    if (profileKey === "pop_00_02" || profileKey === "pcp_00_02") {
        session.rangeStart = 0;
        session.rangeEnd = 2;
    } else if (profileKey === "pop_01_03" || profileKey === "pcp_01_03") {
        session.rangeStart = 1;
        session.rangeEnd = 3;
    }

    session.detectState = ds;
}

function advanceDetectPhaseOnFailure(session, reasonType = "") {
    if (session.kind !== "enum_profile_detect") {
        session.phase = "build";
        return { type: "next" };
    }

    const detectState = session.detectState || {
        phase: "normal",
        preferredProfile: null,
        resolvedProfile: null,
        lastVerifiedCode: null,
        probeHighAck: false,
        probeHighNak: false,
        probeLowAck: false,
        probeLowNak: false
    };

    const currentCommand = cleanUpper(session.currentCandidate?.command || "");
    const phase = cleanUpper(session.currentCandidate?.phase || detectState.phase || "");

    // -------------------------------------------------
    // Si le 03 échoue => plage basse
    // -------------------------------------------------
    if ((isNak || isTimeout) && (currentCommand === "POP03" || currentCommand === "PCP03")) {
        session.bannedCommands = addUnique(session.bannedCommands, currentCommand);
        detectState.probeHighNak = true;

        if (currentCommand === "POP03") {
            markResolvedProfile(session, "pop_00_02");
        } else if (currentCommand === "PCP03") {
            markResolvedProfile(session, "pcp_00_02");
        }

        detectState.phase = "reapply_final";
        session.detectState = detectState;
        session.phase = "build";
        return { type: "next" };
    }

    // -------------------------------------------------
    // Si le 00 échoue => plage haute
    // -------------------------------------------------
    if ((isNak || isTimeout) && (currentCommand === "POP00" || currentCommand === "PCP00")) {
        detectState.probeLowNak = true;

        if (currentCommand === "POP00") {
            markResolvedProfile(session, "pop_01_03");
        } else if (currentCommand === "PCP00") {
            markResolvedProfile(session, "pcp_01_03");
        }

        detectState.phase = "reapply_final";
        session.detectState = detectState;
        session.phase = "build";
        return { type: "next" };
    }

    // -------------------------------------------------
    // Si la tentative normale échoue, on force une vraie détection :
    // 1) probe_low (00)
    // 2) probe_high (03)
    // -------------------------------------------------
    if (phase === "NORMAL" || detectState.phase === "normal") {
        detectState.phase = "probe_low";
        session.detectState = detectState;
        session.phase = "build";
        return { type: "next" };
    }

    if (phase === "PROBE_LOW" || detectState.phase === "probe_low") {
        detectState.phase = "probe_high";
        session.detectState = detectState;
        session.phase = "build";
        return { type: "next" };
    }

    if (phase === "PROBE_HIGH" || detectState.phase === "probe_high") {
        session.detectState = detectState;
        session.phase = "failed";
        return { type: "fail", reason: reasonType || "probe_high_failed" };
    }

    if (phase === "REAPPLY_FINAL" || detectState.phase === "reapply_final") {
        session.detectState = detectState;
        session.phase = "failed";
        return { type: "fail", reason: reasonType || "reapply_failed" };
    }

    session.phase = "failed";
    return { type: "fail", reason: reasonType || "invalid_detect_phase" };
}

// -------------------------
// PHASE 1 : wait_ack
// -------------------------
if (session.phase === "wait_ack") {
    let cmdMatches = false;

    if (pendingCmd && msgCmd && pendingCmd === msgCmd) {
        cmdMatches = true;
    } else if (currentCmd && msgCmd && currentCmd === msgCmd) {
        cmdMatches = true;
    }

    if (isTimeout) {
        if (pendingCmd && currentCmd && pendingCmd === currentCmd) {
            cmdMatches = true;
        } else if (!pendingCmd && currentCmd) {
            cmdMatches = true;
        }
    }

    if (!cmdMatches) return null;

    if (isTimeout) {
        session.lastAck = "TIMEOUT";
        session.updatedAt = Date.now();

        const step = advanceDetectPhaseOnFailure(session, "candidate_timeout");

        flow.set(sessionKey, session);
        flow.set(pendingLearnKey, null);

        if (step.type === "fail") {
            node.status({ fill: "red", shape: "ring", text: `learn fail ${session.param}` });
            return [null, buildFailMsg(session, step.reason || "candidate_timeout")];
        }

        node.status({ fill: "red", shape: "ring", text: `learn timeout ${session.param}` });

        return [null, {
            inverterNum: inv,
            _learn_action: "next_candidate",
            _learn: { sessionId: session.sessionId }
        }];
    }

    if (isNak) {
        session.lastAck = "NAK";
        session.updatedAt = Date.now();

        const currentCommand = cleanUpper(session.currentCandidate?.command || "");
        if (currentCommand === "POP03" || currentCommand === "PCP03") {
            session.bannedCommands = addUnique(session.bannedCommands, currentCommand);
        }

        const step = advanceDetectPhaseOnFailure(session, "candidate_nak");

        flow.set(sessionKey, session);
        flow.set(pendingLearnKey, null);

        if (step.type === "fail") {
            node.status({ fill: "red", shape: "ring", text: `learn fail ${session.param}` });
            return [null, buildFailMsg(session, step.reason || "candidate_nak")];
        }

        node.status({
            fill: "yellow",
            shape: "ring",
            text: `learn NAK ${session.currentCandidate?.command || session.param}`
        });

        return [null, {
            inverterNum: inv,
            _learn_action: "next_candidate",
            _learn: { sessionId: session.sessionId }
        }];
    }

    if (isAck) {
        session.lastAck = "ACK";
        session.phase = "wait_state";
        session.verifySentAt = Date.now();
        session.updatedAt = Date.now();

        const currentCommand = cleanUpper(session.currentCandidate?.command || "");
        const currentPhase = cleanUpper(session.currentCandidate?.phase || "");

        const ds = session.detectState || {};
        if (currentCommand === "POP03" || currentCommand === "PCP03") ds.probeHighAck = true;
        if (currentCommand === "POP00" || currentCommand === "PCP00") ds.probeLowAck = true;
        session.detectState = ds;

        flow.set(sessionKey, session);
        flow.set(pendingLearnKey, {
            sessionId: session.sessionId,
            param: session.param,
            cmd: "QPIRI",
            phase: "wait_state",
            ts: Date.now()
        });

        const verifyMsg = {
            inverterNum: inv,
            command: "QPIRI",
            _cmd: "QPIRI",
            _raw_command: "QPIRI",
            payload: "QPIRI",
            _burst: false,
            _origin: "learn_retry",
            _learn: {
                sessionId: session.sessionId,
                param: session.param,
                requestedValue: session.requestedValue ?? null,
                requestedSlot: session.requestedSlot ?? null,
                candidateKey: session.currentCandidate?.key || null,
                profileKey: session.currentCandidate?.profileKey || null,
                detectPhase: currentPhase || session.detectState?.phase || null,
                phase: "verify"
            }
        };

        node.status({
            fill: "blue",
            shape: "dot",
            text: `learn verify ${session.param}`
        });

        return [verifyMsg, null];
    }

    return null;
}

// -------------------------
// PHASE 2 : wait_state
// -------------------------
if (session.phase === "wait_state") {
    const waitingForQpiri = (pendingCmd === "QPIRI");
    if (!waitingForQpiri) return null;

    if (isTimeout) {
        session.lastAck = "QPIRI_TIMEOUT";
        session.updatedAt = Date.now();

        const step = advanceDetectPhaseOnFailure(session, "verify_timeout");

        flow.set(sessionKey, session);
        flow.set(pendingLearnKey, null);

        if (step.type === "fail") {
            node.status({ fill: "red", shape: "ring", text: `learn fail ${session.param}` });
            return [null, buildFailMsg(session, step.reason || "verify_timeout")];
        }

        node.status({
            fill: "red",
            shape: "ring",
            text: `verify timeout ${session.param}`
        });

        return [null, {
            inverterNum: inv,
            _learn_action: "next_candidate",
            _learn: { sessionId: session.sessionId }
        }];
    }

    return null;
}

return null;

// ====== LEARNING - BUILD CANDIDATE ======
// Sortie 1 = queue enqueue
// Sortie 2 = complete fail

const inv = msg.inverterNum ?? 1;

// -------------------------------------------------
// Helpers
// -------------------------------------------------
function getParallelId(inv) {
    let machine = flow.get(`inv${inv}_parallel_id`);
    if (machine === undefined || machine === null || machine === "") machine = 0;
    machine = Number(machine);
    if (!Number.isFinite(machine) || machine < 0 || machine > 9) machine = 0;
    return machine;
}

function pad3(x) {
    return String(Math.trunc(Number(x))).padStart(3, "0");
}

function fixed1(x) {
    return Number(x).toFixed(1);
}

function isBanned(session, cmd) {
    const banned = Array.isArray(session?.bannedCommands) ? session.bannedCommands : [];
    return banned.includes(String(cmd || "").trim().toUpperCase());
}

function getRegistry(inv) {
    const machine = getParallelId(inv);

    return {
        battery_bulk_voltage: {
            kind: "number",
            candidates: [
                { key: "BULK_PCVV", build: (v) => `PCVV${fixed1(v)}` }
            ]
        },

        battery_float_voltage: {
            kind: "number",
            candidates: [
                { key: "FLOAT_PBFT", build: (v) => `PBFT${fixed1(v)}` }
            ]
        },

        battery_under_voltage: {
            kind: "number",
            candidates: [
                { key: "UNDER_PSDV", build: (v) => `PSDV${fixed1(v)}` }
            ]
        },

        battery_recharge_voltage: {
            kind: "number",
            candidates: [
                { key: "BACK_GRID_PBCV", build: (v) => `PBCV${fixed1(v)}` }
            ]
        },

        battery_re_discharge_voltage: {
            kind: "number",
            candidates: [
                { key: "BACK_BATT_PBDV", build: (v) => `PBDV${fixed1(v)}` }
            ]
        },

        max_charging_current: {
            kind: "number",
            candidates: [
                { key: "MNCHGC_3", build: (v) => `MNCHGC${pad3(v)}` },
                { key: "MNCHGC_MACHINE", build: (v) => `MNCHGC${machine}${pad3(v)}` },
                { key: "MNCHGC_RAW", build: (v) => `MNCHGC${Math.trunc(Number(v))}` },
                { key: "PBDCHGC", build: (v) => `PBDCHGC${pad3(v)}` }
            ]
        },

        max_ac_charging_current: {
            kind: "number",
            candidates: [
                // priorité voulue : tester d'abord MUCHGC0002 / format 4 digits
                { key: "MUCHGC_4", build: (v) => `MUCHGC${String(Math.trunc(Number(v))).padStart(4, "0")}` },

                // puis fallback formats alternatifs
                { key: "MUCHGC_3", build: (v) => `MUCHGC${String(Math.trunc(Number(v))).padStart(3, "0")}` },
                { key: "MUCHGC_2", build: (v) => `MUCHGC${String(Math.trunc(Number(v))).padStart(2, "0")}` },
                { key: "MUCHGC_RAW", build: (v) => `MUCHGC${Math.trunc(Number(v))}` },
                { key: "PBCCHGC", build: (v) => `PBCCHGC${pad3(v)}` }
            ]
        },

        output_source_priority: {
            kind: "enum_profile_detect",
            statePath: "params.qpiri.output_source_priority_code",
            family: "POP",
            defaultProfile: "pop_01_03",
            applyByProfile: {
                pop_00_02: {
                    0: { command: "POP00", expectedCode: 0 },
                    1: { command: "POP01", expectedCode: 1 },
                    2: { command: "POP02", expectedCode: 2 }
                },
                pop_01_03: {
                    0: { command: "POP01", expectedCode: 1 },
                    1: { command: "POP02", expectedCode: 2 },
                    2: { command: "POP03", expectedCode: 3 }
                }
            },
            detect: {
                low: { command: "POP00", expectedCode: 0, profileKey: "pop_00_02" },
                high: { command: "POP03", expectedCode: 3, profileKey: "pop_01_03" }
            }
        },

        charger_source_priority: {
            kind: "enum_profile_detect",
            statePath: "params.qpiri.charger_source_priority_code",
            family: "PCP",
            defaultProfile: "pcp_01_03",
            applyByProfile: {
                pcp_00_02: {
                    0: { command: "PCP00", expectedCode: 0 },
                    1: { command: "PCP01", expectedCode: 1 },
                    2: { command: "PCP02", expectedCode: 2 }
                },
                pcp_01_03: {
                    0: { command: "PCP01", expectedCode: 1 },
                    1: { command: "PCP02", expectedCode: 2 },
                    2: { command: "PCP03", expectedCode: 3 }
                }
            },
            detect: {
                low: { command: "PCP00", expectedCode: 0, profileKey: "pcp_00_02" },
                high: { command: "PCP03", expectedCode: 3, profileKey: "pcp_01_03" }
            }
        }
    };
}

// -------------------------------------------------
// Session
// -------------------------------------------------
const sessionKey = `learn_session_inv${inv}`;
const pendingLearnKey = `learn_pending_inv${inv}`;

let session = flow.get(sessionKey);
if (!session || session.active !== true) return null;

const registry = getRegistry(inv);
const cfg = registry[session.param];
if (!cfg) return null;

// -------------------------------------------------
// Helpers fail msg
// -------------------------------------------------
function buildFailMsg(reason) {
    return {
        inverterNum: inv,
        topic: `voltronic/${inv}/learning/status`,
        payload: {
            active: false,
            success: false,
            reason,
            param: session.param,
            requested_value: session.requestedValue ?? null,
            requested_slot: session.requestedSlot ?? null,
            fingerprint: session.fingerprint,
            finished_at: new Date().toISOString()
        },
        _learn_complete: true,
        _learn_success: false
    };
}

// -------------------------------------------------
// Anti boucle dure
// -------------------------------------------------
function antiLoopCheck(cmd, label) {
    const now = Date.now();
    const prev = session._loopGuard || {
        lastCommand: null,
        count: 0,
        firstTs: 0
    };

    if (prev.lastCommand === cmd && (now - Number(prev.firstTs || 0)) < 8000) {
        prev.count = Number(prev.count || 0) + 1;
    } else {
        prev.lastCommand = cmd;
        prev.count = 1;
        prev.firstTs = now;
    }

    session._loopGuard = prev;

    if (prev.count > 3) {
        session.phase = "failed";
        flow.set(sessionKey, session);
        flow.set(pendingLearnKey, null);

        node.status({
            fill: "red",
            shape: "ring",
            text: `loop stop ${label || session.param}`
        });

        return buildFailMsg(`same_command_loop_${cmd}`);
    }

    return null;
}

// -------------------------------------------------
// MODE NUMERIQUE
// -------------------------------------------------
if (session.kind === "number") {
    const currentIndex = Number(session.index);
    session.index = (Number.isFinite(currentIndex) ? currentIndex : -1) + 1;
    session.updatedAt = Date.now();

    if (!Array.isArray(session.candidateKeys)) {
        return [null, buildFailMsg("invalid_candidate_list")];
    }

    if (session.index >= session.candidateKeys.length) {
        node.status({
            fill: "red",
            shape: "ring",
            text: `learn fail ${session.param}`
        });
        return [null, buildFailMsg("no_candidate_left")];
    }

    const wanted = session.candidateKeys[session.index];
    const candidate = Array.isArray(cfg.candidates)
        ? cfg.candidates.find(c => c.key === wanted.key)
        : null;

    if (!candidate || typeof candidate.build !== "function") {
        flow.set(sessionKey, session);
        return [{
            inverterNum: inv,
            _learn_action: "next_candidate",
            _learn: { sessionId: session.sessionId }
        }, null];
    }

    const cmd = candidate.build(session.requestedValue);

    const loopFail = antiLoopCheck(cmd, candidate.key);
    if (loopFail) return [null, loopFail];

    session.currentCandidate = {
        mode: "number",
        key: candidate.key,
        source: wanted.source,
        command: cmd,
        sentAt: Date.now()
    };

    session.phase = "wait_ack";
    session.lastAck = null;

    flow.set(sessionKey, session);
    flow.set(pendingLearnKey, {
        sessionId: session.sessionId,
        param: session.param,
        cmd: cmd,
        phase: "wait_ack",
        ts: Date.now()
    });

    flow.set(`inv${inv}_poll_pause_until`, Date.now() + 2500);

    const out = {
        inverterNum: inv,
        command: cmd,
        _cmd: cmd,
        _raw_command: cmd,
        payload: cmd,
        _burst: false,
        _origin: "learn_retry",
        _ha_param: session.paramRaw || session.param,
        _ha_value: session.requestedRaw,
        _learn: {
            sessionId: session.sessionId,
            param: session.param,
            requestedValue: session.requestedValue,
            candidateKey: candidate.key,
            source: wanted.source,
            phase: "candidate"
        }
    };

    node.status({
        fill: "yellow",
        shape: "dot",
        text: `learn try ${candidate.key}`
    });

    return [out, null];
}

// -------------------------------------------------
// MODE DETECTION / REAPPLY PROFIL ENUM
// -------------------------------------------------
if (session.kind === "enum_profile_detect") {
    const detectState = session.detectState || {
        phase: "normal",
        preferredProfile: cfg.defaultProfile || null,
        resolvedProfile: null,
        lastVerifiedCode: null,
        probeHighAck: false,
        probeHighNak: false,
        probeLowAck: false,
        probeLowNak: false
    };

    let cmd = null;
    let expectedCode = null;
    let profileKey = null;
    let candidateLabel = null;

    if (detectState.phase === "normal") {
        const requestedSlot = Number(session.requestedSlot);
        const preferred =
            detectState.resolvedProfile ||
            detectState.preferredProfile ||
            cfg.defaultProfile ||
            null;

        if (
            preferred &&
            cfg.applyByProfile?.[preferred] &&
            cfg.applyByProfile[preferred][requestedSlot]
        ) {
            const slotCfg = cfg.applyByProfile[preferred][requestedSlot];
            cmd = slotCfg.command;
            expectedCode = Number(slotCfg.expectedCode);
            profileKey = preferred;
            candidateLabel = `normal_${preferred}`;
        } else {
            return [null, buildFailMsg("invalid_requested_slot")];
        }

        session.currentCandidate = {
            mode: "profile_detect",
            phase: "normal",
            command: cmd,
            expectedCode,
            profileKey,
            requestedSlot,
            sentAt: Date.now()
        };
    }

    else if (detectState.phase === "probe_low") {
        cmd = cfg.detect.low.command;
        expectedCode = cfg.detect.low.expectedCode;
        profileKey = cfg.detect.low.profileKey;
        candidateLabel = "probe_low_00";

        session.currentCandidate = {
            mode: "profile_detect",
            phase: "probe_low",
            command: cmd,
            expectedCode,
            profileKey,
            requestedSlot: session.requestedSlot,
            sentAt: Date.now()
        };
    }

    else if (detectState.phase === "probe_high") {
        if (isBanned(session, cfg.detect.high.command)) {
            return [null, buildFailMsg("high_probe_banned")];
        }

        cmd = cfg.detect.high.command;
        expectedCode = cfg.detect.high.expectedCode;
        profileKey = cfg.detect.high.profileKey;
        candidateLabel = "probe_high_03";

        session.currentCandidate = {
            mode: "profile_detect",
            phase: "probe_high",
            command: cmd,
            expectedCode,
            profileKey,
            requestedSlot: session.requestedSlot,
            sentAt: Date.now()
        };
    }

    else if (detectState.phase === "reapply_final") {
        const resolved = detectState.resolvedProfile;
        const requestedSlot = Number(session.requestedSlot);
        const slotCfg = cfg.applyByProfile?.[resolved]?.[requestedSlot];

        if (!resolved || !slotCfg) {
            return [null, buildFailMsg("invalid_reapply_profile")];
        }

        cmd = slotCfg.command;
        expectedCode = Number(slotCfg.expectedCode);
        profileKey = resolved;
        candidateLabel = "reapply_final_value";

        session.currentCandidate = {
            mode: "profile_detect",
            phase: "reapply_final",
            command: cmd,
            expectedCode,
            profileKey,
            requestedSlot,
            sentAt: Date.now()
        };
    }

    else {
        return [null, buildFailMsg("invalid_detect_phase")];
    }

    const loopFail = antiLoopCheck(cmd, candidateLabel);
    if (loopFail) return [null, loopFail];

    session.phase = "wait_ack";
    session.lastAck = null;
    session.updatedAt = Date.now();

    flow.set(sessionKey, session);
    flow.set(pendingLearnKey, {
        sessionId: session.sessionId,
        param: session.param,
        cmd: cmd,
        phase: "wait_ack",
        ts: Date.now()
    });

    flow.set(`inv${inv}_poll_pause_until`, Date.now() + 2500);

    const out = {
        inverterNum: inv,
        command: cmd,
        _cmd: cmd,
        _raw_command: cmd,
        payload: cmd,
        _burst: false,
        _origin: "learn_retry",
        _ha_param: session.paramRaw || session.param,
        _ha_value: session.requestedRaw,
        _learn: {
            sessionId: session.sessionId,
            param: session.param,
            requestedSlot: session.requestedSlot,
            detectPhase: detectState.phase,
            expectedCode,
            profileKey,
            candidateLabel,
            phase: "candidate"
        }
    };

    node.status({
        fill: "yellow",
        shape: "dot",
        text: `learn try ${candidateLabel}`
    });

    return [out, null];
}

return null;

// ====== LEARNING - STATE FEEDBACK ======
// Sortie 1 = complete success
// Sortie 2 = next candidate / next detect phase

const inv = msg.inverterNum ?? 1;
const sessionKey = `learn_session_inv${inv}`;
const pendingLearnKey = `learn_pending_inv${inv}`;

function getByPath(obj, path) {
    if (!obj || !path) return undefined;
    return path.split(".").reduce((acc, k) => acc && acc[k], obj);
}

function toNum(v) {
    const n = Number(v);
    return Number.isFinite(n) ? n : null;
}

function isEqual(a, b, tol) {
    const na = toNum(a);
    const nb = toNum(b);
    if (na == null || nb == null) return false;
    return Math.abs(na - nb) <= tol;
}

function addNumUnique(arr, value) {
    const out = Array.isArray(arr) ? [...arr] : [];
    const n = Number(value);
    if (Number.isFinite(n) && !out.includes(n)) out.push(n);
    return out.sort((a, b) => a - b);
}

function markResolvedProfile(session, profileKey) {
    const ds = session.detectState || {};
    ds.resolvedProfile = profileKey;

    if (profileKey === "pop_00_02" || profileKey === "pcp_00_02") {
        session.rangeStart = 0;
        session.rangeEnd = 2;
    } else if (profileKey === "pop_01_03" || profileKey === "pcp_01_03") {
        session.rangeStart = 1;
        session.rangeEnd = 3;
    }

    session.detectState = ds;
}

const session = flow.get(sessionKey);
if (!session || session.active !== true) return null;

if (session.phase !== "wait_state") return null;

const pending = flow.get(pendingLearnKey) || null;
const pendingCmd = String(pending?.cmd || "").trim().toUpperCase();
if (pendingCmd !== "QPIRI") return null;

const state = msg.payload;
if (!state || typeof state !== "object") return null;

const ageSinceVerify = Date.now() - Number(session.verifySentAt || 0);
if (ageSinceVerify < 1200) {
    return null;
}

// -------------------------
// MODE NUMERIQUE
// -------------------------
if (session.kind === "number") {
    const actualValue = getByPath(state, session.statePath);

    if (isEqual(actualValue, session.requestedValue, session.tolerance)) {
        flow.set(pendingLearnKey, null);

        const okMsg = {
            inverterNum: inv,
            topic: `voltronic/${inv}/learning/status`,
            payload: {
                active: false,
                success: true,
                param: session.param,
                candidate_key: session.currentCandidate?.key || null,
                command: session.currentCandidate?.command || null,
                requested_value: session.requestedValue,
                verified_value: actualValue,
                fingerprint: session.fingerprint,
                finished_at: new Date().toISOString()
            },
            _learn_complete: true,
            _learn_success: true
        };

        node.status({ fill: "green", shape: "dot", text: `learn OK ${session.param}` });
        return [okMsg, null];
    }

    flow.set(pendingLearnKey, null);

    node.status({ fill: "yellow", shape: "ring", text: `learn next ${session.param}` });
    return [null, {
        inverterNum: inv,
        _learn_action: "next_candidate",
        _learn: { sessionId: session.sessionId }
    }];
}

// -------------------------
// MODE DETECTION PROFIL ENUM + REAPPLY
// -------------------------
if (session.kind === "enum_profile_detect") {
    const actualCode = toNum(getByPath(state, session.statePath));
    const detectState = session.detectState || {
        phase: "normal",
        preferredProfile: null,
        resolvedProfile: null,
        lastVerifiedCode: null,
        probeHighAck: false,
        probeHighNak: false,
        probeLowAck: false,
        probeLowNak: false
    };

    detectState.lastVerifiedCode = actualCode;
    session.detectState = detectState;
    session.supportedCodes = addNumUnique(session.supportedCodes, actualCode);

    const currentPhase = String(session.currentCandidate?.phase || detectState.phase || "").trim().toLowerCase();
    const expectedCode = toNum(session.currentCandidate?.expectedCode);

    // -------------------------------------------------
    // normal:
    // si le code correspond, succès direct
    // sinon on lance une vraie détection par 00
    // -------------------------------------------------
    if (currentPhase === "normal") {
        if (actualCode != null && expectedCode != null && actualCode === expectedCode) {
            markResolvedProfile(
                session,
                session.currentCandidate?.profileKey ||
                detectState.resolvedProfile ||
                detectState.preferredProfile ||
                null
            );

            flow.set(sessionKey, session);
            flow.set(pendingLearnKey, null);

            const okMsg = {
                inverterNum: inv,
                topic: `voltronic/${inv}/learning/status`,
                payload: {
                    active: false,
                    success: true,
                    param: session.param,
                    profile_key: session.detectState?.resolvedProfile || null,
                    command: session.currentCandidate?.command || null,
                    requested_slot: session.requestedSlot,
                    verified_code: actualCode,
                    expected_code: expectedCode,
                    fingerprint: session.fingerprint,
                    finished_at: new Date().toISOString()
                },
                _learn_complete: true,
                _learn_success: true
            };

            node.status({ fill: "green", shape: "dot", text: `learn OK ${session.param}` });
            return [okMsg, null];
        }

        detectState.phase = "probe_low";
        session.detectState = detectState;
        session.updatedAt = Date.now();

        flow.set(sessionKey, session);
        flow.set(pendingLearnKey, null);

        node.status({ fill: "yellow", shape: "ring", text: `probe low ${session.param}` });
        return [null, {
            inverterNum: inv,
            _learn_action: "next_candidate",
            _learn: { sessionId: session.sessionId }
        }];
    }

    // -------------------------------------------------
    // probe_low:
    // si QPIRI lit 0 => plage basse confirmée
    // sinon on tente probe_high
    // -------------------------------------------------
    if (currentPhase === "probe_low") {
        if (actualCode === 0) {
            markResolvedProfile(
                session,
                session.currentCandidate?.profileKey || detectState.resolvedProfile || "pop_00_02"
            );
            detectState.phase = "reapply_final";

            session.detectState = detectState;
            session.updatedAt = Date.now();

            flow.set(sessionKey, session);
            flow.set(pendingLearnKey, null);

            node.status({ fill: "blue", shape: "dot", text: `reapply ${session.param}` });
            return [null, {
                inverterNum: inv,
                _learn_action: "next_candidate",
                _learn: { sessionId: session.sessionId }
            }];
        }

        detectState.phase = "probe_high";
        session.detectState = detectState;
        session.updatedAt = Date.now();

        flow.set(sessionKey, session);
        flow.set(pendingLearnKey, null);

        node.status({ fill: "yellow", shape: "ring", text: `probe high ${session.param}` });
        return [null, {
            inverterNum: inv,
            _learn_action: "next_candidate",
            _learn: { sessionId: session.sessionId }
        }];
    }

    // -------------------------------------------------
    // probe_high:
    // si QPIRI lit 3 => plage haute confirmée
    // sinon échec
    // -------------------------------------------------
    if (currentPhase === "probe_high") {
        if (actualCode === 3) {
            markResolvedProfile(
                session,
                session.currentCandidate?.profileKey || detectState.resolvedProfile || "pop_01_03"
            );
            detectState.phase = "reapply_final";

            session.detectState = detectState;
            session.updatedAt = Date.now();

            flow.set(sessionKey, session);
            flow.set(pendingLearnKey, null);

            node.status({ fill: "blue", shape: "dot", text: `reapply ${session.param}` });
            return [null, {
                inverterNum: inv,
                _learn_action: "next_candidate",
                _learn: { sessionId: session.sessionId }
            }];
        }

        flow.set(pendingLearnKey, null);

        node.status({ fill: "red", shape: "ring", text: `learn fail ${session.param}` });
        return [null, {
            inverterNum: inv,
            topic: `voltronic/${inv}/learning/status`,
            payload: {
                active: false,
                success: false,
                reason: "profile_not_resolved",
                param: session.param,
                requested_slot: session.requestedSlot,
                fingerprint: session.fingerprint,
                finished_at: new Date().toISOString()
            },
            _learn_complete: true,
            _learn_success: false
        }];
    }

    // -------------------------------------------------
    // reapply_final:
    // on valide que la vraie commande du slot demandé
    // donne bien le code attendu
    // -------------------------------------------------
    if (currentPhase === "reapply_final") {
        if (actualCode != null && expectedCode != null && actualCode === expectedCode) {
            flow.set(pendingLearnKey, null);

            const okMsg = {
                inverterNum: inv,
                topic: `voltronic/${inv}/learning/status`,
