        if (!all[fp]) all[fp] = {};

        const prev = all[fp][param] || {};

        all[fp][param] = {
            ...prev,
            bannedCommands: uniqUpper(session?.bannedCommands || prev.bannedCommands || []),
            supportedCodes: uniqNums(session?.supportedCodes || prev.supportedCodes || []),
            rangeStart: Number.isFinite(Number(session?.rangeStart)) ? Number(session?.rangeStart) : prev.rangeStart ?? null,
            rangeEnd: Number.isFinite(Number(session?.rangeEnd)) ? Number(session?.rangeEnd) : prev.rangeEnd ?? null,
            failCount: Number(prev.failCount || 0) + 1,
            lastFailAt: Date.now()
        };

        if (
            all[fp][param].failCount >= 3 &&
            !all[fp][param].profileKey &&
            !all[fp][param].key
        ) {
