// ====== LEARNING - RESTORE / VALIDATE PROFILE ======
// A placer sur une branche de la sortie de NORMALIZE STATE
// Restaure learned_commands depuis le stockage persistant si l'onduleur est reconnu
// Règle retenue : 1 seul élément d'identité valide peut suffire (serial OU model OU fw_main)
// On évite de purger tant qu'il n'y a pas de contradiction claire

const inv = msg.inverterNum ?? 1;

function clone(obj) {
    return JSON.parse(JSON.stringify(obj || {}));
}

function cleanString(v) {
    return String(v ?? "").trim();
}

function getIdentityFromPayload(payload) {
    const model = cleanString(payload?.diag?.model);
    const serial = cleanString(payload?.diag?.serial);
    const fw_main = cleanString(payload?.diag?.fw_main);

    let fingerprint = "";
    let key = "";

    if (serial) {
        fingerprint = `SERIAL:${serial}`;
        key = `SERIAL:${serial}`;
    } else if (model && fw_main) {
        fingerprint = `MODELFW:${model}|${fw_main}`;
        key = `MODELFW:${model}|${fw_main}`;
    } else if (model) {
        fingerprint = `MODEL:${model}`;
        key = `MODEL:${model}`;
    } else if (fw_main) {
        fingerprint = `FW:${fw_main}`;
        key = `FW:${fw_main}`;
    } else {
        return null;
    }

    return {
        model,
        serial,
        fw_main,
        fingerprint,
        key
    };
}

function buildIdentityVariants(identity) {
    const out = [];
    const seen = new Set();

    function add(v) {
        const s = cleanString(v);
        if (!s || seen.has(s)) return;
        seen.add(s);
        out.push(s);
    }

    add(identity?.serial ? `SERIAL:${identity.serial}` : "");
    add(identity?.model && identity?.fw_main ? `MODELFW:${identity.model}|${identity.fw_main}` : "");
    add(identity?.model ? `MODEL:${identity.model}` : "");
    add(identity?.fw_main ? `FW:${identity.fw_main}` : "");

    return out;
}

function same(a, b) {
    return cleanString(a) && cleanString(b) && cleanString(a) === cleanString(b);
}

// Retourne :
// - match: true si au moins un des 3 éléments communs match
// - contradiction: true si on a une contradiction claire
// - comparableCount: nombre d'éléments comparables présents des 2 côtés
function compareIdentity(savedIdentity, currentIdentity) {
    const saved = {
        serial: cleanString(savedIdentity?.serial),
        model: cleanString(savedIdentity?.model),
        fw_main: cleanString(savedIdentity?.fw_main)
    };

    const curr = {
        serial: cleanString(currentIdentity?.serial),
        model: cleanString(currentIdentity?.model),
        fw_main: cleanString(currentIdentity?.fw_main)
    };

    let comparableCount = 0;
    let matchCount = 0;
    let mismatchCount = 0;

    if (saved.serial && curr.serial) {
        comparableCount++;
        if (saved.serial === curr.serial) matchCount++;
        else mismatchCount++;
    }

    if (saved.model && curr.model) {
        comparableCount++;
        if (saved.model === curr.model) matchCount++;
        else mismatchCount++;
    }

    if (saved.fw_main && curr.fw_main) {
        comparableCount++;
        if (saved.fw_main === curr.fw_main) matchCount++;
        else mismatchCount++;
    }

    const match = matchCount >= 1;

    // Contradiction claire :
    // - serial connu des 2 côtés et différent
    // - ou 2 infos comparables ou plus, toutes différentes, aucune ne match
    let contradiction = false;

    if (saved.serial && curr.serial && saved.serial !== curr.serial) {
        contradiction = true;
    } else if (comparableCount >= 2 && matchCount === 0 && mismatchCount === comparableCount) {
        contradiction = true;
    }

    return {
        match,
        contradiction,
        comparableCount,
        matchCount,
        mismatchCount
    };
}

function getProfileLearnedMap(profile, learnedPersistent, learnedBackup) {
    const savedFp = cleanString(profile?.identity?.fingerprint || "");

    let sourceLearned = clone(profile?.learned || {});
    if (sourceLearned && typeof sourceLearned === "object" && Object.keys(sourceLearned).length > 0) {
        return sourceLearned;
    }

    sourceLearned = clone(learnedPersistent[savedFp] || {});
    if (sourceLearned && typeof sourceLearned === "object" && Object.keys(sourceLearned).length > 0) {
        return sourceLearned;
    }

    sourceLearned = clone(learnedBackup[savedFp] || {});
    if (sourceLearned && typeof sourceLearned === "object" && Object.keys(sourceLearned).length > 0) {
        return sourceLearned;
    }

    return {};
}

const state = msg.payload;
if (!state || typeof state !== "object") return msg;

const identity = getIdentityFromPayload(state);
if (!identity) {
    node.status({
        fill: "yellow",
        shape: "ring",
        text: `restore wait identity inv${inv}`
    });
    return msg;
}

const currentVariants = buildIdentityVariants(identity);

// lecture marqueurs
const lastAppliedKey = cleanString(
    flow.get(`inv${inv}_profile_identity_key`, "persistent") ||
    flow.get(`inv${inv}_profile_identity_key`) ||
    ""
);

const lastMatchedSavedKey = cleanString(
    flow.get(`inv${inv}_profile_saved_identity_key`, "persistent") ||
    flow.get(`inv${inv}_profile_saved_identity_key`) ||
    ""
);

// profils persistants
let profiles = clone(global.get("inverter_profiles", "persistent") || {});
if (!profiles || typeof profiles !== "object") profiles = {};

// learned_commands RAM
let learnedAll = clone(global.get("learned_commands") || {});
if (!learnedAll || typeof learnedAll !== "object") learnedAll = {};

// learned_commands persistent
let learnedPersistent = clone(global.get("learned_commands", "persistent") || {});
if (!learnedPersistent || typeof learnedPersistent !== "object") learnedPersistent = {};

// backup persistant
let learnedBackup = clone(global.get("learned_commands_backup", "persistent") || {});
if (!learnedBackup || typeof learnedBackup !== "object") learnedBackup = {};

const profile = profiles[`inv${inv}`] || null;

// aucun profil sauvegardé
if (!profile || !profile.identity) {
    flow.set(`inv${inv}_profile_identity_key`, identity.key, "persistent");
    flow.set(`inv${inv}_profile_identity_key`, identity.key);
    flow.set(`inv${inv}_profile_saved_identity_key`, "", "persistent");
    flow.set(`inv${inv}_profile_saved_identity_key`, "");

    node.status({
        fill: "yellow",
        shape: "dot",
        text: `no saved profile inv${inv}`
    });
    return msg;
}

const savedIdentity = {
    model: cleanString(profile.identity.model),
    serial: cleanString(profile.identity.serial),
    fw_main: cleanString(profile.identity.fw_main),
    fingerprint: cleanString(profile.identity.fingerprint),
    key: cleanString(profile.identity.key)
};

const compare = compareIdentity(savedIdentity, identity);
const savedVariants = buildIdentityVariants(savedIdentity);

// Vérifie si déjà réellement restauré
const currentFp = cleanString(identity.fingerprint);
const alreadyLoaded =
    lastAppliedKey === identity.key &&
    lastMatchedSavedKey === savedIdentity.key &&
    learnedAll &&
    typeof learnedAll === "object" &&
    learnedAll[currentFp] &&
    typeof learnedAll[currentFp] === "object" &&
    Object.keys(learnedAll[currentFp]).length > 0;

// -------------------------------------------------
// CAS 1 : au moins 1 élément match => restauration
// -------------------------------------------------
if (compare.match) {
    if (!alreadyLoaded) {
        const sourceLearned = getProfileLearnedMap(profile, learnedPersistent, learnedBackup);
        const savedFp = cleanString(savedIdentity.fingerprint);

        // injecte la config apprise sous le fingerprint courant
        learnedAll[currentFp] = clone(sourceLearned || {});
        global.set("learned_commands", learnedAll);
        global.set("learned_commands", learnedAll, "persistent");

        // garde aussi la version sous le fingerprint sauvegardé si différent
        if (savedFp && savedFp !== currentFp) {
            learnedAll[savedFp] = clone(sourceLearned || {});
            global.set("learned_commands", learnedAll);
            global.set("learned_commands", learnedAll, "persistent");
        }

        learnedBackup[currentFp] = clone(sourceLearned || {});
        global.set("learned_commands_backup", learnedBackup, "persistent");

        if (savedFp && savedFp !== currentFp) {
            learnedBackup[savedFp] = clone(sourceLearned || {});
            global.set("learned_commands_backup", learnedBackup, "persistent");
        }
    }

    flow.set(`inv${inv}_profile_identity_key`, identity.key, "persistent");
    flow.set(`inv${inv}_profile_identity_key`, identity.key);

    flow.set(`inv${inv}_profile_saved_identity_key`, savedIdentity.key, "persistent");
    flow.set(`inv${inv}_profile_saved_identity_key`, savedIdentity.key);

    node.status({
        fill: "green",
        shape: "dot",
        text: alreadyLoaded ? `profile already ok inv${inv}` : `profile restored inv${inv}`
    });

    return msg;
}

// -------------------------------------------------
// CAS 2 : pas de match mais pas assez d'éléments pour conclure => attendre
// -------------------------------------------------
if (!compare.contradiction) {
    node.status({
        fill: "yellow",
        shape: "ring",
        text: `restore wait more id inv${inv}`
    });
    return msg;
}

// -------------------------------------------------
// CAS 3 : contradiction claire => purge
// -------------------------------------------------
delete profiles[`inv${inv}`];
global.set("inverter_profiles", profiles, "persistent");

const oldFingerprint = cleanString(savedIdentity.fingerprint || "");

if (oldFingerprint && learnedAll[oldFingerprint]) {
    delete learnedAll[oldFingerprint];
    global.set("learned_commands", learnedAll);
    global.set("learned_commands", learnedAll, "persistent");
}

