    flow.set(`inv${inv}_profile_saved_identity_key`, "");

    node.status({
        fill: "yellow",
        shape: "dot",
        text: `no saved profile inv${inv}`
    });
    return msg;
}

const savedIdentity = {
    model: cleanString(profile.identity.model),
    serial: cleanString(profile.identity.serial),
    fw_main: cleanString(profile.identity.fw_main),
    fingerprint: cleanString(profile.identity.fingerprint),
    key: cleanString(profile.identity.key)
};

const compare = compareIdentity(savedIdentity, identity);
const savedVariants = buildIdentityVariants(savedIdentity);

// Vérifie si déjà réellement restauré
const currentFp = cleanString(identity.fingerprint);
const alreadyLoaded =
    lastAppliedKey === identity.key &&
    lastMatchedSavedKey === savedIdentity.key &&
    learnedAll &&
    typeof learnedAll === "object" &&
    learnedAll[currentFp] &&
    typeof learnedAll[currentFp] === "object" &&
    Object.keys(learnedAll[currentFp]).length > 0;

// -------------------------------------------------
// CAS 1 : au moins 1 élément match => restauration
// -------------------------------------------------
if (compare.match) {
    if (!alreadyLoaded) {
        const sourceLearned = getProfileLearnedMap(profile, learnedPersistent, learnedBackup);
        const savedFp = cleanString(savedIdentity.fingerprint);

        // injecte la config apprise sous le fingerprint courant
        learnedAll[currentFp] = clone(sourceLearned || {});
        global.set("learned_commands", learnedAll);
        global.set("learned_commands", learnedAll, "persistent");

        // garde aussi la version sous le fingerprint sauvegardé si différent
        if (savedFp && savedFp !== currentFp) {
            learnedAll[savedFp] = clone(sourceLearned || {});
            global.set("learned_commands", learnedAll);
            global.set("learned_commands", learnedAll, "persistent");
        }

        learnedBackup[currentFp] = clone(sourceLearned || {});
        global.set("learned_commands_backup", learnedBackup, "persistent");

        if (savedFp && savedFp !== currentFp) {
            learnedBackup[savedFp] = clone(sourceLearned || {});
            global.set("learned_commands_backup", learnedBackup, "persistent");
        }
    }

    flow.set(`inv${inv}_profile_identity_key`, identity.key, "persistent");
    flow.set(`inv${inv}_profile_identity_key`, identity.key);

    flow.set(`inv${inv}_profile_saved_identity_key`, savedIdentity.key, "persistent");
    flow.set(`inv${inv}_profile_saved_identity_key`, savedIdentity.key);

    node.status({
        fill: "green",
        shape: "dot",
        text: alreadyLoaded ? `profile already ok inv${inv}` : `profile restored inv${inv}`
    });

    return msg;
}

// -------------------------------------------------
// CAS 2 : pas de match mais pas assez d'éléments pour conclure => attendre
// -------------------------------------------------
if (!compare.contradiction) {
    node.status({
        fill: "yellow",
        shape: "ring",
        text: `restore wait more id inv${inv}`
    });
    return msg;
}

// -------------------------------------------------
// CAS 3 : contradiction claire => purge
// -------------------------------------------------
delete profiles[`inv${inv}`];
global.set("inverter_profiles", profiles, "persistent");

const oldFingerprint = cleanString(savedIdentity.fingerprint || "");

if (oldFingerprint && learnedAll[oldFingerprint]) {
    delete learnedAll[oldFingerprint];
    global.set("learned_commands", learnedAll);
    global.set("learned_commands", learnedAll, "persistent");
}

if (oldFingerprint && learnedPersistent[oldFingerprint]) {
    delete learnedPersistent[oldFingerprint];
    global.set("learned_commands", learnedPersistent, "persistent");
}

if (oldFingerprint && learnedBackup[oldFingerprint]) {
    delete learnedBackup[oldFingerprint];
    global.set("learned_commands_backup", learnedBackup, "persistent");
}

flow.set(`learn_session_inv${inv}`, null);
flow.set(`learn_pending_inv${inv}`, null);
flow.set(`learn_session_inv${inv}`, null, "persistent");
flow.set(`learn_pending_inv${inv}`, null, "persistent");

flow.set(`inv${inv}_profile_identity_key`, identity.key, "persistent");
flow.set(`inv${inv}_profile_identity_key`, identity.key);

flow.set(`inv${inv}_profile_saved_identity_key`, "", "persistent");
flow.set(`inv${inv}_profile_saved_identity_key`, "");

node.status({
    fill: "red",
    shape: "ring",
    text: `profile cleared inv${inv} changed`
});

return msg;

// =====================================
// DAILY ENERGY CALC / FALLBACK
// VERSION ROBUSTE PERSISTENCE + FILE STORE + ANTI RESET POST UPDATE
// =====================================

if (!msg || !msg.payload || typeof msg.payload !== "object") return msg;

const inv = Number(msg.inverterNum ?? msg.payload.inverter ?? 1) || 1;
const state = { ...msg.payload };

const premiumActive = global.get("premium.active") === true;
const fs = global.get("fs");
const path = global.get("path");

const ENERGY_STORE_FILE = "/config/smart_voltronic_energy_store.json";
const FILE_STORE_VERSION = 1;
const fileInvKey = `inverter_${inv}`;

function toNum(v) {
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
}

function round2(v) {
  const n = Number(v);
  return Number.isFinite(n) ? Math.round((n + Number.EPSILON) * 100) / 100 : 0;
}

function clampNonNegative(v, fb = 0) {
  const n = Number(v);
  if (!Number.isFinite(n)) return fb;
  return Math.max(0, round2(n));
}

function ensureObj(v, fb = {}) {
  return v && typeof v === "object" && !Array.isArray(v) ? v : fb;
}

function pickFirstNumber(...vals) {
  for (const v of vals) {
    const n = Number(v);
    if (Number.isFinite(n)) return n;
  }
  return null;
}

function getSafeTimezone() {
  let tz = (global.get("addon_timezone") || "UTC").toString().trim();
  if (!tz) tz = "UTC";

  try {
    new Intl.DateTimeFormat("en-CA", { timeZone: tz }).format(new Date());
  } catch (e) {
    tz = "UTC";
  }

  return tz;
}

function localDateParts(d = new Date()) {
  const tz = getSafeTimezone();

  const parts = new Intl.DateTimeFormat("en-CA", {
    timeZone: tz,
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hour12: false
  }).formatToParts(d);

  const get = (t) => parts.find(p => p.type === t)?.value;

  const year = get("year");
  const month = get("month");
  const day = get("day");
  const hour = Number(get("hour") || 0);
  const minute = Number(get("minute") || 0);

  return {
    year,
    month,
    day,
    hour,
    minute,
    minutesSinceMidnight: hour * 60 + minute,
    dayKey: `${year}${month}${day}`,
    monthKey: `${year}${month}`,
    yearKey: `${year}`
  };
}

function safeGet(key, storeName) {
  try {
    return flow.get(key, storeName);
  } catch (e) {
    return undefined;
  }
}

function safeSet(key, value, storeName) {
  try {
    flow.set(key, value, storeName);
    return true;
  } catch (e) {
    return false;
  }
}

function getRobust(key, fallback = null) {
  const fromPersistent = safeGet(key, "persistent");
  if (fromPersistent !== undefined && fromPersistent !== null) return fromPersistent;

  const fromDefault = safeGet(key);
  if (fromDefault !== undefined && fromDefault !== null) return fromDefault;

  return fallback;
}

function setRobust(key, value) {
  try {
    flow.set(key, value);
  } catch (e) { }

  safeSet(key, value, "persistent");
}

function readEnergyFileStore() {
  if (!fs) return null;

  try {
    if (!fs.existsSync(ENERGY_STORE_FILE)) return null;

    const raw = fs.readFileSync(ENERGY_STORE_FILE, "utf8");
    const data = JSON.parse(raw);

    if (!data || typeof data !== "object") return null;
    if (!data.inverters || typeof data.inverters !== "object") return null;

    return data;
  } catch (e) {
    node.warn("Energy file store read error: " + e.message);
    return null;
  }
}

function restoreStatsFromFile(invKey) {
  const data = readEnergyFileStore();
  const invData = data?.inverters?.[invKey];

  if (!invData || typeof invData !== "object") return null;
  if (!invData.stats || typeof invData.stats !== "object") return null;

  return invData.stats;
}

function restoreLastValuesFromFile(invKey) {
  const data = readEnergyFileStore();
  const invData = data?.inverters?.[invKey];

  if (!invData || typeof invData !== "object") return null;
  if (!invData.last_values || typeof invData.last_values !== "object") return null;

  return invData.last_values;
}

function writeEnergyFileStoreForInv(invKey, patch) {
  if (!fs) return false;

  try {
    let data = readEnergyFileStore();

    if (!data || typeof data !== "object") {
      data = {
        version: FILE_STORE_VERSION,
        updated_at: null,
        inverters: {}
      };
    }

    if (!data.inverters || typeof data.inverters !== "object") {
      data.inverters = {};
    }

    const previous = ensureObj(data.inverters[invKey], {});

    data.version = FILE_STORE_VERSION;
    data.updated_at = new Date().toISOString();

    data.inverters[invKey] = {
      ...previous,
      ...patch,
      updated_at: new Date().toISOString()
    };

    if (path && typeof path.dirname === "function") {
      fs.mkdirSync(path.dirname(ENERGY_STORE_FILE), { recursive: true });
    } else {
      fs.mkdirSync("/config", { recursive: true });
    }

    fs.writeFileSync(ENERGY_STORE_FILE, JSON.stringify(data, null, 2), "utf8");
    return true;
  } catch (e) {
    node.warn("Energy file store write error: " + e.message);
    return false;
  }
}

function setDiagSource(diag, key, source, reason = "") {
  diag[key] = source;
  if (reason) diag[`${key}_reason`] = reason;
}

const nowKeys = localDateParts(new Date());
const dayKey = nowKeys.dayKey;
const monthKey = nowKeys.monthKey;
const yearKey = nowKeys.yearKey;
const tsNow = Date.now();

state.diag = ensureObj(state.diag, {});
state.diag.energy_logic_version = "source_lock_v6_file_store_anti_reset";
state.diag.energy_timezone = getSafeTimezone();
state.diag.energy_file_store = ENERGY_STORE_FILE;

const statsKey = `inv${inv}_energy_stats`;

let statsRestoreSource = "new";

let stats = restoreStatsFromFile(fileInvKey);
if (stats) {
  statsRestoreSource = "file_config";
} else {
  stats = getRobust(statsKey, null);
  if (stats) statsRestoreSource = "node_red_context";
}

if (!stats || typeof stats !== "object") {
  stats = {
    lastTs: tsNow,
    lastDayKey: dayKey,
    lastMonthKey: monthKey,
    lastYearKey: yearKey,
    lastDayResetTs: tsNow,
    day: { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 },
    month: { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 },
    year: { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 },
    total: { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 }
  };
}

stats.day = ensureObj(stats.day, { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 });
stats.month = ensureObj(stats.month, { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 });
stats.year = ensureObj(stats.year, { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 });
stats.total = ensureObj(stats.total, { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 });

for (const bucket of ["day", "month", "year", "total"]) {
  stats[bucket].pv = Number(stats[bucket].pv) || 0;
  stats[bucket].load = Number(stats[bucket].load) || 0;
  stats[bucket].grid = Number(stats[bucket].grid) || 0;
  stats[bucket].battCharge = Number(stats[bucket].battCharge) || 0;
  stats[bucket].battDischarge = Number(stats[bucket].battDischarge) || 0;
}

if (!Number.isFinite(Number(stats.lastTs))) stats.lastTs = tsNow;
if (!stats.lastDayKey) stats.lastDayKey = dayKey;
if (!stats.lastMonthKey) stats.lastMonthKey = monthKey;
if (!stats.lastYearKey) stats.lastYearKey = yearKey;
if (!Number.isFinite(Number(stats.lastDayResetTs))) stats.lastDayResetTs = tsNow;

let dtHours = (tsNow - Number(stats.lastTs || tsNow)) / 3600000;
if (!Number.isFinite(dtHours) || dtHours < 0) dtHours = 0;
if (dtHours > 1) dtHours = 0;

const dayChanged = stats.lastDayKey !== dayKey;
const monthChanged = stats.lastMonthKey !== monthKey;
const yearChanged = stats.lastYearKey !== yearKey;

if (dayChanged) {
  stats.day = { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 };
  stats.lastDayResetTs = tsNow;
}

if (monthChanged) {
  stats.month = { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 };
}

if (yearChanged) {
  stats.year = { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 };
}

const pvPower =
  pickFirstNumber(
    state.pv_total_power,
    state.pv_power,
    state.solar_power,
    state.pv1_power
  ) || 0;

const loadPower =
  pickFirstNumber(
    state.ac_output_active_power,
    state.load_power,
    state.output_load_power,
    state.ac_output_power
  ) || 0;

const batteryPower =
  pickFirstNumber(
    state.battery_power,
    state.global_battery_power
  ) || 0;

let gridPower =
  pickFirstNumber(
    state.grid_power,
    state.utility_power
  );

if (!Number.isFinite(gridPower)) {
  const battContributionToLoad = batteryPower < 0 ? Math.abs(batteryPower) : 0;
  const battChargeFromSystem = batteryPower > 0 ? batteryPower : 0;
  gridPower = Math.max(0, loadPower - pvPower - battContributionToLoad + battChargeFromSystem);
}

gridPower = Math.max(0, gridPower);

const MIDNIGHT_GUARD_MS = 5 * 60 * 1000;
const BATTERY_IDLE_W = 25;
const BATTERY_STRONG_ACTIVITY_W = 150;

const msSinceDayReset = tsNow - Number(stats.lastDayResetTs || tsNow);
const withinMidnightGuard = msSinceDayReset >= 0 && msSinceDayReset < MIDNIGHT_GUARD_MS;

let batteryChargeGuarded = false;
let batteryDischargeGuarded = false;

const pvInc = Math.max(0, pvPower) * dtHours / 1000;
const loadInc = Math.max(0, loadPower) * dtHours / 1000;
const gridInc = Math.max(0, gridPower) * dtHours / 1000;

const battChargePower = batteryPower > 0 ? batteryPower : 0;
const battDischargePower = batteryPower < 0 ? Math.abs(batteryPower) : 0;

let battChargeInc = Math.max(0, battChargePower) * dtHours / 1000;
let battDischargeInc = Math.max(0, battDischargePower) * dtHours / 1000;

if (withinMidnightGuard) {
  if (battChargePower > 0 && battChargePower < BATTERY_STRONG_ACTIVITY_W) {
    battChargeInc = 0;
    batteryChargeGuarded = true;
  }

  if (battDischargePower > 0 && battDischargePower < BATTERY_STRONG_ACTIVITY_W) {
    battDischargeInc = 0;
    batteryDischargeGuarded = true;
  }

  if (Math.abs(batteryPower) <= BATTERY_IDLE_W) {
    battChargeInc = 0;
    battDischargeInc = 0;
    batteryChargeGuarded = true;
    batteryDischargeGuarded = true;
  }
}

if (dtHours > 0) {
  stats.day.pv += pvInc;
  stats.day.load += loadInc;
  stats.day.grid += gridInc;
  stats.day.battCharge += battChargeInc;
  stats.day.battDischarge += battDischargeInc;

  stats.month.pv += pvInc;
  stats.month.load += loadInc;
  stats.month.grid += gridInc;
  stats.month.battCharge += battChargeInc;
  stats.month.battDischarge += battDischargeInc;

  stats.year.pv += pvInc;
  stats.year.load += loadInc;
  stats.year.grid += gridInc;
  stats.year.battCharge += battChargeInc;
  stats.year.battDischarge += battDischargeInc;

  stats.total.pv += pvInc;
  stats.total.load += loadInc;
  stats.total.grid += gridInc;
  stats.total.battCharge += battChargeInc;
  stats.total.battDischarge += battDischargeInc;
}

let calcPvDay = clampNonNegative(stats.day.pv);
let calcPvMonth = clampNonNegative(stats.month.pv);
let calcPvYear = clampNonNegative(stats.year.pv);
let calcPvTotal = clampNonNegative(stats.total.pv);

let calcLoadDay = clampNonNegative(stats.day.load);
let calcLoadMonth = clampNonNegative(stats.month.load);
let calcLoadYear = clampNonNegative(stats.year.load);
let calcLoadTotal = clampNonNegative(stats.total.load);

let calcGridDay = clampNonNegative(stats.day.grid);
let calcGridMonth = clampNonNegative(stats.month.grid);
let calcGridYear = clampNonNegative(stats.year.grid);
let calcGridTotal = clampNonNegative(stats.total.grid);

let calcBattChargeDay = clampNonNegative(stats.day.battCharge);
let calcBattChargeMonth = clampNonNegative(stats.month.battCharge);
let calcBattChargeYear = clampNonNegative(stats.year.battCharge);
let calcBattChargeTotal = clampNonNegative(stats.total.battCharge);

let calcBattDischargeDay = clampNonNegative(stats.day.battDischarge);
let calcBattDischargeMonth = clampNonNegative(stats.month.battDischarge);
let calcBattDischargeYear = clampNonNegative(stats.year.battDischarge);
let calcBattDischargeTotal = clampNonNegative(stats.total.battDischarge);

const lastValues = restoreLastValuesFromFile(fileInvKey) || {};

const justRestored =
  statsRestoreSource === "file_config" ||
  statsRestoreSource === "node_red_context";

const noNewEnergyIntegration = dtHours === 0;

function protectRestoredValue(currentValue, statsValue, lastFileValue) {
  const current = Number(currentValue) || 0;
  const fromStats = Number(statsValue) || 0;
  const fromFile = Number(lastFileValue) || 0;

  if (current > 0) return round2(current);
  if (fromStats > 0) return round2(fromStats);
  if (fromFile > 0) return round2(fromFile);

  return 0;
}

if (justRestored && noNewEnergyIntegration && !dayChanged) {
  calcPvDay = protectRestoredValue(calcPvDay, stats.day.pv, lastValues.pv_energy_day_kwh);
  calcLoadDay = protectRestoredValue(calcLoadDay, stats.day.load, lastValues.load_energy_day_kwh);
  calcGridDay = protectRestoredValue(calcGridDay, stats.day.grid, lastValues.grid_energy_day_kwh);
  calcBattChargeDay = protectRestoredValue(calcBattChargeDay, stats.day.battCharge, lastValues.battery_charge_day_kwh);
  calcBattDischargeDay = protectRestoredValue(calcBattDischargeDay, stats.day.battDischarge, lastValues.battery_discharge_day_kwh);
}

const inverterPvDayRaw = toNum(state.pv_energy_day_kwh);
const inverterPvMonthRaw = toNum(state.pv_energy_month_kwh);
const inverterPvYearRaw = toNum(state.pv_energy_year_kwh);
const inverterPvTotalRaw = toNum(state.pv_energy_total_kwh);

const inverterLoadDayRaw = toNum(state.load_energy_day_kwh);
const inverterLoadMonthRaw = toNum(state.load_energy_month_kwh);
const inverterLoadYearRaw = toNum(state.load_energy_year_kwh);
const inverterLoadTotalRaw = toNum(state.load_energy_total_kwh);

function nativeOk(v) {
  const n = Number(v);
  return Number.isFinite(n) && n >= 0;
}

function resolveNativeOrCalc(nativeVal, calcVal, metric, currentPower = 0) {
  const n = Number(nativeVal);
  const c = Number(calcVal) || 0;

  if (nativeOk(n)) {
    if (!(n === 0 && c > 0 && currentPower > 30)) {
      return {
        value: clampNonNegative(n),
        source: "inverter",
        reason: "native_valid"
      };
    }
  }

  return {
    value: clampNonNegative(c),
    source: "calculated",
    reason: "native_missing_or_invalid"
  };
}

const pvDayResolved = resolveNativeOrCalc(inverterPvDayRaw, calcPvDay, "pv_day", pvPower);
const pvMonthResolved = resolveNativeOrCalc(inverterPvMonthRaw, calcPvMonth, "pv_month", pvPower);
const pvYearResolved = resolveNativeOrCalc(inverterPvYearRaw, calcPvYear, "pv_year", pvPower);
const pvTotalResolved = resolveNativeOrCalc(inverterPvTotalRaw, calcPvTotal, "pv_total", pvPower);

const loadDayResolved = resolveNativeOrCalc(inverterLoadDayRaw, calcLoadDay, "load_day", loadPower);
const loadMonthResolved = resolveNativeOrCalc(inverterLoadMonthRaw, calcLoadMonth, "load_month", loadPower);
const loadYearResolved = resolveNativeOrCalc(inverterLoadYearRaw, calcLoadYear, "load_year", loadPower);
const loadTotalResolved = resolveNativeOrCalc(inverterLoadTotalRaw, calcLoadTotal, "load_total", loadPower);

state.pv_energy_day_kwh = pvDayResolved.value;
state.pv_energy_month_kwh = pvMonthResolved.value;
state.pv_energy_year_kwh = pvYearResolved.value;
state.pv_energy_total_kwh = pvTotalResolved.value;

state.load_energy_day_kwh = loadDayResolved.value;
state.load_energy_month_kwh = loadMonthResolved.value;
state.load_energy_year_kwh = loadYearResolved.value;
state.load_energy_total_kwh = loadTotalResolved.value;

state.grid_energy_day_kwh = calcGridDay;
state.grid_energy_month_kwh = calcGridMonth;
state.grid_energy_year_kwh = calcGridYear;
state.grid_energy_total_kwh = calcGridTotal;

state.battery_charge_day_kwh = calcBattChargeDay;
state.battery_charge_month_kwh = calcBattChargeMonth;
state.battery_charge_year_kwh = calcBattChargeYear;
state.battery_charge_total_kwh = calcBattChargeTotal;

state.battery_discharge_day_kwh = calcBattDischargeDay;
state.battery_discharge_month_kwh = calcBattDischargeMonth;
state.battery_discharge_year_kwh = calcBattDischargeYear;
state.battery_discharge_total_kwh = calcBattDischargeTotal;

stats.lastTs = tsNow;
stats.lastDayKey = dayKey;
stats.lastMonthKey = monthKey;
stats.lastYearKey = yearKey;

setRobust(statsKey, stats);

const fileWriteOk = writeEnergyFileStoreForInv(fileInvKey, {
  stats,
  last_values: {
    pv_energy_day_kwh: state.pv_energy_day_kwh,
    pv_energy_month_kwh: state.pv_energy_month_kwh,
    pv_energy_year_kwh: state.pv_energy_year_kwh,
    pv_energy_total_kwh: state.pv_energy_total_kwh,

    load_energy_day_kwh: state.load_energy_day_kwh,
    load_energy_month_kwh: state.load_energy_month_kwh,
    load_energy_year_kwh: state.load_energy_year_kwh,
    load_energy_total_kwh: state.load_energy_total_kwh,

    grid_energy_day_kwh: state.grid_energy_day_kwh,
    grid_energy_month_kwh: state.grid_energy_month_kwh,
    grid_energy_year_kwh: state.grid_energy_year_kwh,
    grid_energy_total_kwh: state.grid_energy_total_kwh,

    battery_charge_day_kwh: state.battery_charge_day_kwh,
    battery_charge_month_kwh: state.battery_charge_month_kwh,
    battery_charge_year_kwh: state.battery_charge_year_kwh,
    battery_charge_total_kwh: state.battery_charge_total_kwh,

    battery_discharge_day_kwh: state.battery_discharge_day_kwh,
    battery_discharge_month_kwh: state.battery_discharge_month_kwh,
    battery_discharge_year_kwh: state.battery_discharge_year_kwh,
    battery_discharge_total_kwh: state.battery_discharge_total_kwh
  }
});

setDiagSource(state.diag, "pv_energy_day_source", pvDayResolved.source, pvDayResolved.reason);
setDiagSource(state.diag, "pv_energy_month_source", pvMonthResolved.source, pvMonthResolved.reason);
setDiagSource(state.diag, "pv_energy_year_source", pvYearResolved.source, pvYearResolved.reason);
setDiagSource(state.diag, "pv_energy_total_source", pvTotalResolved.source, pvTotalResolved.reason);

setDiagSource(state.diag, "load_energy_day_source", loadDayResolved.source, loadDayResolved.reason);
setDiagSource(state.diag, "load_energy_month_source", loadMonthResolved.source, loadMonthResolved.reason);
setDiagSource(state.diag, "load_energy_year_source", loadYearResolved.source, loadYearResolved.reason);
setDiagSource(state.diag, "load_energy_total_source", loadTotalResolved.source, loadTotalResolved.reason);

setDiagSource(state.diag, "grid_energy_day_source", "calculated", "policy_always_calculated");
setDiagSource(state.diag, "grid_energy_month_source", "calculated", "policy_always_calculated");
setDiagSource(state.diag, "grid_energy_year_source", "calculated", "policy_always_calculated");
setDiagSource(state.diag, "grid_energy_total_source", "calculated", "policy_always_calculated");

setDiagSource(state.diag, "battery_charge_day_source", "calculated", withinMidnightGuard && batteryChargeGuarded ? "midnight_guard" : "policy_always_calculated");
setDiagSource(state.diag, "battery_charge_month_source", "calculated", "policy_always_calculated");
setDiagSource(state.diag, "battery_charge_year_source", "calculated", "policy_always_calculated");
setDiagSource(state.diag, "battery_charge_total_source", "calculated", "policy_always_calculated");

setDiagSource(state.diag, "battery_discharge_day_source", "calculated", withinMidnightGuard && batteryDischargeGuarded ? "midnight_guard" : "policy_always_calculated");
setDiagSource(state.diag, "battery_discharge_month_source", "calculated", "policy_always_calculated");
setDiagSource(state.diag, "battery_discharge_year_source", "calculated", "policy_always_calculated");
setDiagSource(state.diag, "battery_discharge_total_source", "calculated", "policy_always_calculated");

state.diag.energy_dt_hours = round2(dtHours);
state.diag.energy_store_restore_stats = statsRestoreSource;
state.diag.energy_store_write_mode = "default_plus_persistent_plus_config_file";
state.diag.energy_file_store_write_ok = fileWriteOk;
state.diag.energy_file_store_key = fileInvKey;
state.diag.energy_anti_reset_active = justRestored && noNewEnergyIntegration && !dayChanged;

state.diag.energy_midnight_guard_active = withinMidnightGuard;
state.diag.energy_battery_charge_guarded = batteryChargeGuarded;
state.diag.energy_battery_discharge_guarded = batteryDischargeGuarded;

state._day_key = dayKey;
state._month_key = monthKey;
state._year_key = yearKey;
state._premium_extended_energy = premiumActive;

msg.payload = state;
return msg;

// =====================================
// DAILY ENERGY CALC / FALLBACK
// VERSION ROBUSTE PERSISTENCE + FILE STORE + ANTI RESET POST UPDATE
// =====================================

if (!msg || !msg.payload || typeof msg.payload !== "object") return msg;

const inv = Number(msg.inverterNum ?? msg.payload.inverter ?? 1) || 1;
const state = { ...msg.payload };

const premiumActive = global.get("premium.active") === true;
const fs = global.get("fs");
const path = global.get("path");

const ENERGY_STORE_FILE = "/config/smart_voltronic_energy_store.json";
const FILE_STORE_VERSION = 1;
const fileInvKey = `inverter_${inv}`;

function toNum(v) {
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
}

function round2(v) {
  const n = Number(v);
  return Number.isFinite(n) ? Math.round((n + Number.EPSILON) * 100) / 100 : 0;
}

function clampNonNegative(v, fb = 0) {
  const n = Number(v);
  if (!Number.isFinite(n)) return fb;
  return Math.max(0, round2(n));
}

function ensureObj(v, fb = {}) {
  return v && typeof v === "object" && !Array.isArray(v) ? v : fb;
}

function pickFirstNumber(...vals) {
  for (const v of vals) {
    const n = Number(v);
    if (Number.isFinite(n)) return n;
  }
  return null;
}

function getSafeTimezone() {
  let tz = (global.get("addon_timezone") || "UTC").toString().trim();
  if (!tz) tz = "UTC";

  try {
    new Intl.DateTimeFormat("en-CA", { timeZone: tz }).format(new Date());
  } catch (e) {
    tz = "UTC";
  }

  return tz;
}

function localDateParts(d = new Date()) {
  const tz = getSafeTimezone();

  const parts = new Intl.DateTimeFormat("en-CA", {
    timeZone: tz,
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hour12: false
  }).formatToParts(d);

  const get = (t) => parts.find(p => p.type === t)?.value;

  const year = get("year");
  const month = get("month");
  const day = get("day");
  const hour = Number(get("hour") || 0);
  const minute = Number(get("minute") || 0);

  return {
    year,
    month,
    day,
    hour,
    minute,
    minutesSinceMidnight: hour * 60 + minute,
    dayKey: `${year}${month}${day}`,
    monthKey: `${year}${month}`,
    yearKey: `${year}`
  };
}

function safeGet(key, storeName) {
  try {
    return flow.get(key, storeName);
  } catch (e) {
    return undefined;
  }
}

function safeSet(key, value, storeName) {
  try {
    flow.set(key, value, storeName);
    return true;
  } catch (e) {
    return false;
  }
}

function getRobust(key, fallback = null) {
  const fromPersistent = safeGet(key, "persistent");
  if (fromPersistent !== undefined && fromPersistent !== null) return fromPersistent;

  const fromDefault = safeGet(key);
  if (fromDefault !== undefined && fromDefault !== null) return fromDefault;

  return fallback;
}

function setRobust(key, value) {
  try {
    flow.set(key, value);
  } catch (e) { }

  safeSet(key, value, "persistent");
}

function readEnergyFileStore() {
  if (!fs) return null;

  try {
    if (!fs.existsSync(ENERGY_STORE_FILE)) return null;

    const raw = fs.readFileSync(ENERGY_STORE_FILE, "utf8");
    const data = JSON.parse(raw);

    if (!data || typeof data !== "object") return null;
    if (!data.inverters || typeof data.inverters !== "object") return null;

    return data;
  } catch (e) {
    node.warn("Energy file store read error: " + e.message);
    return null;
  }
}

function restoreStatsFromFile(invKey) {
  const data = readEnergyFileStore();
  const invData = data?.inverters?.[invKey];

  if (!invData || typeof invData !== "object") return null;
  if (!invData.stats || typeof invData.stats !== "object") return null;

  return invData.stats;
}

function restoreLastValuesFromFile(invKey) {
  const data = readEnergyFileStore();
  const invData = data?.inverters?.[invKey];

  if (!invData || typeof invData !== "object") return null;
  if (!invData.last_values || typeof invData.last_values !== "object") return null;

  return invData.last_values;
}

function writeEnergyFileStoreForInv(invKey, patch) {
  if (!fs) return false;

  try {
    let data = readEnergyFileStore();

    if (!data || typeof data !== "object") {
      data = {
        version: FILE_STORE_VERSION,
        updated_at: null,
        inverters: {}
      };
    }

    if (!data.inverters || typeof data.inverters !== "object") {
      data.inverters = {};
    }

    const previous = ensureObj(data.inverters[invKey], {});

    data.version = FILE_STORE_VERSION;
    data.updated_at = new Date().toISOString();

    data.inverters[invKey] = {
      ...previous,
      ...patch,
      updated_at: new Date().toISOString()
    };

    if (path && typeof path.dirname === "function") {
      fs.mkdirSync(path.dirname(ENERGY_STORE_FILE), { recursive: true });
    } else {
      fs.mkdirSync("/config", { recursive: true });
    }

    fs.writeFileSync(ENERGY_STORE_FILE, JSON.stringify(data, null, 2), "utf8");
    return true;
  } catch (e) {
    node.warn("Energy file store write error: " + e.message);
    return false;
  }
}

function setDiagSource(diag, key, source, reason = "") {
  diag[key] = source;
  if (reason) diag[`${key}_reason`] = reason;
}

const nowKeys = localDateParts(new Date());
const dayKey = nowKeys.dayKey;
const monthKey = nowKeys.monthKey;
const yearKey = nowKeys.yearKey;
const tsNow = Date.now();

state.diag = ensureObj(state.diag, {});
state.diag.energy_logic_version = "source_lock_v6_file_store_anti_reset";
state.diag.energy_timezone = getSafeTimezone();
state.diag.energy_file_store = ENERGY_STORE_FILE;

const statsKey = `inv${inv}_energy_stats`;

let statsRestoreSource = "new";

let stats = restoreStatsFromFile(fileInvKey);
if (stats) {
  statsRestoreSource = "file_config";
} else {
  stats = getRobust(statsKey, null);
  if (stats) statsRestoreSource = "node_red_context";
}

if (!stats || typeof stats !== "object") {
  stats = {
    lastTs: tsNow,
    lastDayKey: dayKey,
    lastMonthKey: monthKey,
    lastYearKey: yearKey,
    lastDayResetTs: tsNow,
    day: { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 },
    month: { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 },
    year: { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 },
    total: { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 }
  };
}

stats.day = ensureObj(stats.day, { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 });
stats.month = ensureObj(stats.month, { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 });
stats.year = ensureObj(stats.year, { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 });
stats.total = ensureObj(stats.total, { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 });

for (const bucket of ["day", "month", "year", "total"]) {
  stats[bucket].pv = Number(stats[bucket].pv) || 0;
  stats[bucket].load = Number(stats[bucket].load) || 0;
  stats[bucket].grid = Number(stats[bucket].grid) || 0;
  stats[bucket].battCharge = Number(stats[bucket].battCharge) || 0;
  stats[bucket].battDischarge = Number(stats[bucket].battDischarge) || 0;
}

if (!Number.isFinite(Number(stats.lastTs))) stats.lastTs = tsNow;
if (!stats.lastDayKey) stats.lastDayKey = dayKey;
if (!stats.lastMonthKey) stats.lastMonthKey = monthKey;
if (!stats.lastYearKey) stats.lastYearKey = yearKey;
if (!Number.isFinite(Number(stats.lastDayResetTs))) stats.lastDayResetTs = tsNow;

let dtHours = (tsNow - Number(stats.lastTs || tsNow)) / 3600000;
if (!Number.isFinite(dtHours) || dtHours < 0) dtHours = 0;
if (dtHours > 1) dtHours = 0;

const dayChanged = stats.lastDayKey !== dayKey;
const monthChanged = stats.lastMonthKey !== monthKey;
const yearChanged = stats.lastYearKey !== yearKey;

if (dayChanged) {
  stats.day = { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 };
  stats.lastDayResetTs = tsNow;
}

if (monthChanged) {
  stats.month = { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 };
}

if (yearChanged) {
  stats.year = { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 };
}

const pvPower =
  pickFirstNumber(
    state.pv_total_power,
    state.pv_power,
    state.solar_power,
    state.pv1_power
  ) || 0;

const loadPower =
  pickFirstNumber(
    state.ac_output_active_power,
    state.load_power,
    state.output_load_power,
    state.ac_output_power
  ) || 0;

const batteryPower =
  pickFirstNumber(
    state.battery_power,
    state.global_battery_power
  ) || 0;

let gridPower =
  pickFirstNumber(
    state.grid_power,
    state.utility_power
  );

if (!Number.isFinite(gridPower)) {
  const battContributionToLoad = batteryPower < 0 ? Math.abs(batteryPower) : 0;
  const battChargeFromSystem = batteryPower > 0 ? batteryPower : 0;
  gridPower = Math.max(0, loadPower - pvPower - battContributionToLoad + battChargeFromSystem);
}

gridPower = Math.max(0, gridPower);

const MIDNIGHT_GUARD_MS = 5 * 60 * 1000;
const BATTERY_IDLE_W = 25;
const BATTERY_STRONG_ACTIVITY_W = 150;

const msSinceDayReset = tsNow - Number(stats.lastDayResetTs || tsNow);
const withinMidnightGuard = msSinceDayReset >= 0 && msSinceDayReset < MIDNIGHT_GUARD_MS;

let batteryChargeGuarded = false;
let batteryDischargeGuarded = false;

const pvInc = Math.max(0, pvPower) * dtHours / 1000;
const loadInc = Math.max(0, loadPower) * dtHours / 1000;
const gridInc = Math.max(0, gridPower) * dtHours / 1000;

const battChargePower = batteryPower > 0 ? batteryPower : 0;
const battDischargePower = batteryPower < 0 ? Math.abs(batteryPower) : 0;

let battChargeInc = Math.max(0, battChargePower) * dtHours / 1000;
let battDischargeInc = Math.max(0, battDischargePower) * dtHours / 1000;

if (withinMidnightGuard) {
  if (battChargePower > 0 && battChargePower < BATTERY_STRONG_ACTIVITY_W) {
    battChargeInc = 0;
    batteryChargeGuarded = true;
  }

  if (battDischargePower > 0 && battDischargePower < BATTERY_STRONG_ACTIVITY_W) {
    battDischargeInc = 0;
    batteryDischargeGuarded = true;
  }

  if (Math.abs(batteryPower) <= BATTERY_IDLE_W) {
    battChargeInc = 0;
    battDischargeInc = 0;
    batteryChargeGuarded = true;
    batteryDischargeGuarded = true;
  }
}

if (dtHours > 0) {
  stats.day.pv += pvInc;
  stats.day.load += loadInc;
  stats.day.grid += gridInc;
  stats.day.battCharge += battChargeInc;
  stats.day.battDischarge += battDischargeInc;

  stats.month.pv += pvInc;
  stats.month.load += loadInc;
  stats.month.grid += gridInc;
  stats.month.battCharge += battChargeInc;
  stats.month.battDischarge += battDischargeInc;

  stats.year.pv += pvInc;
  stats.year.load += loadInc;
  stats.year.grid += gridInc;
  stats.year.battCharge += battChargeInc;
  stats.year.battDischarge += battDischargeInc;

  stats.total.pv += pvInc;
  stats.total.load += loadInc;
  stats.total.grid += gridInc;
  stats.total.battCharge += battChargeInc;
  stats.total.battDischarge += battDischargeInc;
}

let calcPvDay = clampNonNegative(stats.day.pv);
let calcPvMonth = clampNonNegative(stats.month.pv);
let calcPvYear = clampNonNegative(stats.year.pv);
let calcPvTotal = clampNonNegative(stats.total.pv);

let calcLoadDay = clampNonNegative(stats.day.load);
let calcLoadMonth = clampNonNegative(stats.month.load);
let calcLoadYear = clampNonNegative(stats.year.load);
let calcLoadTotal = clampNonNegative(stats.total.load);

let calcGridDay = clampNonNegative(stats.day.grid);
let calcGridMonth = clampNonNegative(stats.month.grid);
let calcGridYear = clampNonNegative(stats.year.grid);
let calcGridTotal = clampNonNegative(stats.total.grid);

let calcBattChargeDay = clampNonNegative(stats.day.battCharge);
let calcBattChargeMonth = clampNonNegative(stats.month.battCharge);
let calcBattChargeYear = clampNonNegative(stats.year.battCharge);
let calcBattChargeTotal = clampNonNegative(stats.total.battCharge);

let calcBattDischargeDay = clampNonNegative(stats.day.battDischarge);
let calcBattDischargeMonth = clampNonNegative(stats.month.battDischarge);
let calcBattDischargeYear = clampNonNegative(stats.year.battDischarge);
let calcBattDischargeTotal = clampNonNegative(stats.total.battDischarge);

const lastValues = restoreLastValuesFromFile(fileInvKey) || {};

const justRestored =
  statsRestoreSource === "file_config" ||
  statsRestoreSource === "node_red_context";

const noNewEnergyIntegration = dtHours === 0;

function protectRestoredValue(currentValue, statsValue, lastFileValue) {
  const current = Number(currentValue) || 0;
  const fromStats = Number(statsValue) || 0;
  const fromFile = Number(lastFileValue) || 0;

  if (current > 0) return round2(current);
  if (fromStats > 0) return round2(fromStats);
  if (fromFile > 0) return round2(fromFile);

  return 0;
}

if (justRestored && noNewEnergyIntegration && !dayChanged) {
  calcPvDay = protectRestoredValue(calcPvDay, stats.day.pv, lastValues.pv_energy_day_kwh);
  calcLoadDay = protectRestoredValue(calcLoadDay, stats.day.load, lastValues.load_energy_day_kwh);
  calcGridDay = protectRestoredValue(calcGridDay, stats.day.grid, lastValues.grid_energy_day_kwh);
  calcBattChargeDay = protectRestoredValue(calcBattChargeDay, stats.day.battCharge, lastValues.battery_charge_day_kwh);
  calcBattDischargeDay = protectRestoredValue(calcBattDischargeDay, stats.day.battDischarge, lastValues.battery_discharge_day_kwh);
}

const inverterPvDayRaw = toNum(state.pv_energy_day_kwh);
const inverterPvMonthRaw = toNum(state.pv_energy_month_kwh);
const inverterPvYearRaw = toNum(state.pv_energy_year_kwh);
const inverterPvTotalRaw = toNum(state.pv_energy_total_kwh);

const inverterLoadDayRaw = toNum(state.load_energy_day_kwh);
const inverterLoadMonthRaw = toNum(state.load_energy_month_kwh);
const inverterLoadYearRaw = toNum(state.load_energy_year_kwh);
const inverterLoadTotalRaw = toNum(state.load_energy_total_kwh);

function nativeOk(v) {
  const n = Number(v);
  return Number.isFinite(n) && n >= 0;
}

function resolveNativeOrCalc(nativeVal, calcVal, metric, currentPower = 0) {
  const n = Number(nativeVal);
  const c = Number(calcVal) || 0;

  if (nativeOk(n)) {
    if (!(n === 0 && c > 0 && currentPower > 30)) {
      return {
        value: clampNonNegative(n),
        source: "inverter",
        reason: "native_valid"
      };
    }
  }

  return {
    value: clampNonNegative(c),
    source: "calculated",
    reason: "native_missing_or_invalid"
  };
}

const pvDayResolved = resolveNativeOrCalc(inverterPvDayRaw, calcPvDay, "pv_day", pvPower);
const pvMonthResolved = resolveNativeOrCalc(inverterPvMonthRaw, calcPvMonth, "pv_month", pvPower);
const pvYearResolved = resolveNativeOrCalc(inverterPvYearRaw, calcPvYear, "pv_year", pvPower);
const pvTotalResolved = resolveNativeOrCalc(inverterPvTotalRaw, calcPvTotal, "pv_total", pvPower);

const loadDayResolved = resolveNativeOrCalc(inverterLoadDayRaw, calcLoadDay, "load_day", loadPower);
const loadMonthResolved = resolveNativeOrCalc(inverterLoadMonthRaw, calcLoadMonth, "load_month", loadPower);
const loadYearResolved = resolveNativeOrCalc(inverterLoadYearRaw, calcLoadYear, "load_year", loadPower);
const loadTotalResolved = resolveNativeOrCalc(inverterLoadTotalRaw, calcLoadTotal, "load_total", loadPower);

state.pv_energy_day_kwh = pvDayResolved.value;
state.pv_energy_month_kwh = pvMonthResolved.value;
state.pv_energy_year_kwh = pvYearResolved.value;
state.pv_energy_total_kwh = pvTotalResolved.value;

state.load_energy_day_kwh = loadDayResolved.value;
state.load_energy_month_kwh = loadMonthResolved.value;
state.load_energy_year_kwh = loadYearResolved.value;
state.load_energy_total_kwh = loadTotalResolved.value;

state.grid_energy_day_kwh = calcGridDay;
state.grid_energy_month_kwh = calcGridMonth;
state.grid_energy_year_kwh = calcGridYear;
state.grid_energy_total_kwh = calcGridTotal;

state.battery_charge_day_kwh = calcBattChargeDay;
state.battery_charge_month_kwh = calcBattChargeMonth;
state.battery_charge_year_kwh = calcBattChargeYear;
state.battery_charge_total_kwh = calcBattChargeTotal;

state.battery_discharge_day_kwh = calcBattDischargeDay;
state.battery_discharge_month_kwh = calcBattDischargeMonth;
state.battery_discharge_year_kwh = calcBattDischargeYear;
state.battery_discharge_total_kwh = calcBattDischargeTotal;

stats.lastTs = tsNow;
stats.lastDayKey = dayKey;
stats.lastMonthKey = monthKey;
stats.lastYearKey = yearKey;

setRobust(statsKey, stats);

const fileWriteOk = writeEnergyFileStoreForInv(fileInvKey, {
  stats,
  last_values: {
    pv_energy_day_kwh: state.pv_energy_day_kwh,
    pv_energy_month_kwh: state.pv_energy_month_kwh,
    pv_energy_year_kwh: state.pv_energy_year_kwh,
    pv_energy_total_kwh: state.pv_energy_total_kwh,

    load_energy_day_kwh: state.load_energy_day_kwh,
    load_energy_month_kwh: state.load_energy_month_kwh,
    load_energy_year_kwh: state.load_energy_year_kwh,
    load_energy_total_kwh: state.load_energy_total_kwh,

    grid_energy_day_kwh: state.grid_energy_day_kwh,
    grid_energy_month_kwh: state.grid_energy_month_kwh,
    grid_energy_year_kwh: state.grid_energy_year_kwh,
    grid_energy_total_kwh: state.grid_energy_total_kwh,

    battery_charge_day_kwh: state.battery_charge_day_kwh,
    battery_charge_month_kwh: state.battery_charge_month_kwh,
    battery_charge_year_kwh: state.battery_charge_year_kwh,
    battery_charge_total_kwh: state.battery_charge_total_kwh,

    battery_discharge_day_kwh: state.battery_discharge_day_kwh,
    battery_discharge_month_kwh: state.battery_discharge_month_kwh,
    battery_discharge_year_kwh: state.battery_discharge_year_kwh,
    battery_discharge_total_kwh: state.battery_discharge_total_kwh
  }
});

setDiagSource(state.diag, "pv_energy_day_source", pvDayResolved.source, pvDayResolved.reason);
setDiagSource(state.diag, "pv_energy_month_source", pvMonthResolved.source, pvMonthResolved.reason);
setDiagSource(state.diag, "pv_energy_year_source", pvYearResolved.source, pvYearResolved.reason);
setDiagSource(state.diag, "pv_energy_total_source", pvTotalResolved.source, pvTotalResolved.reason);

setDiagSource(state.diag, "load_energy_day_source", loadDayResolved.source, loadDayResolved.reason);
setDiagSource(state.diag, "load_energy_month_source", loadMonthResolved.source, loadMonthResolved.reason);
setDiagSource(state.diag, "load_energy_year_source", loadYearResolved.source, loadYearResolved.reason);
setDiagSource(state.diag, "load_energy_total_source", loadTotalResolved.source, loadTotalResolved.reason);

setDiagSource(state.diag, "grid_energy_day_source", "calculated", "policy_always_calculated");
setDiagSource(state.diag, "grid_energy_month_source", "calculated", "policy_always_calculated");
setDiagSource(state.diag, "grid_energy_year_source", "calculated", "policy_always_calculated");
setDiagSource(state.diag, "grid_energy_total_source", "calculated", "policy_always_calculated");

setDiagSource(state.diag, "battery_charge_day_source", "calculated", withinMidnightGuard && batteryChargeGuarded ? "midnight_guard" : "policy_always_calculated");
setDiagSource(state.diag, "battery_charge_month_source", "calculated", "policy_always_calculated");
setDiagSource(state.diag, "battery_charge_year_source", "calculated", "policy_always_calculated");
setDiagSource(state.diag, "battery_charge_total_source", "calculated", "policy_always_calculated");

setDiagSource(state.diag, "battery_discharge_day_source", "calculated", withinMidnightGuard && batteryDischargeGuarded ? "midnight_guard" : "policy_always_calculated");
setDiagSource(state.diag, "battery_discharge_month_source", "calculated", "policy_always_calculated");
setDiagSource(state.diag, "battery_discharge_year_source", "calculated", "policy_always_calculated");
setDiagSource(state.diag, "battery_discharge_total_source", "calculated", "policy_always_calculated");

state.diag.energy_dt_hours = round2(dtHours);
state.diag.energy_store_restore_stats = statsRestoreSource;
state.diag.energy_store_write_mode = "default_plus_persistent_plus_config_file";
state.diag.energy_file_store_write_ok = fileWriteOk;
state.diag.energy_file_store_key = fileInvKey;
state.diag.energy_anti_reset_active = justRestored && noNewEnergyIntegration && !dayChanged;

state.diag.energy_midnight_guard_active = withinMidnightGuard;
state.diag.energy_battery_charge_guarded = batteryChargeGuarded;
state.diag.energy_battery_discharge_guarded = batteryDischargeGuarded;

state._day_key = dayKey;
state._month_key = monthKey;
state._year_key = yearKey;
state._premium_extended_energy = premiumActive;

msg.payload = state;
return msg;

// =====================================
// DAILY ENERGY CALC / FALLBACK
// VERSION ROBUSTE PERSISTENCE + FILE STORE + ANTI RESET POST UPDATE
// =====================================

if (!msg || !msg.payload || typeof msg.payload !== "object") return msg;

const inv = Number(msg.inverterNum ?? msg.payload.inverter ?? 1) || 1;
const state = { ...msg.payload };

const premiumActive = global.get("premium.active") === true;
const fs = global.get("fs");
const path = global.get("path");

const ENERGY_STORE_FILE = "/config/smart_voltronic_energy_store.json";
const FILE_STORE_VERSION = 1;
const fileInvKey = `inverter_${inv}`;

function toNum(v) {
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
}

function round2(v) {
  const n = Number(v);
  return Number.isFinite(n) ? Math.round((n + Number.EPSILON) * 100) / 100 : 0;
}

function clampNonNegative(v, fb = 0) {
  const n = Number(v);
  if (!Number.isFinite(n)) return fb;
  return Math.max(0, round2(n));
}

function ensureObj(v, fb = {}) {
  return v && typeof v === "object" && !Array.isArray(v) ? v : fb;
}

function pickFirstNumber(...vals) {
  for (const v of vals) {
    const n = Number(v);
    if (Number.isFinite(n)) return n;
  }
  return null;
}

function getSafeTimezone() {
  let tz = (global.get("addon_timezone") || "UTC").toString().trim();
  if (!tz) tz = "UTC";

  try {
    new Intl.DateTimeFormat("en-CA", { timeZone: tz }).format(new Date());
  } catch (e) {
    tz = "UTC";
  }

  return tz;
}

function localDateParts(d = new Date()) {
  const tz = getSafeTimezone();

  const parts = new Intl.DateTimeFormat("en-CA", {
    timeZone: tz,
    year: "numeric",
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
    second: "2-digit",
    hour12: false
  }).formatToParts(d);

  const get = (t) => parts.find(p => p.type === t)?.value;

  const year = get("year");
  const month = get("month");
  const day = get("day");
  const hour = Number(get("hour") || 0);
  const minute = Number(get("minute") || 0);

  return {
    year,
    month,
    day,
    hour,
    minute,
    minutesSinceMidnight: hour * 60 + minute,
    dayKey: `${year}${month}${day}`,
    monthKey: `${year}${month}`,
    yearKey: `${year}`
  };
}

function safeGet(key, storeName) {
  try {
    return flow.get(key, storeName);
  } catch (e) {
    return undefined;
  }
}

function safeSet(key, value, storeName) {
  try {
    flow.set(key, value, storeName);
    return true;
  } catch (e) {
    return false;
  }
}

function getRobust(key, fallback = null) {
  const fromPersistent = safeGet(key, "persistent");
  if (fromPersistent !== undefined && fromPersistent !== null) return fromPersistent;

  const fromDefault = safeGet(key);
  if (fromDefault !== undefined && fromDefault !== null) return fromDefault;

  return fallback;
}

function setRobust(key, value) {
  try {
    flow.set(key, value);
  } catch (e) { }

  safeSet(key, value, "persistent");
}

function readEnergyFileStore() {
  if (!fs) return null;

  try {
    if (!fs.existsSync(ENERGY_STORE_FILE)) return null;

    const raw = fs.readFileSync(ENERGY_STORE_FILE, "utf8");
    const data = JSON.parse(raw);

    if (!data || typeof data !== "object") return null;
    if (!data.inverters || typeof data.inverters !== "object") return null;

    return data;
  } catch (e) {
    node.warn("Energy file store read error: " + e.message);
    return null;
  }
}

function restoreStatsFromFile(invKey) {
  const data = readEnergyFileStore();
  const invData = data?.inverters?.[invKey];

  if (!invData || typeof invData !== "object") return null;
  if (!invData.stats || typeof invData.stats !== "object") return null;

  return invData.stats;
}

function restoreLastValuesFromFile(invKey) {
  const data = readEnergyFileStore();
  const invData = data?.inverters?.[invKey];

  if (!invData || typeof invData !== "object") return null;
  if (!invData.last_values || typeof invData.last_values !== "object") return null;

  return invData.last_values;
}

function writeEnergyFileStoreForInv(invKey, patch) {
  if (!fs) return false;

  try {
    let data = readEnergyFileStore();

    if (!data || typeof data !== "object") {
      data = {
        version: FILE_STORE_VERSION,
        updated_at: null,
        inverters: {}
      };
    }

    if (!data.inverters || typeof data.inverters !== "object") {
      data.inverters = {};
    }

    const previous = ensureObj(data.inverters[invKey], {});

    data.version = FILE_STORE_VERSION;
    data.updated_at = new Date().toISOString();

    data.inverters[invKey] = {
      ...previous,
      ...patch,
      updated_at: new Date().toISOString()
    };

    if (path && typeof path.dirname === "function") {
      fs.mkdirSync(path.dirname(ENERGY_STORE_FILE), { recursive: true });
    } else {
      fs.mkdirSync("/config", { recursive: true });
    }

    fs.writeFileSync(ENERGY_STORE_FILE, JSON.stringify(data, null, 2), "utf8");
    return true;
  } catch (e) {
    node.warn("Energy file store write error: " + e.message);
    return false;
  }
}

function setDiagSource(diag, key, source, reason = "") {
  diag[key] = source;
  if (reason) diag[`${key}_reason`] = reason;
}

const nowKeys = localDateParts(new Date());
const dayKey = nowKeys.dayKey;
const monthKey = nowKeys.monthKey;
const yearKey = nowKeys.yearKey;
const tsNow = Date.now();

state.diag = ensureObj(state.diag, {});
state.diag.energy_logic_version = "source_lock_v6_file_store_anti_reset";
state.diag.energy_timezone = getSafeTimezone();
state.diag.energy_file_store = ENERGY_STORE_FILE;

const statsKey = `inv${inv}_energy_stats`;

let statsRestoreSource = "new";

let stats = restoreStatsFromFile(fileInvKey);
if (stats) {
  statsRestoreSource = "file_config";
} else {
  stats = getRobust(statsKey, null);
  if (stats) statsRestoreSource = "node_red_context";
}

if (!stats || typeof stats !== "object") {
  stats = {
    lastTs: tsNow,
    lastDayKey: dayKey,
    lastMonthKey: monthKey,
    lastYearKey: yearKey,
    lastDayResetTs: tsNow,
    day: { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 },
    month: { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 },
    year: { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 },
    total: { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 }
  };
}

stats.day = ensureObj(stats.day, { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 });
stats.month = ensureObj(stats.month, { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 });
stats.year = ensureObj(stats.year, { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 });
stats.total = ensureObj(stats.total, { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 });

for (const bucket of ["day", "month", "year", "total"]) {
  stats[bucket].pv = Number(stats[bucket].pv) || 0;
  stats[bucket].load = Number(stats[bucket].load) || 0;
  stats[bucket].grid = Number(stats[bucket].grid) || 0;
  stats[bucket].battCharge = Number(stats[bucket].battCharge) || 0;
  stats[bucket].battDischarge = Number(stats[bucket].battDischarge) || 0;
}

if (!Number.isFinite(Number(stats.lastTs))) stats.lastTs = tsNow;
if (!stats.lastDayKey) stats.lastDayKey = dayKey;
if (!stats.lastMonthKey) stats.lastMonthKey = monthKey;
if (!stats.lastYearKey) stats.lastYearKey = yearKey;
if (!Number.isFinite(Number(stats.lastDayResetTs))) stats.lastDayResetTs = tsNow;

let dtHours = (tsNow - Number(stats.lastTs || tsNow)) / 3600000;
if (!Number.isFinite(dtHours) || dtHours < 0) dtHours = 0;
if (dtHours > 1) dtHours = 0;

const dayChanged = stats.lastDayKey !== dayKey;
const monthChanged = stats.lastMonthKey !== monthKey;
const yearChanged = stats.lastYearKey !== yearKey;

if (dayChanged) {
  stats.day = { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 };
  stats.lastDayResetTs = tsNow;
}

if (monthChanged) {
  stats.month = { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 };
}

if (yearChanged) {
  stats.year = { pv: 0, load: 0, grid: 0, battCharge: 0, battDischarge: 0 };
}

const pvPower =
  pickFirstNumber(
    state.pv_total_power,
    state.pv_power,
    state.solar_power,
    state.pv1_power
  ) || 0;

const loadPower =
  pickFirstNumber(
    state.ac_output_active_power,
    state.load_power,
    state.output_load_power,
    state.ac_output_power
  ) || 0;

const batteryPower =
  pickFirstNumber(
    state.battery_power,
    state.global_battery_power
  ) || 0;

let gridPower =
  pickFirstNumber(
    state.grid_power,
    state.utility_power
  );

if (!Number.isFinite(gridPower)) {
  const battContributionToLoad = batteryPower < 0 ? Math.abs(batteryPower) : 0;
  const battChargeFromSystem = batteryPower > 0 ? batteryPower : 0;
  gridPower = Math.max(0, loadPower - pvPower - battContributionToLoad + battChargeFromSystem);
}

gridPower = Math.max(0, gridPower);

const MIDNIGHT_GUARD_MS = 5 * 60 * 1000;
const BATTERY_IDLE_W = 25;
const BATTERY_STRONG_ACTIVITY_W = 150;

const msSinceDayReset = tsNow - Number(stats.lastDayResetTs || tsNow);
const withinMidnightGuard = msSinceDayReset >= 0 && msSinceDayReset < MIDNIGHT_GUARD_MS;

let batteryChargeGuarded = false;
let batteryDischargeGuarded = false;

const pvInc = Math.max(0, pvPower) * dtHours / 1000;
const loadInc = Math.max(0, loadPower) * dtHours / 1000;
const gridInc = Math.max(0, gridPower) * dtHours / 1000;

const battChargePower = batteryPower > 0 ? batteryPower : 0;
const battDischargePower = batteryPower < 0 ? Math.abs(batteryPower) : 0;

let battChargeInc = Math.max(0, battChargePower) * dtHours / 1000;
let battDischargeInc = Math.max(0, battDischargePower) * dtHours / 1000;

if (withinMidnightGuard) {
  if (battChargePower > 0 && battChargePower < BATTERY_STRONG_ACTIVITY_W) {
    battChargeInc = 0;
    batteryChargeGuarded = true;
  }

  if (battDischargePower > 0 && battDischargePower < BATTERY_STRONG_ACTIVITY_W) {
    battDischargeInc = 0;
    batteryDischargeGuarded = true;
  }

  if (Math.abs(batteryPower) <= BATTERY_IDLE_W) {
    battChargeInc = 0;
    battDischargeInc = 0;
    batteryChargeGuarded = true;
    batteryDischargeGuarded = true;
  }
}

if (dtHours > 0) {
  stats.day.pv += pvInc;
  stats.day.load += loadInc;
  stats.day.grid += gridInc;
  stats.day.battCharge += battChargeInc;
  stats.day.battDischarge += battDischargeInc;

  stats.month.pv += pvInc;
  stats.month.load += loadInc;
  stats.month.grid += gridInc;
  stats.month.battCharge += battChargeInc;
  stats.month.battDischarge += battDischargeInc;

  stats.year.pv += pvInc;
  stats.year.load += loadInc;
  stats.year.grid += gridInc;
  stats.year.battCharge += battChargeInc;
  stats.year.battDischarge += battDischargeInc;

  stats.total.pv += pvInc;
  stats.total.load += loadInc;
  stats.total.grid += gridInc;
  stats.total.battCharge += battChargeInc;
  stats.total.battDischarge += battDischargeInc;
}

let calcPvDay = clampNonNegative(stats.day.pv);
let calcPvMonth = clampNonNegative(stats.month.pv);
let calcPvYear = clampNonNegative(stats.year.pv);
let calcPvTotal = clampNonNegative(stats.total.pv);

let calcLoadDay = clampNonNegative(stats.day.load);
let calcLoadMonth = clampNonNegative(stats.month.load);
let calcLoadYear = clampNonNegative(stats.year.load);
let calcLoadTotal = clampNonNegative(stats.total.load);

let calcGridDay = clampNonNegative(stats.day.grid);
let calcGridMonth = clampNonNegative(stats.month.grid);
let calcGridYear = clampNonNegative(stats.year.grid);
let calcGridTotal = clampNonNegative(stats.total.grid);

let calcBattChargeDay = clampNonNegative(stats.day.battCharge);
let calcBattChargeMonth = clampNonNegative(stats.month.battCharge);
let calcBattChargeYear = clampNonNegative(stats.year.battCharge);
let calcBattChargeTotal = clampNonNegative(stats.total.battCharge);

let calcBattDischargeDay = clampNonNegative(stats.day.battDischarge);
let calcBattDischargeMonth = clampNonNegative(stats.month.battDischarge);
let calcBattDischargeYear = clampNonNegative(stats.year.battDischarge);
let calcBattDischargeTotal = clampNonNegative(stats.total.battDischarge);

const lastValues = restoreLastValuesFromFile(fileInvKey) || {};

const justRestored =
  statsRestoreSource === "file_config" ||
  statsRestoreSource === "node_red_context";

const noNewEnergyIntegration = dtHours === 0;

function protectRestoredValue(currentValue, statsValue, lastFileValue) {
  const current = Number(currentValue) || 0;
  const fromStats = Number(statsValue) || 0;
  const fromFile = Number(lastFileValue) || 0;

  if (current > 0) return round2(current);
  if (fromStats > 0) return round2(fromStats);
  if (fromFile > 0) return round2(fromFile);

  return 0;
}

if (justRestored && noNewEnergyIntegration && !dayChanged) {
  calcPvDay = protectRestoredValue(calcPvDay, stats.day.pv, lastValues.pv_energy_day_kwh);
  calcLoadDay = protectRestoredValue(calcLoadDay, stats.day.load, lastValues.load_energy_day_kwh);
  calcGridDay = protectRestoredValue(calcGridDay, stats.day.grid, lastValues.grid_energy_day_kwh);
  calcBattChargeDay = protectRestoredValue(calcBattChargeDay, stats.day.battCharge, lastValues.battery_charge_day_kwh);
  calcBattDischargeDay = protectRestoredValue(calcBattDischargeDay, stats.day.battDischarge, lastValues.battery_discharge_day_kwh);
}

const inverterPvDayRaw = toNum(state.pv_energy_day_kwh);
const inverterPvMonthRaw = toNum(state.pv_energy_month_kwh);
const inverterPvYearRaw = toNum(state.pv_energy_year_kwh);
const inverterPvTotalRaw = toNum(state.pv_energy_total_kwh);

const inverterLoadDayRaw = toNum(state.load_energy_day_kwh);
const inverterLoadMonthRaw = toNum(state.load_energy_month_kwh);
const inverterLoadYearRaw = toNum(state.load_energy_year_kwh);
const inverterLoadTotalRaw = toNum(state.load_energy_total_kwh);

function nativeOk(v) {
  const n = Number(v);
  return Number.isFinite(n) && n >= 0;
}

function resolveNativeOrCalc(nativeVal, calcVal, metric, currentPower = 0) {
  const n = Number(nativeVal);
  const c = Number(calcVal) || 0;

  if (nativeOk(n)) {
    if (!(n === 0 && c > 0 && currentPower > 30)) {
      return {
        value: clampNonNegative(n),
        source: "inverter",
        reason: "native_valid"
      };
    }
  }

  return {
    value: clampNonNegative(c),
    source: "calculated",
    reason: "native_missing_or_invalid"
  };
}

const pvDayResolved = resolveNativeOrCalc(inverterPvDayRaw, calcPvDay, "pv_day", pvPower);
const pvMonthResolved = resolveNativeOrCalc(inverterPvMonthRaw, calcPvMonth, "pv_month", pvPower);
const pvYearResolved = resolveNativeOrCalc(inverterPvYearRaw, calcPvYear, "pv_year", pvPower);
const pvTotalResolved = resolveNativeOrCalc(inverterPvTotalRaw, calcPvTotal, "pv_total", pvPower);

const loadDayResolved = resolveNativeOrCalc(inverterLoadDayRaw, calcLoadDay, "load_day", loadPower);
const loadMonthResolved = resolveNativeOrCalc(inverterLoadMonthRaw, calcLoadMonth, "load_month", loadPower);
const loadYearResolved = resolveNativeOrCalc(inverterLoadYearRaw, calcLoadYear, "load_year", loadPower);
const loadTotalResolved = resolveNativeOrCalc(inverterLoadTotalRaw, calcLoadTotal, "load_total", loadPower);

state.pv_energy_day_kwh = pvDayResolved.value;
state.pv_energy_month_kwh = pvMonthResolved.value;
state.pv_energy_year_kwh = pvYearResolved.value;
state.pv_energy_total_kwh = pvTotalResolved.value;

state.load_energy_day_kwh = loadDayResolved.value;
state.load_energy_month_kwh = loadMonthResolved.value;
state.load_energy_year_kwh = loadYearResolved.value;
state.load_energy_total_kwh = loadTotalResolved.value;

state.grid_energy_day_kwh = calcGridDay;
state.grid_energy_month_kwh = calcGridMonth;
state.grid_energy_year_kwh = calcGridYear;
state.grid_energy_total_kwh = calcGridTotal;

state.battery_charge_day_kwh = calcBattChargeDay;
state.battery_charge_month_kwh = calcBattChargeMonth;
state.battery_charge_year_kwh = calcBattChargeYear;
state.battery_charge_total_kwh = calcBattChargeTotal;

state.battery_discharge_day_kwh = calcBattDischargeDay;
state.battery_discharge_month_kwh = calcBattDischargeMonth;
state.battery_discharge_year_kwh = calcBattDischargeYear;
state.battery_discharge_total_kwh = calcBattDischargeTotal;

stats.lastTs = tsNow;
stats.lastDayKey = dayKey;
stats.lastMonthKey = monthKey;
stats.lastYearKey = yearKey;

setRobust(statsKey, stats);

const fileWriteOk = writeEnergyFileStoreForInv(fileInvKey, {
  stats,
  last_values: {
    pv_energy_day_kwh: state.pv_energy_day_kwh,
    pv_energy_month_kwh: state.pv_energy_month_kwh,
    pv_energy_year_kwh: state.pv_energy_year_kwh,
    pv_energy_total_kwh: state.pv_energy_total_kwh,

    load_energy_day_kwh: state.load_energy_day_kwh,
    load_energy_month_kwh: state.load_energy_month_kwh,
    load_energy_year_kwh: state.load_energy_year_kwh,
    load_energy_total_kwh: state.load_energy_total_kwh,

    grid_energy_day_kwh: state.grid_energy_day_kwh,
    grid_energy_month_kwh: state.grid_energy_month_kwh,
    grid_energy_year_kwh: state.grid_energy_year_kwh,
    grid_energy_total_kwh: state.grid_energy_total_kwh,

    battery_charge_day_kwh: state.battery_charge_day_kwh,
    battery_charge_month_kwh: state.battery_charge_month_kwh,
    battery_charge_year_kwh: state.battery_charge_year_kwh,
    battery_charge_total_kwh: state.battery_charge_total_kwh,

    battery_discharge_day_kwh: state.battery_discharge_day_kwh,
    battery_discharge_month_kwh: state.battery_discharge_month_kwh,
    battery_discharge_year_kwh: state.battery_discharge_year_kwh,
    battery_discharge_total_kwh: state.battery_discharge_total_kwh
  }
});

setDiagSource(state.diag, "pv_energy_day_source", pvDayResolved.source, pvDayResolved.reason);
setDiagSource(state.diag, "pv_energy_month_source", pvMonthResolved.source, pvMonthResolved.reason);
setDiagSource(state.diag, "pv_energy_year_source", pvYearResolved.source, pvYearResolved.reason);
setDiagSource(state.diag, "pv_energy_total_source", pvTotalResolved.source, pvTotalResolved.reason);

setDiagSource(state.diag, "load_energy_day_source", loadDayResolved.source, loadDayResolved.reason);
setDiagSource(state.diag, "load_energy_month_source", loadMonthResolved.source, loadMonthResolved.reason);
setDiagSource(state.diag, "load_energy_year_source", loadYearResolved.source, loadYearResolved.reason);
setDiagSource(state.diag, "load_energy_total_source", loadTotalResolved.source, loadTotalResolved.reason);

setDiagSource(state.diag, "grid_energy_day_source", "calculated", "policy_always_calculated");
setDiagSource(state.diag, "grid_energy_month_source", "calculated", "policy_always_calculated");
setDiagSource(state.diag, "grid_energy_year_source", "calculated", "policy_always_calculated");
setDiagSource(state.diag, "grid_energy_total_source", "calculated", "policy_always_calculated");

setDiagSource(state.diag, "battery_charge_day_source", "calculated", withinMidnightGuard && batteryChargeGuarded ? "midnight_guard" : "policy_always_calculated");
setDiagSource(state.diag, "battery_charge_month_source", "calculated", "policy_always_calculated");
setDiagSource(state.diag, "battery_charge_year_source", "calculated", "policy_always_calculated");
setDiagSource(state.diag, "battery_charge_total_source", "calculated", "policy_always_calculated");

setDiagSource(state.diag, "battery_discharge_day_source", "calculated", withinMidnightGuard && batteryDischargeGuarded ? "midnight_guard" : "policy_always_calculated");
setDiagSource(state.diag, "battery_discharge_month_source", "calculated", "policy_always_calculated");
setDiagSource(state.diag, "battery_discharge_year_source", "calculated", "policy_always_calculated");
setDiagSource(state.diag, "battery_discharge_total_source", "calculated", "policy_always_calculated");

state.diag.energy_dt_hours = round2(dtHours);
state.diag.energy_store_restore_stats = statsRestoreSource;
state.diag.energy_store_write_mode = "default_plus_persistent_plus_config_file";
state.diag.energy_file_store_write_ok = fileWriteOk;
state.diag.energy_file_store_key = fileInvKey;
state.diag.energy_anti_reset_active = justRestored && noNewEnergyIntegration && !dayChanged;

state.diag.energy_midnight_guard_active = withinMidnightGuard;
state.diag.energy_battery_charge_guarded = batteryChargeGuarded;
state.diag.energy_battery_discharge_guarded = batteryDischargeGuarded;

state._day_key = dayKey;
state._month_key = monthKey;
state._year_key = yearKey;
state._premium_extended_energy = premiumActive;

msg.payload = state;
return msg;

// ===============================
// PREMIUM CALC
// A placer après "Daily Energy Calc / Fallback"
// et avant "MQTT state publisher"
// ===============================

if (!msg || !msg.payload || typeof msg.payload !== "object") return msg;

const premiumActive = global.get("premium.active") === true;
if (!premiumActive) return msg;

const state = msg.payload;
const inv = msg.inverterNum ?? state.inverter ?? 1;
const now = Date.now();

// --------------------------------------------------
// Helpers
// --------------------------------------------------
function n(v) {
    const x = Number(v);
    return Number.isFinite(x) ? x : null;
}
function nz(v, fb = 0) {
    const x = Number(v);
    return Number.isFinite(x) ? x : fb;
}
function clamp(v, min, max) {
    const x = Number(v);
    if (!Number.isFinite(x)) return min;
    return Math.max(min, Math.min(max, x));
}
function round(v, d = 1) {
    const x = Number(v);
    if (!Number.isFinite(x)) return null;
    const m = Math.pow(10, d);
    return Math.round(x * m) / m;
}
function avg(arr) {
    if (!Array.isArray(arr) || !arr.length) return null;
    const vals = arr.map(Number).filter(Number.isFinite);
    if (!vals.length) return null;
    return vals.reduce((a, b) => a + b, 0) / vals.length;
}
function safeText(v, fb = "unknown") {
    if (v === null || v === undefined || v === "") return fb;
    return String(v);
}
function setNum(obj, key, val, digits = null) {
    if (!Number.isFinite(Number(val))) return;
    obj[key] = digits == null ? Number(val) : round(val, digits);
}
function getPersistent(key, fb = null) {
    const v = flow.get(key, "persistent");
    return v === undefined ? fb : v;
}
function setPersistent(key, val) {
    flow.set(key, val, "persistent");
}

function getSafeTimezone() {
    let tz = (global.get("addon_timezone") || "UTC").toString().trim();
    if (!tz) tz = "UTC";
    try {
        new Intl.DateTimeFormat("en-CA", { timeZone: tz }).format(new Date());
    } catch (e) {
        tz = "UTC";
    }
    return tz;
}

function localDayKey(d = new Date()) {
    const tz = getSafeTimezone();
    const parts = new Intl.DateTimeFormat("en-CA", {
        timeZone: tz,
        year: "numeric",
        month: "2-digit",
        day: "2-digit"
    }).formatToParts(d);

    const get = (t) => parts.find(p => p.type === t)?.value;
    return `${get("year")}-${get("month")}-${get("day")}`;
}

function localMonthKey(d = new Date()) {
    const tz = getSafeTimezone();
    const parts = new Intl.DateTimeFormat("en-CA", {
        timeZone: tz,
        year: "numeric",
        month: "2-digit"
    }).formatToParts(d);

    const get = (t) => parts.find(p => p.type === t)?.value;
    return `${get("year")}-${get("month")}`;
}

function localYearKey(d = new Date()) {
    const tz = getSafeTimezone();
    const parts = new Intl.DateTimeFormat("en-CA", {
        timeZone: tz,
        year: "numeric"
    }).formatToParts(d);

    const get = (t) => parts.find(p => p.type === t)?.value;
    return `${get("year")}`;
}

function sanitizeEnergyGap(v, totalLoad, pctFloor = 0.01, absFloor = 0.05) {
    let x = Math.max(0, nz(v));
    const load = Math.max(0, nz(totalLoad));
    const dynamicFloor = Math.max(absFloor, load * pctFloor);
    if (x < dynamicFloor) x = 0;
    return x;
}

// --------------------------------------------------
// Battery user config (premium)
// --------------------------------------------------
const sysV = Number(
    global.get(`inverter_${inv}.battery_system_voltage`) ??
    global.get("config.batterySystemVoltage") ??
    global.get("battery_system_voltage") ??
    48
);

const batteryCapacityAh = n(
    global.get(`inverter_${inv}.battery_capacity_ah`) ??
    global.get("battery_capacity_ah")
);

const batteryTotalCapacityKwh = n(
    global.get(`inverter_${inv}.battery_total_capacity_kwh`) ??
    global.get("battery_total_capacity_kwh")
);

// --------------------------------------------------
// Stats premium persistantes
// --------------------------------------------------
const statsKey = `premium_stats_inv${inv}`;
let stats = context.get(statsKey) || flow.get(statsKey, "persistent");

if (!stats || typeof stats !== "object") {
    stats = {
        dayKey: "",
        monthKey: "",
        yearKey: "",
        lastTs: now,
        battery: {
            restSamples: [],
            loadSamples: [],
            lowVoltageEventsToday: 0,
            nearLowVoltageMinutesToday: 0,
            heavyDischargeMinutesToday: 0,
            lastLowVoltageFlag: false,
            highCrateMinutesToday: 0,
            veryHighCrateMinutesToday: 0,
            highRelativePowerMinutesToday: 0,
            veryHighRelativePowerMinutesToday: 0
        },
        inverter: {
            highTempMinutesToday: 0,
            severeTempMinutesToday: 0,
            bypassMinutesToday: 0,
            faultMinutesToday: 0,
            load70MinutesToday: 0,
            load85MinutesToday: 0,
            load95MinutesToday: 0
        },
        energy: {
            gridToLoadTodayCalc: 0,
            solarToLoadTodayCalc: 0,
            gridSeenToday: false,
            gridSeenMonth: false,
            gridSeenYear: false
        }
    };
}

stats.battery = stats.battery || {};
stats.inverter = stats.inverter || {};
stats.energy = stats.energy || {};

if (!Array.isArray(stats.battery.restSamples)) stats.battery.restSamples = [];
if (!Array.isArray(stats.battery.loadSamples)) stats.battery.loadSamples = [];

if (typeof stats.energy.gridSeenToday !== "boolean") stats.energy.gridSeenToday = false;
if (typeof stats.energy.gridSeenMonth !== "boolean") stats.energy.gridSeenMonth = false;
if (typeof stats.energy.gridSeenYear !== "boolean") stats.energy.gridSeenYear = false;
if (!Number.isFinite(Number(stats.energy.gridToLoadTodayCalc))) stats.energy.gridToLoadTodayCalc = 0;
if (!Number.isFinite(Number(stats.energy.solarToLoadTodayCalc))) stats.energy.solarToLoadTodayCalc = 0;

// --------------------------------------------------
// Reset journalier / mensuel / annuel
// --------------------------------------------------
const tz = getSafeTimezone();
const dayKey = localDayKey(new Date());
const monthKey = localMonthKey(new Date());
const yearKey = localYearKey(new Date());

if (stats.dayKey !== dayKey) {
    stats.dayKey = dayKey;
    stats.lastTs = now;

    stats.battery.restSamples = [];
    stats.battery.loadSamples = [];
    stats.battery.lowVoltageEventsToday = 0;
    stats.battery.nearLowVoltageMinutesToday = 0;
    stats.battery.heavyDischargeMinutesToday = 0;
    stats.battery.lastLowVoltageFlag = false;
    stats.battery.highCrateMinutesToday = 0;
    stats.battery.veryHighCrateMinutesToday = 0;
    stats.battery.highRelativePowerMinutesToday = 0;
    stats.battery.veryHighRelativePowerMinutesToday = 0;

    stats.inverter.highTempMinutesToday = 0;
    stats.inverter.severeTempMinutesToday = 0;
    stats.inverter.bypassMinutesToday = 0;
    stats.inverter.faultMinutesToday = 0;
    stats.inverter.load70MinutesToday = 0;
    stats.inverter.load85MinutesToday = 0;
    stats.inverter.load95MinutesToday = 0;

    stats.energy.gridToLoadTodayCalc = 0;
    stats.energy.solarToLoadTodayCalc = 0;
    stats.energy.gridSeenToday = false;
}

if (stats.monthKey !== monthKey) {
    stats.monthKey = monthKey;
    stats.energy.gridSeenMonth = false;
}

if (stats.yearKey !== yearKey) {
    stats.yearKey = yearKey;
    stats.energy.gridSeenYear = false;
}

// --------------------------------------------------
// Delta temps
// --------------------------------------------------
let dtSec = (now - Number(stats.lastTs || now)) / 1000;
if (!Number.isFinite(dtSec) || dtSec < 0) dtSec = 0;
if (dtSec > 300) dtSec = 300;
stats.lastTs = now;

const dtH = dtSec / 3600;
const dtMin = dtSec / 60;

// --------------------------------------------------
// Valeurs source
// --------------------------------------------------
const loadPower = Math.max(0, nz(
    state.ac_output_active_power ??
    state.output_active_power ??
    state.output_power ??
    state.load_power
));

const loadPct = clamp(nz(state.output_load_percent), 0, 100);

const pv1Power = Math.max(0, nz(state.pv1_power));
const pv2Power = Math.max(0, nz(state.pv2_power));
const pvTotalPowerRaw = Math.max(0, nz(state.pv_total_power, pv1Power + pv2Power));

// seuil nuit / micro-prod
const solarReallyProducing = pvTotalPowerRaw > 5;
const pvTotalPower = solarReallyProducing ? pvTotalPowerRaw : 0;

const batteryVoltage = nz(state.battery_voltage);
const batteryChargeCurrent = Math.max(0, nz(state.battery_charging_current ?? state.battery_charge_current));
const batteryDischargeCurrent = Math.max(0, nz(state.battery_discharge_current));

const batteryChargePower = Math.max(
    0,
    nz(state.battery_charge ?? state.battery_charge_power, batteryVoltage * batteryChargeCurrent)
);

const batteryDischargePower = Math.max(
    0,
    Math.abs(nz(state.battery_discharge ?? state.battery_discharge_power, batteryVoltage * batteryDischargeCurrent))
);

const gridVoltage = Math.max(0, nz(state.grid_voltage ?? state.ac_input_voltage ?? state.input_voltage));
const gridPowerInstant = Math.max(0, nz(state.grid_power ?? state.grid_to_load_power));

const heatsinkTemp = n(
    state.inverter_heat_sink_temp ??
    state.heatsink_temp ??
    state.inverter_temp
);

const loadToday = Math.max(0, nz(state.load_energy_day_kwh ?? state.load_today));

// si Daily a forcé le solaire à 0 après minuit, on le respecte ici
const pvForcedZeroAfterMidnight = state.diag?.pv_force_zero_after_midnight === true;

const solarTodayRaw = Math.max(0, nz(state.pv_energy_day_kwh ?? state.solar_today ?? state.pv_today));
const solarToday = pvForcedZeroAfterMidnight ? 0 : solarTodayRaw;

const batteryDischargeToday = Math.max(0, nz(state.battery_discharge_day_kwh ?? state.battery_discharge_today));

const loadMonth = Math.max(0, nz(state.load_energy_month_kwh));
const solarMonth = Math.max(0, nz(state.pv_energy_month_kwh));
const batteryDischargeMonth = Math.max(0, nz(state.battery_discharge_month_kwh));

const loadYear = Math.max(0, nz(state.load_energy_year_kwh));
const solarYear = Math.max(0, nz(state.pv_energy_year_kwh));
const batteryDischargeYear = Math.max(0, nz(state.battery_discharge_year_kwh));

const gridDaySource = safeText(state.diag?.grid_energy_day_source, "").trim().toLowerCase();
const gridMonthSource = safeText(state.diag?.grid_energy_month_source, "").trim().toLowerCase();
const gridYearSource = safeText(state.diag?.grid_energy_year_source, "").trim().toLowerCase();

const gridTodayRaw = n(state.grid_energy_day_kwh ?? state.grid_today);
const gridMonthRaw = n(state.grid_energy_month_kwh);
const gridYearRaw = n(state.grid_energy_year_kwh);

const hasGridTodayValue = gridTodayRaw !== null && gridTodayRaw >= 0;
const hasGridMonthValue = gridMonthRaw !== null && gridMonthRaw >= 0;
const hasGridYearValue = gridYearRaw !== null && gridYearRaw >= 0;

const gridTodayValue = hasGridTodayValue ? Math.max(0, gridTodayRaw) : null;
const gridMonthValue = hasGridMonthValue ? Math.max(0, gridMonthRaw) : null;
const gridYearValue = hasGridYearValue ? Math.max(0, gridYearRaw) : null;

let opMode = safeText(
    state.operation_mode_code ?? state.operation_mode ?? state.qmod_mode,
    ""
).trim().toUpperCase();

if (opMode === "LINE") opMode = "L";
else if (opMode === "BATTERY") opMode = "B";
else if (opMode === "BYPASS") opMode = "Y";
else if (opMode === "FAULT") opMode = "F";
else if (opMode === "CHARGE") opMode = "C";

const gridPresent = gridVoltage >= 150 || gridPowerInstant > 20;

if (gridPresent || (hasGridTodayValue && gridTodayValue > 0.01)) {
    stats.energy.gridSeenToday = true;
}
if (gridPresent || (hasGridMonthValue && gridMonthValue > 0.05) || (hasGridTodayValue && gridTodayValue > 0.01)) {
    stats.energy.gridSeenMonth = true;
}
if (gridPresent || (hasGridYearValue && gridYearValue > 0.10) || (hasGridMonthValue && gridMonthValue > 0.05) || (hasGridTodayValue && gridTodayValue > 0.01)) {
    stats.energy.gridSeenYear = true;
}

const underVoltage = n(
    state.params?.qpiri?.battery_under_voltage ??
    state.battery_under_voltage ??
    state.under_voltage
);

const returnGridVoltage = n(
    state.params?.qpiri?.battery_recharge_voltage ??
    state.return_grid_voltage ??
    state.return_to_grid_voltage
);

// --------------------------------------------------
// 1) ENERGY MIX
// --------------------------------------------------

// instantané : solaire interdit la nuit
let solarToLoadPower = solarReallyProducing ? Math.min(loadPower, pvTotalPower) : 0;

let gridToLoadPower = Math.max(0, loadPower - solarToLoadPower);
if (!gridPresent || opMode === "B" || opMode === "F") gridToLoadPower = 0;

// cumuls estimés
stats.energy.solarToLoadTodayCalc += (solarToLoadPower * dtH) / 1000;
stats.energy.gridToLoadTodayCalc += (gridToLoadPower * dtH) / 1000;

// today
let gridToLoadToday = 0;
let energyFlowCalcQuality = "estimated";

// solaire journalier :
// - on garde la sécurité juste après minuit
// - mais on NE remet PAS à 0 la contribution solaire du jour simplement parce qu'il fait nuit
let solarToLoadToday = pvForcedZeroAfterMidnight
    ? 0
    : Math.max(0, Math.min(loadToday, solarToday));

// sécurité complémentaire : si une micro-valeur négative ou incohérente apparaît
if (!Number.isFinite(solarToLoadToday) || solarToLoadToday < 0) {
    solarToLoadToday = 0;
}

const batteryToLoadToday = Math.max(0, batteryDischargeToday);

if (hasGridTodayValue) {
    gridToLoadToday = Math.max(0, gridTodayValue);
    energyFlowCalcQuality = (gridDaySource === "inverter") ? "native" : "calculated";
} else if (stats.energy.gridSeenToday && loadToday > 0) {
    gridToLoadToday = Math.max(0, loadToday - solarToLoadToday - batteryToLoadToday);
    gridToLoadToday = sanitizeEnergyGap(gridToLoadToday, loadToday, 0.01, 0.03);
    energyFlowCalcQuality = "estimated";
} else {
    gridToLoadToday = 0;
    energyFlowCalcQuality = "no_grid_seen_today";
}

let sumToday = solarToLoadToday + batteryToLoadToday + gridToLoadToday;
if (loadToday > 0 && sumToday > loadToday) {
    const factor = loadToday / sumToday;
    solarToLoadToday *= factor;
    gridToLoadToday *= factor;
}

// batterie inchangée
let batteryToLoadTodayFinal = Math.max(0, batteryToLoadToday);
let gridToLoadTodayFinal = Math.max(0, gridToLoadToday);

sumToday = solarToLoadToday + batteryToLoadTodayFinal + gridToLoadTodayFinal;
if (loadToday > 0 && sumToday > loadToday) {
    const factor = loadToday / sumToday;
    solarToLoadToday *= factor;
    batteryToLoadTodayFinal *= factor;
    gridToLoadTodayFinal *= factor;
}

let solarSupplyTodayPct = 0;
let batterySupplyTodayPct = 0;
let gridSupplyTodayPct = 0;
let selfSufficiencyTodayPct = 0;
let gridDependencyTodayPct = 0;

if (loadToday > 0.001) {
    solarSupplyTodayPct = clamp((solarToLoadToday / loadToday) * 100, 0, 100);
    batterySupplyTodayPct = clamp((batteryToLoadTodayFinal / loadToday) * 100, 0, 100);
    gridSupplyTodayPct = clamp((gridToLoadTodayFinal / loadToday) * 100, 0, 100);

    const totalPct = solarSupplyTodayPct + batterySupplyTodayPct + gridSupplyTodayPct;
    if (Math.abs(totalPct - 100) > 0.2) {
        gridSupplyTodayPct = clamp(gridSupplyTodayPct + (100 - totalPct), 0, 100);
    }

    selfSufficiencyTodayPct = clamp(solarSupplyTodayPct + batterySupplyTodayPct, 0, 100);
    gridDependencyTodayPct = clamp(gridSupplyTodayPct, 0, 100);
}

if (!stats.energy.gridSeenToday && !(hasGridTodayValue && gridTodayValue > 0.01)) {
    gridSupplyTodayPct = 0;
    selfSufficiencyTodayPct = loadToday > 0.001 ? 100 : 0;
    gridDependencyTodayPct = 0;
}

// month
const solarToLoadMonth = Math.max(0, Math.min(loadMonth, solarMonth));
let gridToLoadMonth = 0;

if (hasGridMonthValue) {
    gridToLoadMonth = Math.max(0, gridMonthValue);
} else if (stats.energy.gridSeenMonth && loadMonth > 0) {
    gridToLoadMonth = Math.max(0, loadMonth - solarToLoadMonth - batteryDischargeMonth);
    gridToLoadMonth = sanitizeEnergyGap(gridToLoadMonth, loadMonth, 0.01, 0.10);
}

let selfSufficiencyMonthPct = null;
let gridDependencyMonthPct = null;

if (loadMonth > 0.001) {
    selfSufficiencyMonthPct = clamp(((solarToLoadMonth + batteryDischargeMonth) / loadMonth) * 100, 0, 100);
    gridDependencyMonthPct = clamp((gridToLoadMonth / loadMonth) * 100, 0, 100);
}

if (!stats.energy.gridSeenMonth && !(hasGridMonthValue && gridMonthValue > 0.05)) {
    gridDependencyMonthPct = 0;
    if (loadMonth > 0.001) selfSufficiencyMonthPct = 100;
}

// year
const solarToLoadYear = Math.max(0, Math.min(loadYear, solarYear));
let gridToLoadYear = 0;

if (hasGridYearValue) {
    gridToLoadYear = Math.max(0, gridYearValue);
} else if (stats.energy.gridSeenYear && loadYear > 0) {
    gridToLoadYear = Math.max(0, loadYear - solarToLoadYear - batteryDischargeYear);
    gridToLoadYear = sanitizeEnergyGap(gridToLoadYear, loadYear, 0.01, 0.25);
}

let selfSufficiencyYearPct = null;
let gridDependencyYearPct = null;

if (loadYear > 0.001) {
    selfSufficiencyYearPct = clamp(((solarToLoadYear + batteryDischargeYear) / loadYear) * 100, 0, 100);
    gridDependencyYearPct = clamp((gridToLoadYear / loadYear) * 100, 0, 100);
}

if (!stats.energy.gridSeenYear && !(hasGridYearValue && gridYearValue > 0.10)) {
    gridDependencyYearPct = 0;
    if (loadYear > 0.001) selfSufficiencyYearPct = 100;
}

// persistance
const persistBase = `inv${inv}_premium_energy`;

if (Number.isFinite(selfSufficiencyTodayPct)) setPersistent(`${persistBase}_self_today`, selfSufficiencyTodayPct);
if (Number.isFinite(selfSufficiencyMonthPct)) setPersistent(`${persistBase}_self_month`, selfSufficiencyMonthPct);
if (Number.isFinite(selfSufficiencyYearPct)) setPersistent(`${persistBase}_self_year`, selfSufficiencyYearPct);

if (Number.isFinite(gridDependencyTodayPct)) setPersistent(`${persistBase}_grid_today`, gridDependencyTodayPct);
if (Number.isFinite(gridDependencyMonthPct)) setPersistent(`${persistBase}_grid_month`, gridDependencyMonthPct);
if (Number.isFinite(gridDependencyYearPct)) setPersistent(`${persistBase}_grid_year`, gridDependencyYearPct);

if (!Number.isFinite(selfSufficiencyTodayPct)) selfSufficiencyTodayPct = getPersistent(`${persistBase}_self_today`, 0);
if (!Number.isFinite(selfSufficiencyMonthPct)) selfSufficiencyMonthPct = getPersistent(`${persistBase}_self_month`, 0);
if (!Number.isFinite(selfSufficiencyYearPct)) selfSufficiencyYearPct = getPersistent(`${persistBase}_self_year`, 0);

if (!Number.isFinite(gridDependencyTodayPct)) gridDependencyTodayPct = getPersistent(`${persistBase}_grid_today`, 0);
if (!Number.isFinite(gridDependencyMonthPct)) gridDependencyMonthPct = getPersistent(`${persistBase}_grid_month`, 0);
if (!Number.isFinite(gridDependencyYearPct)) gridDependencyYearPct = getPersistent(`${persistBase}_grid_year`, 0);

setNum(state, "grid_to_load_today", gridToLoadTodayFinal, 2);
setNum(state, "grid_to_load_month", gridToLoadMonth, 2);
setNum(state, "grid_to_load_year", gridToLoadYear, 2);

setNum(state, "solar_supply_today_pct", solarSupplyTodayPct, 1);
setNum(state, "battery_supply_today_pct", batterySupplyTodayPct, 1);
setNum(state, "grid_supply_today_pct", gridSupplyTodayPct, 1);

setNum(state, "self_sufficiency_today_pct", selfSufficiencyTodayPct, 1);
setNum(state, "self_sufficiency_month_pct", selfSufficiencyMonthPct, 1);
setNum(state, "self_sufficiency_year_pct", selfSufficiencyYearPct, 1);

setNum(state, "grid_dependency_today_pct", gridDependencyTodayPct, 1);
setNum(state, "grid_dependency_month_pct", gridDependencyMonthPct, 1);
setNum(state, "grid_dependency_year_pct", gridDependencyYearPct, 1);

state.energy_flow_calc_quality = energyFlowCalcQuality;

// --------------------------------------------------
// 2) BATTERY HEALTH
// --------------------------------------------------
const battery = stats.battery;

const lowLoad = loadPower <= 150 && batteryDischargePower <= 120;
const underLoad = loadPower >= 250 || batteryDischargePower >= 150;

if (batteryVoltage > 0) {
    if (lowLoad) {
        battery.restSamples.push(batteryVoltage);
        if (battery.restSamples.length > 20) battery.restSamples.shift();
    }
    if (underLoad) {
        battery.loadSamples.push(batteryVoltage);
        if (battery.loadSamples.length > 20) battery.loadSamples.shift();
    }
}

const restVoltageAvg = avg(battery.restSamples);
const loadVoltageAvg = avg(battery.loadSamples);
const voltageSag = (restVoltageAvg != null && loadVoltageAvg != null)
    ? Math.max(0, restVoltageAvg - loadVoltageAvg)
    : null;

let lowVoltageFlag = false;
if (underVoltage != null && batteryVoltage > 0) {
    lowVoltageFlag = batteryVoltage <= (underVoltage + 0.2);
}

if (lowVoltageFlag && !battery.lastLowVoltageFlag) {
    battery.lowVoltageEventsToday = nz(battery.lowVoltageEventsToday) + 1;
}
battery.lastLowVoltageFlag = lowVoltageFlag;

if (lowVoltageFlag && dtMin > 0) {
    battery.nearLowVoltageMinutesToday += dtMin;
}
if (batteryDischargePower > 300 && dtMin > 0) {
    battery.heavyDischargeMinutesToday += dtMin;
}

let cRate = null;
if (batteryCapacityAh && batteryCapacityAh > 0) {
    cRate = batteryDischargeCurrent / batteryCapacityAh;
    if (cRate >= 0.3) battery.highCrateMinutesToday += dtMin;
    if (cRate >= 0.6) battery.veryHighCrateMinutesToday += dtMin;
}

let relativePowerRatio = null;
const nominalBatteryPower = batteryTotalCapacityKwh && batteryTotalCapacityKwh > 0
    ? batteryTotalCapacityKwh * 1000
    : (batteryCapacityAh && batteryCapacityAh > 0 ? batteryCapacityAh * sysV : null);

if (nominalBatteryPower && nominalBatteryPower > 0) {
    relativePowerRatio = batteryDischargePower / nominalBatteryPower;
    if (relativePowerRatio >= 0.25) battery.highRelativePowerMinutesToday += dtMin;
    if (relativePowerRatio >= 0.45) battery.veryHighRelativePowerMinutesToday += dtMin;
}

let batteryHealthScore = 100;
let batteryHealthReason = "good";
let batteryStressState = "low";

if (voltageSag != null) {
    if (voltageSag >= 4.0) batteryHealthScore -= 35;
    else if (voltageSag >= 3.0) batteryHealthScore -= 25;
    else if (voltageSag >= 2.0) batteryHealthScore -= 15;
    else if (voltageSag >= 1.2) batteryHealthScore -= 8;
}

batteryHealthScore -= Math.min(20, nz(battery.lowVoltageEventsToday) * 4);
batteryHealthScore -= Math.min(20, nz(battery.nearLowVoltageMinutesToday) * 0.15);
batteryHealthScore -= Math.min(10, nz(battery.heavyDischargeMinutesToday) * 0.05);
batteryHealthScore -= Math.min(10, nz(battery.highCrateMinutesToday) * 0.03);
batteryHealthScore -= Math.min(12, nz(battery.veryHighCrateMinutesToday) * 0.05);
batteryHealthScore -= Math.min(8, nz(battery.highRelativePowerMinutesToday) * 0.02);
batteryHealthScore -= Math.min(10, nz(battery.veryHighRelativePowerMinutesToday) * 0.04);

batteryHealthScore = clamp(Math.round(batteryHealthScore), 0, 100);

let batteryHealthState = "GOOD";
if (batteryHealthScore >= 85) batteryHealthState = "EXCELLENT";
else if (batteryHealthScore >= 70) batteryHealthState = "GOOD";
else if (batteryHealthScore >= 50) batteryHealthState = "MEDIUM";
else if (batteryHealthScore >= 30) batteryHealthState = "LOW";
else batteryHealthState = "CRITICAL";

if (batteryHealthScore < 30) batteryHealthReason = "critical_voltage_stress";
else if (nz(battery.lowVoltageEventsToday) >= 3) batteryHealthReason = "repeated_low_voltage";
else if (voltageSag != null && voltageSag >= 3.0) batteryHealthReason = "high_voltage_sag";
else if (nz(battery.nearLowVoltageMinutesToday) >= 30) batteryHealthReason = "near_low_voltage";
else batteryHealthReason = "good";

if (batteryHealthScore < 35) batteryStressState = "high";
else if (batteryHealthScore < 60) batteryStressState = "moderate";
else batteryStressState = "low";

setNum(state, "battery_health_score", batteryHealthScore, 0);
state.battery_health_state = batteryHealthState;
state.battery_health_reason = batteryHealthReason;
state.battery_stress_state = batteryStressState;

// --------------------------------------------------
// 3) INVERTER HEALTH
// --------------------------------------------------
const inverter = stats.inverter;

if (heatsinkTemp != null && dtMin > 0) {
    if (heatsinkTemp >= 75) inverter.highTempMinutesToday += dtMin;
    if (heatsinkTemp >= 85) inverter.severeTempMinutesToday += dtMin;
}

if ((opMode === "Y" || opMode === "L") && dtMin > 0) inverter.bypassMinutesToday += dtMin;
if (opMode === "F" && dtMin > 0) inverter.faultMinutesToday += dtMin;

if (loadPct >= 70 && dtMin > 0) inverter.load70MinutesToday += dtMin;
if (loadPct >= 85 && dtMin > 0) inverter.load85MinutesToday += dtMin;
if (loadPct >= 95 && dtMin > 0) inverter.load95MinutesToday += dtMin;

let inverterHealthScore = 100;
inverterHealthScore -= Math.min(20, nz(inverter.highTempMinutesToday) * 0.10);
inverterHealthScore -= Math.min(25, nz(inverter.severeTempMinutesToday) * 0.20);
inverterHealthScore -= Math.min(30, nz(inverter.faultMinutesToday) * 1.50);
inverterHealthScore -= Math.min(15, nz(inverter.load85MinutesToday) * 0.06);
inverterHealthScore -= Math.min(20, nz(inverter.load95MinutesToday) * 0.10);

inverterHealthScore = clamp(Math.round(inverterHealthScore), 0, 100);

let inverterHealthState = "GOOD";
if (inverterHealthScore >= 85) inverterHealthState = "EXCELLENT";
else if (inverterHealthScore >= 70) inverterHealthState = "GOOD";
else if (inverterHealthScore >= 50) inverterHealthState = "MEDIUM";
else if (inverterHealthScore >= 30) inverterHealthState = "LOW";
else inverterHealthState = "CRITICAL";

let inverterStressState = "low";
if (
    nz(inverter.faultMinutesToday) >= 5 ||
    nz(inverter.severeTempMinutesToday) >= 30 ||
    nz(inverter.load95MinutesToday) >= 60
) {
    inverterStressState = "high";
} else if (
    nz(inverter.highTempMinutesToday) >= 60 ||
    nz(inverter.load85MinutesToday) >= 120 ||
    nz(inverter.load70MinutesToday) >= 180
) {
    inverterStressState = "moderate";
}

setNum(state, "inverter_health_score", inverterHealthScore, 0);
state.inverter_health_state = inverterHealthState;
state.inverter_stress_state = inverterStressState;

// --------------------------------------------------
// 4) ENERGY AUTONOMY SCORE
// --------------------------------------------------
let energyAutonomyScore =
    (selfSufficiencyTodayPct * 0.40) +
    (inverterHealthScore * 0.30) +
    ((100 - gridDependencyTodayPct) * 0.20);

if (inverterStressState === "low") energyAutonomyScore += 10;
else if (inverterStressState === "moderate") energyAutonomyScore += 6;
else if (inverterStressState === "high") energyAutonomyScore += 3;

energyAutonomyScore = clamp(Math.round(energyAutonomyScore), 0, 100);

let energyAutonomyState = "LOW";
if (energyAutonomyScore >= 85) energyAutonomyState = "EXCELLENT";
else if (energyAutonomyScore >= 70) energyAutonomyState = "HIGH";
else if (energyAutonomyScore >= 50) energyAutonomyState = "GOOD";
else if (energyAutonomyScore >= 30) energyAutonomyState = "MEDIUM";

setNum(state, "energy_autonomy_score", energyAutonomyScore, 0);
state.energy_autonomy_state = energyAutonomyState;

setPersistent(`${persistBase}_autonomy_score`, energyAutonomyScore);
setPersistent(`${persistBase}_autonomy_state`, energyAutonomyState);

// --------------------------------------------------
// 5) DIAG premium
// --------------------------------------------------
state.diag = state.diag || {};
state.diag.premium_day_key = dayKey;
state.diag.premium_timezone = tz;
state.diag.premium_grid_energy_day_source = gridDaySource || "unknown";
state.diag.premium_solar_really_producing = solarReallyProducing;
state.diag.premium_pv_forced_zero_after_midnight = pvForcedZeroAfterMidnight;

setNum(state.diag, "premium_voltage_sag", voltageSag, 2);
setNum(state.diag, "premium_rest_voltage_avg", restVoltageAvg, 2);
setNum(state.diag, "premium_load_voltage_avg", loadVoltageAvg, 2);

setNum(state.diag, "premium_battery_low_voltage_events_today", stats.battery.lowVoltageEventsToday, 0);
setNum(state.diag, "premium_battery_near_low_voltage_minutes_today", stats.battery.nearLowVoltageMinutesToday, 0);
setNum(state.diag, "premium_battery_high_crate_minutes_today", stats.battery.highCrateMinutesToday, 0);
setNum(state.diag, "premium_battery_very_high_crate_minutes_today", stats.battery.veryHighCrateMinutesToday, 0);
setNum(state.diag, "premium_battery_high_relative_power_minutes_today", stats.battery.highRelativePowerMinutesToday, 0);
setNum(state.diag, "premium_battery_very_high_relative_power_minutes_today", stats.battery.veryHighRelativePowerMinutesToday, 0);

setNum(state.diag, "premium_inverter_high_temp_minutes_today", stats.inverter.highTempMinutesToday, 0);
setNum(state.diag, "premium_inverter_fault_minutes_today", stats.inverter.faultMinutesToday, 0);
setNum(state.diag, "premium_inverter_load70_minutes_today", stats.inverter.load70MinutesToday, 0);
setNum(state.diag, "premium_inverter_load85_minutes_today", stats.inverter.load85MinutesToday, 0);
setNum(state.diag, "premium_inverter_load95_minutes_today", stats.inverter.load95MinutesToday, 0);

state.diag.premium_battery_stress_mode = batteryStressState;
if (cRate != null) setNum(state.diag, "premium_battery_c_rate", cRate, 3);
if (relativePowerRatio != null) setNum(state.diag, "premium_battery_relative_power_ratio", relativePowerRatio, 3);

state.diag.premium_grid_seen_today = stats.energy.gridSeenToday;
state.diag.premium_grid_seen_month = stats.energy.gridSeenMonth;
state.diag.premium_grid_seen_year = stats.energy.gridSeenYear;

// --------------------------------------------------
// Save
// --------------------------------------------------
context.set(statsKey, stats);
flow.set(statsKey, stats, "persistent");

msg.payload = state;
return msg;

// ===============================
// PREMIUM CALC
// A placer après "Daily Energy Calc / Fallback"
// et avant "MQTT state publisher"
// ===============================

if (!msg || !msg.payload || typeof msg.payload !== "object") return msg;

const premiumActive = global.get("premium.active") === true;
if (!premiumActive) return msg;

const state = msg.payload;
const inv = msg.inverterNum ?? state.inverter ?? 1;
const now = Date.now();

// --------------------------------------------------
// Helpers
// --------------------------------------------------
function n(v) {
    const x = Number(v);
    return Number.isFinite(x) ? x : null;
}
function nz(v, fb = 0) {
    const x = Number(v);
    return Number.isFinite(x) ? x : fb;
}
function clamp(v, min, max) {
    const x = Number(v);
    if (!Number.isFinite(x)) return min;
    return Math.max(min, Math.min(max, x));
}
function round(v, d = 1) {
    const x = Number(v);
    if (!Number.isFinite(x)) return null;
    const m = Math.pow(10, d);
    return Math.round(x * m) / m;
}
function avg(arr) {
    if (!Array.isArray(arr) || !arr.length) return null;
    const vals = arr.map(Number).filter(Number.isFinite);
    if (!vals.length) return null;
    return vals.reduce((a, b) => a + b, 0) / vals.length;
}
function safeText(v, fb = "unknown") {
    if (v === null || v === undefined || v === "") return fb;
    return String(v);
}
function setNum(obj, key, val, digits = null) {
    if (!Number.isFinite(Number(val))) return;
    obj[key] = digits == null ? Number(val) : round(val, digits);
}
function getPersistent(key, fb = null) {
    const v = flow.get(key, "persistent");
    return v === undefined ? fb : v;
}
function setPersistent(key, val) {
    flow.set(key, val, "persistent");
}

function getSafeTimezone() {
    let tz = (global.get("addon_timezone") || "UTC").toString().trim();
    if (!tz) tz = "UTC";
    try {
        new Intl.DateTimeFormat("en-CA", { timeZone: tz }).format(new Date());
    } catch (e) {
        tz = "UTC";
    }
    return tz;
}

function localDayKey(d = new Date()) {
    const tz = getSafeTimezone();
    const parts = new Intl.DateTimeFormat("en-CA", {
        timeZone: tz,
        year: "numeric",
        month: "2-digit",
        day: "2-digit"
    }).formatToParts(d);

    const get = (t) => parts.find(p => p.type === t)?.value;
    return `${get("year")}-${get("month")}-${get("day")}`;
}

function localMonthKey(d = new Date()) {
    const tz = getSafeTimezone();
    const parts = new Intl.DateTimeFormat("en-CA", {
        timeZone: tz,
        year: "numeric",
        month: "2-digit"
    }).formatToParts(d);

    const get = (t) => parts.find(p => p.type === t)?.value;
    return `${get("year")}-${get("month")}`;
}

function localYearKey(d = new Date()) {
    const tz = getSafeTimezone();
    const parts = new Intl.DateTimeFormat("en-CA", {
        timeZone: tz,
        year: "numeric"
    }).formatToParts(d);

    const get = (t) => parts.find(p => p.type === t)?.value;
    return `${get("year")}`;
}

function sanitizeEnergyGap(v, totalLoad, pctFloor = 0.01, absFloor = 0.05) {
    let x = Math.max(0, nz(v));
    const load = Math.max(0, nz(totalLoad));
    const dynamicFloor = Math.max(absFloor, load * pctFloor);
    if (x < dynamicFloor) x = 0;
    return x;
}

// --------------------------------------------------
// Battery user config (premium)
// --------------------------------------------------
const sysV = Number(
    global.get(`inverter_${inv}.battery_system_voltage`) ??
    global.get("config.batterySystemVoltage") ??
    global.get("battery_system_voltage") ??
    48
);

const batteryCapacityAh = n(
    global.get(`inverter_${inv}.battery_capacity_ah`) ??
    global.get("battery_capacity_ah")
);

const batteryTotalCapacityKwh = n(
    global.get(`inverter_${inv}.battery_total_capacity_kwh`) ??
    global.get("battery_total_capacity_kwh")
);

// --------------------------------------------------
// Stats premium persistantes
// --------------------------------------------------
const statsKey = `premium_stats_inv${inv}`;
let stats = context.get(statsKey) || flow.get(statsKey, "persistent");

if (!stats || typeof stats !== "object") {
    stats = {
        dayKey: "",
        monthKey: "",
        yearKey: "",
        lastTs: now,
        battery: {
            restSamples: [],
            loadSamples: [],
            lowVoltageEventsToday: 0,
            nearLowVoltageMinutesToday: 0,
            heavyDischargeMinutesToday: 0,
            lastLowVoltageFlag: false,
            highCrateMinutesToday: 0,
            veryHighCrateMinutesToday: 0,
            highRelativePowerMinutesToday: 0,
            veryHighRelativePowerMinutesToday: 0
        },
        inverter: {
            highTempMinutesToday: 0,
            severeTempMinutesToday: 0,
            bypassMinutesToday: 0,
            faultMinutesToday: 0,
            load70MinutesToday: 0,
            load85MinutesToday: 0,
            load95MinutesToday: 0
        },
        energy: {
            gridToLoadTodayCalc: 0,
            solarToLoadTodayCalc: 0,
            gridSeenToday: false,
            gridSeenMonth: false,
            gridSeenYear: false
        }
    };
}

stats.battery = stats.battery || {};
stats.inverter = stats.inverter || {};
stats.energy = stats.energy || {};

if (!Array.isArray(stats.battery.restSamples)) stats.battery.restSamples = [];
if (!Array.isArray(stats.battery.loadSamples)) stats.battery.loadSamples = [];

if (typeof stats.energy.gridSeenToday !== "boolean") stats.energy.gridSeenToday = false;
if (typeof stats.energy.gridSeenMonth !== "boolean") stats.energy.gridSeenMonth = false;
if (typeof stats.energy.gridSeenYear !== "boolean") stats.energy.gridSeenYear = false;
if (!Number.isFinite(Number(stats.energy.gridToLoadTodayCalc))) stats.energy.gridToLoadTodayCalc = 0;
if (!Number.isFinite(Number(stats.energy.solarToLoadTodayCalc))) stats.energy.solarToLoadTodayCalc = 0;

// --------------------------------------------------
// Reset journalier / mensuel / annuel
// --------------------------------------------------
const tz = getSafeTimezone();
const dayKey = localDayKey(new Date());
const monthKey = localMonthKey(new Date());
const yearKey = localYearKey(new Date());

if (stats.dayKey !== dayKey) {
    stats.dayKey = dayKey;
    stats.lastTs = now;

    stats.battery.restSamples = [];
    stats.battery.loadSamples = [];
    stats.battery.lowVoltageEventsToday = 0;
    stats.battery.nearLowVoltageMinutesToday = 0;
    stats.battery.heavyDischargeMinutesToday = 0;
    stats.battery.lastLowVoltageFlag = false;
    stats.battery.highCrateMinutesToday = 0;
    stats.battery.veryHighCrateMinutesToday = 0;
    stats.battery.highRelativePowerMinutesToday = 0;
    stats.battery.veryHighRelativePowerMinutesToday = 0;

    stats.inverter.highTempMinutesToday = 0;
    stats.inverter.severeTempMinutesToday = 0;
    stats.inverter.bypassMinutesToday = 0;
    stats.inverter.faultMinutesToday = 0;
    stats.inverter.load70MinutesToday = 0;
    stats.inverter.load85MinutesToday = 0;
    stats.inverter.load95MinutesToday = 0;

    stats.energy.gridToLoadTodayCalc = 0;
    stats.energy.solarToLoadTodayCalc = 0;
    stats.energy.gridSeenToday = false;
}

if (stats.monthKey !== monthKey) {
    stats.monthKey = monthKey;
    stats.energy.gridSeenMonth = false;
}

if (stats.yearKey !== yearKey) {
    stats.yearKey = yearKey;
    stats.energy.gridSeenYear = false;
}

// --------------------------------------------------
// Delta temps
// --------------------------------------------------
let dtSec = (now - Number(stats.lastTs || now)) / 1000;
if (!Number.isFinite(dtSec) || dtSec < 0) dtSec = 0;
if (dtSec > 300) dtSec = 300;
stats.lastTs = now;

const dtH = dtSec / 3600;
const dtMin = dtSec / 60;

// --------------------------------------------------
// Valeurs source
// --------------------------------------------------
const loadPower = Math.max(0, nz(
    state.ac_output_active_power ??
    state.output_active_power ??
    state.output_power ??
    state.load_power
));

const loadPct = clamp(nz(state.output_load_percent), 0, 100);

const pv1Power = Math.max(0, nz(state.pv1_power));
const pv2Power = Math.max(0, nz(state.pv2_power));
const pvTotalPowerRaw = Math.max(0, nz(state.pv_total_power, pv1Power + pv2Power));

// seuil nuit / micro-prod
const solarReallyProducing = pvTotalPowerRaw > 5;
const pvTotalPower = solarReallyProducing ? pvTotalPowerRaw : 0;

const batteryVoltage = nz(state.battery_voltage);
const batteryChargeCurrent = Math.max(0, nz(state.battery_charging_current ?? state.battery_charge_current));
const batteryDischargeCurrent = Math.max(0, nz(state.battery_discharge_current));

const batteryChargePower = Math.max(
    0,
    nz(state.battery_charge ?? state.battery_charge_power, batteryVoltage * batteryChargeCurrent)
);

const batteryDischargePower = Math.max(
    0,
    Math.abs(nz(state.battery_discharge ?? state.battery_discharge_power, batteryVoltage * batteryDischargeCurrent))
);

const gridVoltage = Math.max(0, nz(state.grid_voltage ?? state.ac_input_voltage ?? state.input_voltage));
const gridPowerInstant = Math.max(0, nz(state.grid_power ?? state.grid_to_load_power));

const heatsinkTemp = n(
    state.inverter_heat_sink_temp ??
    state.heatsink_temp ??
    state.inverter_temp
);

const loadToday = Math.max(0, nz(state.load_energy_day_kwh ?? state.load_today));

// si Daily a forcé le solaire à 0 après minuit, on le respecte ici
const pvForcedZeroAfterMidnight = state.diag?.pv_force_zero_after_midnight === true;

const solarTodayRaw = Math.max(0, nz(state.pv_energy_day_kwh ?? state.solar_today ?? state.pv_today));
const solarToday = pvForcedZeroAfterMidnight ? 0 : solarTodayRaw;

const batteryDischargeToday = Math.max(0, nz(state.battery_discharge_day_kwh ?? state.battery_discharge_today));

const loadMonth = Math.max(0, nz(state.load_energy_month_kwh));
const solarMonth = Math.max(0, nz(state.pv_energy_month_kwh));
const batteryDischargeMonth = Math.max(0, nz(state.battery_discharge_month_kwh));

const loadYear = Math.max(0, nz(state.load_energy_year_kwh));
const solarYear = Math.max(0, nz(state.pv_energy_year_kwh));
const batteryDischargeYear = Math.max(0, nz(state.battery_discharge_year_kwh));

const gridDaySource = safeText(state.diag?.grid_energy_day_source, "").trim().toLowerCase();
const gridMonthSource = safeText(state.diag?.grid_energy_month_source, "").trim().toLowerCase();
const gridYearSource = safeText(state.diag?.grid_energy_year_source, "").trim().toLowerCase();

const gridTodayRaw = n(state.grid_energy_day_kwh ?? state.grid_today);
const gridMonthRaw = n(state.grid_energy_month_kwh);
const gridYearRaw = n(state.grid_energy_year_kwh);

const hasGridTodayValue = gridTodayRaw !== null && gridTodayRaw >= 0;
const hasGridMonthValue = gridMonthRaw !== null && gridMonthRaw >= 0;
const hasGridYearValue = gridYearRaw !== null && gridYearRaw >= 0;

const gridTodayValue = hasGridTodayValue ? Math.max(0, gridTodayRaw) : null;
const gridMonthValue = hasGridMonthValue ? Math.max(0, gridMonthRaw) : null;
const gridYearValue = hasGridYearValue ? Math.max(0, gridYearRaw) : null;

let opMode = safeText(
    state.operation_mode_code ?? state.operation_mode ?? state.qmod_mode,
    ""
).trim().toUpperCase();

if (opMode === "LINE") opMode = "L";
else if (opMode === "BATTERY") opMode = "B";
else if (opMode === "BYPASS") opMode = "Y";
else if (opMode === "FAULT") opMode = "F";
else if (opMode === "CHARGE") opMode = "C";

const gridPresent = gridVoltage >= 150 || gridPowerInstant > 20;

if (gridPresent || (hasGridTodayValue && gridTodayValue > 0.01)) {
    stats.energy.gridSeenToday = true;
}
if (gridPresent || (hasGridMonthValue && gridMonthValue > 0.05) || (hasGridTodayValue && gridTodayValue > 0.01)) {
    stats.energy.gridSeenMonth = true;
}
if (gridPresent || (hasGridYearValue && gridYearValue > 0.10) || (hasGridMonthValue && gridMonthValue > 0.05) || (hasGridTodayValue && gridTodayValue > 0.01)) {
    stats.energy.gridSeenYear = true;
}

const underVoltage = n(
    state.params?.qpiri?.battery_under_voltage ??
    state.battery_under_voltage ??
    state.under_voltage
);

const returnGridVoltage = n(
    state.params?.qpiri?.battery_recharge_voltage ??
    state.return_grid_voltage ??
    state.return_to_grid_voltage
);

// --------------------------------------------------
// 1) ENERGY MIX
// --------------------------------------------------

// instantané : solaire interdit la nuit
let solarToLoadPower = solarReallyProducing ? Math.min(loadPower, pvTotalPower) : 0;

let gridToLoadPower = Math.max(0, loadPower - solarToLoadPower);
if (!gridPresent || opMode === "B" || opMode === "F") gridToLoadPower = 0;

// cumuls estimés
stats.energy.solarToLoadTodayCalc += (solarToLoadPower * dtH) / 1000;
stats.energy.gridToLoadTodayCalc += (gridToLoadPower * dtH) / 1000;

// today
let gridToLoadToday = 0;
let energyFlowCalcQuality = "estimated";

// solaire journalier :
// - on garde la sécurité juste après minuit
// - mais on NE remet PAS à 0 la contribution solaire du jour simplement parce qu'il fait nuit
let solarToLoadToday = pvForcedZeroAfterMidnight
    ? 0
    : Math.max(0, Math.min(loadToday, solarToday));

// sécurité complémentaire : si une micro-valeur négative ou incohérente apparaît
if (!Number.isFinite(solarToLoadToday) || solarToLoadToday < 0) {
    solarToLoadToday = 0;
}

const batteryToLoadToday = Math.max(0, batteryDischargeToday);

if (hasGridTodayValue) {
    gridToLoadToday = Math.max(0, gridTodayValue);
    energyFlowCalcQuality = (gridDaySource === "inverter") ? "native" : "calculated";
} else if (stats.energy.gridSeenToday && loadToday > 0) {
    gridToLoadToday = Math.max(0, loadToday - solarToLoadToday - batteryToLoadToday);
    gridToLoadToday = sanitizeEnergyGap(gridToLoadToday, loadToday, 0.01, 0.03);
    energyFlowCalcQuality = "estimated";
} else {
    gridToLoadToday = 0;
    energyFlowCalcQuality = "no_grid_seen_today";
}

let sumToday = solarToLoadToday + batteryToLoadToday + gridToLoadToday;
if (loadToday > 0 && sumToday > loadToday) {
    const factor = loadToday / sumToday;
    solarToLoadToday *= factor;
    gridToLoadToday *= factor;
}

// batterie inchangée
let batteryToLoadTodayFinal = Math.max(0, batteryToLoadToday);
let gridToLoadTodayFinal = Math.max(0, gridToLoadToday);

sumToday = solarToLoadToday + batteryToLoadTodayFinal + gridToLoadTodayFinal;
if (loadToday > 0 && sumToday > loadToday) {
    const factor = loadToday / sumToday;
    solarToLoadToday *= factor;
    batteryToLoadTodayFinal *= factor;
    gridToLoadTodayFinal *= factor;
}

let solarSupplyTodayPct = 0;
let batterySupplyTodayPct = 0;
let gridSupplyTodayPct = 0;
let selfSufficiencyTodayPct = 0;
let gridDependencyTodayPct = 0;

if (loadToday > 0.001) {
    solarSupplyTodayPct = clamp((solarToLoadToday / loadToday) * 100, 0, 100);
    batterySupplyTodayPct = clamp((batteryToLoadTodayFinal / loadToday) * 100, 0, 100);
    gridSupplyTodayPct = clamp((gridToLoadTodayFinal / loadToday) * 100, 0, 100);

    const totalPct = solarSupplyTodayPct + batterySupplyTodayPct + gridSupplyTodayPct;
    if (Math.abs(totalPct - 100) > 0.2) {
        gridSupplyTodayPct = clamp(gridSupplyTodayPct + (100 - totalPct), 0, 100);
    }

    selfSufficiencyTodayPct = clamp(solarSupplyTodayPct + batterySupplyTodayPct, 0, 100);
    gridDependencyTodayPct = clamp(gridSupplyTodayPct, 0, 100);
}

if (!stats.energy.gridSeenToday && !(hasGridTodayValue && gridTodayValue > 0.01)) {
    gridSupplyTodayPct = 0;
    selfSufficiencyTodayPct = loadToday > 0.001 ? 100 : 0;
    gridDependencyTodayPct = 0;
}

// month
const solarToLoadMonth = Math.max(0, Math.min(loadMonth, solarMonth));
let gridToLoadMonth = 0;

if (hasGridMonthValue) {
    gridToLoadMonth = Math.max(0, gridMonthValue);
} else if (stats.energy.gridSeenMonth && loadMonth > 0) {
    gridToLoadMonth = Math.max(0, loadMonth - solarToLoadMonth - batteryDischargeMonth);
    gridToLoadMonth = sanitizeEnergyGap(gridToLoadMonth, loadMonth, 0.01, 0.10);
}

let selfSufficiencyMonthPct = null;
let gridDependencyMonthPct = null;

if (loadMonth > 0.001) {
    selfSufficiencyMonthPct = clamp(((solarToLoadMonth + batteryDischargeMonth) / loadMonth) * 100, 0, 100);
    gridDependencyMonthPct = clamp((gridToLoadMonth / loadMonth) * 100, 0, 100);
}

if (!stats.energy.gridSeenMonth && !(hasGridMonthValue && gridMonthValue > 0.05)) {
    gridDependencyMonthPct = 0;
    if (loadMonth > 0.001) selfSufficiencyMonthPct = 100;
}

// year
const solarToLoadYear = Math.max(0, Math.min(loadYear, solarYear));
let gridToLoadYear = 0;

if (hasGridYearValue) {
    gridToLoadYear = Math.max(0, gridYearValue);
} else if (stats.energy.gridSeenYear && loadYear > 0) {
    gridToLoadYear = Math.max(0, loadYear - solarToLoadYear - batteryDischargeYear);
    gridToLoadYear = sanitizeEnergyGap(gridToLoadYear, loadYear, 0.01, 0.25);
}

let selfSufficiencyYearPct = null;
let gridDependencyYearPct = null;

if (loadYear > 0.001) {
    selfSufficiencyYearPct = clamp(((solarToLoadYear + batteryDischargeYear) / loadYear) * 100, 0, 100);
    gridDependencyYearPct = clamp((gridToLoadYear / loadYear) * 100, 0, 100);
}

if (!stats.energy.gridSeenYear && !(hasGridYearValue && gridYearValue > 0.10)) {
    gridDependencyYearPct = 0;
    if (loadYear > 0.001) selfSufficiencyYearPct = 100;
}

// persistance
const persistBase = `inv${inv}_premium_energy`;

if (Number.isFinite(selfSufficiencyTodayPct)) setPersistent(`${persistBase}_self_today`, selfSufficiencyTodayPct);
if (Number.isFinite(selfSufficiencyMonthPct)) setPersistent(`${persistBase}_self_month`, selfSufficiencyMonthPct);
if (Number.isFinite(selfSufficiencyYearPct)) setPersistent(`${persistBase}_self_year`, selfSufficiencyYearPct);

if (Number.isFinite(gridDependencyTodayPct)) setPersistent(`${persistBase}_grid_today`, gridDependencyTodayPct);
if (Number.isFinite(gridDependencyMonthPct)) setPersistent(`${persistBase}_grid_month`, gridDependencyMonthPct);
if (Number.isFinite(gridDependencyYearPct)) setPersistent(`${persistBase}_grid_year`, gridDependencyYearPct);

if (!Number.isFinite(selfSufficiencyTodayPct)) selfSufficiencyTodayPct = getPersistent(`${persistBase}_self_today`, 0);
if (!Number.isFinite(selfSufficiencyMonthPct)) selfSufficiencyMonthPct = getPersistent(`${persistBase}_self_month`, 0);
if (!Number.isFinite(selfSufficiencyYearPct)) selfSufficiencyYearPct = getPersistent(`${persistBase}_self_year`, 0);

if (!Number.isFinite(gridDependencyTodayPct)) gridDependencyTodayPct = getPersistent(`${persistBase}_grid_today`, 0);
if (!Number.isFinite(gridDependencyMonthPct)) gridDependencyMonthPct = getPersistent(`${persistBase}_grid_month`, 0);
if (!Number.isFinite(gridDependencyYearPct)) gridDependencyYearPct = getPersistent(`${persistBase}_grid_year`, 0);

setNum(state, "grid_to_load_today", gridToLoadTodayFinal, 2);
setNum(state, "grid_to_load_month", gridToLoadMonth, 2);
setNum(state, "grid_to_load_year", gridToLoadYear, 2);

setNum(state, "solar_supply_today_pct", solarSupplyTodayPct, 1);
setNum(state, "battery_supply_today_pct", batterySupplyTodayPct, 1);
setNum(state, "grid_supply_today_pct", gridSupplyTodayPct, 1);

setNum(state, "self_sufficiency_today_pct", selfSufficiencyTodayPct, 1);
setNum(state, "self_sufficiency_month_pct", selfSufficiencyMonthPct, 1);
setNum(state, "self_sufficiency_year_pct", selfSufficiencyYearPct, 1);

setNum(state, "grid_dependency_today_pct", gridDependencyTodayPct, 1);
setNum(state, "grid_dependency_month_pct", gridDependencyMonthPct, 1);
setNum(state, "grid_dependency_year_pct", gridDependencyYearPct, 1);

state.energy_flow_calc_quality = energyFlowCalcQuality;

// --------------------------------------------------
// 2) BATTERY HEALTH
// --------------------------------------------------
const battery = stats.battery;

const lowLoad = loadPower <= 150 && batteryDischargePower <= 120;
const underLoad = loadPower >= 250 || batteryDischargePower >= 150;

if (batteryVoltage > 0) {
    if (lowLoad) {
        battery.restSamples.push(batteryVoltage);
        if (battery.restSamples.length > 20) battery.restSamples.shift();
    }
    if (underLoad) {
        battery.loadSamples.push(batteryVoltage);
        if (battery.loadSamples.length > 20) battery.loadSamples.shift();
    }
}

const restVoltageAvg = avg(battery.restSamples);
const loadVoltageAvg = avg(battery.loadSamples);
const voltageSag = (restVoltageAvg != null && loadVoltageAvg != null)
    ? Math.max(0, restVoltageAvg - loadVoltageAvg)
    : null;

let lowVoltageFlag = false;
if (underVoltage != null && batteryVoltage > 0) {
    lowVoltageFlag = batteryVoltage <= (underVoltage + 0.2);
}

if (lowVoltageFlag && !battery.lastLowVoltageFlag) {
    battery.lowVoltageEventsToday = nz(battery.lowVoltageEventsToday) + 1;
}
battery.lastLowVoltageFlag = lowVoltageFlag;

if (lowVoltageFlag && dtMin > 0) {
    battery.nearLowVoltageMinutesToday += dtMin;
}
if (batteryDischargePower > 300 && dtMin > 0) {
    battery.heavyDischargeMinutesToday += dtMin;
}

let cRate = null;
if (batteryCapacityAh && batteryCapacityAh > 0) {
    cRate = batteryDischargeCurrent / batteryCapacityAh;
    if (cRate >= 0.3) battery.highCrateMinutesToday += dtMin;
    if (cRate >= 0.6) battery.veryHighCrateMinutesToday += dtMin;
}

let relativePowerRatio = null;
const nominalBatteryPower = batteryTotalCapacityKwh && batteryTotalCapacityKwh > 0
    ? batteryTotalCapacityKwh * 1000
    : (batteryCapacityAh && batteryCapacityAh > 0 ? batteryCapacityAh * sysV : null);

if (nominalBatteryPower && nominalBatteryPower > 0) {
    relativePowerRatio = batteryDischargePower / nominalBatteryPower;
    if (relativePowerRatio >= 0.25) battery.highRelativePowerMinutesToday += dtMin;
    if (relativePowerRatio >= 0.45) battery.veryHighRelativePowerMinutesToday += dtMin;
}

let batteryHealthScore = 100;
let batteryHealthReason = "good";
let batteryStressState = "low";

if (voltageSag != null) {
    if (voltageSag >= 4.0) batteryHealthScore -= 35;
    else if (voltageSag >= 3.0) batteryHealthScore -= 25;
    else if (voltageSag >= 2.0) batteryHealthScore -= 15;
    else if (voltageSag >= 1.2) batteryHealthScore -= 8;
}

batteryHealthScore -= Math.min(20, nz(battery.lowVoltageEventsToday) * 4);
batteryHealthScore -= Math.min(20, nz(battery.nearLowVoltageMinutesToday) * 0.15);
batteryHealthScore -= Math.min(10, nz(battery.heavyDischargeMinutesToday) * 0.05);
batteryHealthScore -= Math.min(10, nz(battery.highCrateMinutesToday) * 0.03);
batteryHealthScore -= Math.min(12, nz(battery.veryHighCrateMinutesToday) * 0.05);
batteryHealthScore -= Math.min(8, nz(battery.highRelativePowerMinutesToday) * 0.02);
batteryHealthScore -= Math.min(10, nz(battery.veryHighRelativePowerMinutesToday) * 0.04);

batteryHealthScore = clamp(Math.round(batteryHealthScore), 0, 100);

let batteryHealthState = "GOOD";
if (batteryHealthScore >= 85) batteryHealthState = "EXCELLENT";
else if (batteryHealthScore >= 70) batteryHealthState = "GOOD";
else if (batteryHealthScore >= 50) batteryHealthState = "MEDIUM";
else if (batteryHealthScore >= 30) batteryHealthState = "LOW";
else batteryHealthState = "CRITICAL";

if (batteryHealthScore < 30) batteryHealthReason = "critical_voltage_stress";
else if (nz(battery.lowVoltageEventsToday) >= 3) batteryHealthReason = "repeated_low_voltage";
else if (voltageSag != null && voltageSag >= 3.0) batteryHealthReason = "high_voltage_sag";
else if (nz(battery.nearLowVoltageMinutesToday) >= 30) batteryHealthReason = "near_low_voltage";
else batteryHealthReason = "good";

if (batteryHealthScore < 35) batteryStressState = "high";
else if (batteryHealthScore < 60) batteryStressState = "moderate";
else batteryStressState = "low";

setNum(state, "battery_health_score", batteryHealthScore, 0);
state.battery_health_state = batteryHealthState;
state.battery_health_reason = batteryHealthReason;
state.battery_stress_state = batteryStressState;

// --------------------------------------------------
// 3) INVERTER HEALTH
// --------------------------------------------------
const inverter = stats.inverter;

if (heatsinkTemp != null && dtMin > 0) {
    if (heatsinkTemp >= 75) inverter.highTempMinutesToday += dtMin;
    if (heatsinkTemp >= 85) inverter.severeTempMinutesToday += dtMin;
}

if ((opMode === "Y" || opMode === "L") && dtMin > 0) inverter.bypassMinutesToday += dtMin;
if (opMode === "F" && dtMin > 0) inverter.faultMinutesToday += dtMin;

if (loadPct >= 70 && dtMin > 0) inverter.load70MinutesToday += dtMin;
if (loadPct >= 85 && dtMin > 0) inverter.load85MinutesToday += dtMin;
if (loadPct >= 95 && dtMin > 0) inverter.load95MinutesToday += dtMin;

let inverterHealthScore = 100;
inverterHealthScore -= Math.min(20, nz(inverter.highTempMinutesToday) * 0.10);
inverterHealthScore -= Math.min(25, nz(inverter.severeTempMinutesToday) * 0.20);
inverterHealthScore -= Math.min(30, nz(inverter.faultMinutesToday) * 1.50);
inverterHealthScore -= Math.min(15, nz(inverter.load85MinutesToday) * 0.06);
inverterHealthScore -= Math.min(20, nz(inverter.load95MinutesToday) * 0.10);

inverterHealthScore = clamp(Math.round(inverterHealthScore), 0, 100);

let inverterHealthState = "GOOD";
if (inverterHealthScore >= 85) inverterHealthState = "EXCELLENT";
else if (inverterHealthScore >= 70) inverterHealthState = "GOOD";
else if (inverterHealthScore >= 50) inverterHealthState = "MEDIUM";
else if (inverterHealthScore >= 30) inverterHealthState = "LOW";
else inverterHealthState = "CRITICAL";

let inverterStressState = "low";
if (
    nz(inverter.faultMinutesToday) >= 5 ||
    nz(inverter.severeTempMinutesToday) >= 30 ||
    nz(inverter.load95MinutesToday) >= 60
) {
    inverterStressState = "high";
} else if (
    nz(inverter.highTempMinutesToday) >= 60 ||
    nz(inverter.load85MinutesToday) >= 120 ||
    nz(inverter.load70MinutesToday) >= 180
) {
    inverterStressState = "moderate";
}

setNum(state, "inverter_health_score", inverterHealthScore, 0);
state.inverter_health_state = inverterHealthState;
state.inverter_stress_state = inverterStressState;

// --------------------------------------------------
// 4) ENERGY AUTONOMY SCORE
// --------------------------------------------------
let energyAutonomyScore =
    (selfSufficiencyTodayPct * 0.40) +
    (inverterHealthScore * 0.30) +
    ((100 - gridDependencyTodayPct) * 0.20);

if (inverterStressState === "low") energyAutonomyScore += 10;
else if (inverterStressState === "moderate") energyAutonomyScore += 6;
else if (inverterStressState === "high") energyAutonomyScore += 3;

energyAutonomyScore = clamp(Math.round(energyAutonomyScore), 0, 100);

let energyAutonomyState = "LOW";
if (energyAutonomyScore >= 85) energyAutonomyState = "EXCELLENT";
else if (energyAutonomyScore >= 70) energyAutonomyState = "HIGH";
else if (energyAutonomyScore >= 50) energyAutonomyState = "GOOD";
else if (energyAutonomyScore >= 30) energyAutonomyState = "MEDIUM";

setNum(state, "energy_autonomy_score", energyAutonomyScore, 0);
state.energy_autonomy_state = energyAutonomyState;

setPersistent(`${persistBase}_autonomy_score`, energyAutonomyScore);
setPersistent(`${persistBase}_autonomy_state`, energyAutonomyState);

// --------------------------------------------------
// 5) DIAG premium
// --------------------------------------------------
state.diag = state.diag || {};
state.diag.premium_day_key = dayKey;
state.diag.premium_timezone = tz;
state.diag.premium_grid_energy_day_source = gridDaySource || "unknown";
state.diag.premium_solar_really_producing = solarReallyProducing;
state.diag.premium_pv_forced_zero_after_midnight = pvForcedZeroAfterMidnight;

setNum(state.diag, "premium_voltage_sag", voltageSag, 2);
setNum(state.diag, "premium_rest_voltage_avg", restVoltageAvg, 2);
setNum(state.diag, "premium_load_voltage_avg", loadVoltageAvg, 2);

setNum(state.diag, "premium_battery_low_voltage_events_today", stats.battery.lowVoltageEventsToday, 0);
setNum(state.diag, "premium_battery_near_low_voltage_minutes_today", stats.battery.nearLowVoltageMinutesToday, 0);
setNum(state.diag, "premium_battery_high_crate_minutes_today", stats.battery.highCrateMinutesToday, 0);
setNum(state.diag, "premium_battery_very_high_crate_minutes_today", stats.battery.veryHighCrateMinutesToday, 0);
setNum(state.diag, "premium_battery_high_relative_power_minutes_today", stats.battery.highRelativePowerMinutesToday, 0);
setNum(state.diag, "premium_battery_very_high_relative_power_minutes_today", stats.battery.veryHighRelativePowerMinutesToday, 0);

setNum(state.diag, "premium_inverter_high_temp_minutes_today", stats.inverter.highTempMinutesToday, 0);
setNum(state.diag, "premium_inverter_fault_minutes_today", stats.inverter.faultMinutesToday, 0);
setNum(state.diag, "premium_inverter_load70_minutes_today", stats.inverter.load70MinutesToday, 0);
setNum(state.diag, "premium_inverter_load85_minutes_today", stats.inverter.load85MinutesToday, 0);
setNum(state.diag, "premium_inverter_load95_minutes_today", stats.inverter.load95MinutesToday, 0);

state.diag.premium_battery_stress_mode = batteryStressState;
if (cRate != null) setNum(state.diag, "premium_battery_c_rate", cRate, 3);
if (relativePowerRatio != null) setNum(state.diag, "premium_battery_relative_power_ratio", relativePowerRatio, 3);

state.diag.premium_grid_seen_today = stats.energy.gridSeenToday;
state.diag.premium_grid_seen_month = stats.energy.gridSeenMonth;
state.diag.premium_grid_seen_year = stats.energy.gridSeenYear;

// --------------------------------------------------
// Save
// --------------------------------------------------
context.set(statsKey, stats);
flow.set(statsKey, stats, "persistent");

msg.payload = state;
return msg;

// ===============================
// PREMIUM CALC
// A placer après "Daily Energy Calc / Fallback"
// et avant "MQTT state publisher"
// ===============================

if (!msg || !msg.payload || typeof msg.payload !== "object") return msg;

const premiumActive = global.get("premium.active") === true;
if (!premiumActive) return msg;

const state = msg.payload;
const inv = msg.inverterNum ?? state.inverter ?? 1;
const now = Date.now();

// --------------------------------------------------
// Helpers
// --------------------------------------------------
function n(v) {
    const x = Number(v);
    return Number.isFinite(x) ? x : null;
}
function nz(v, fb = 0) {
    const x = Number(v);
    return Number.isFinite(x) ? x : fb;
}
function clamp(v, min, max) {
    const x = Number(v);
    if (!Number.isFinite(x)) return min;
    return Math.max(min, Math.min(max, x));
}
function round(v, d = 1) {
    const x = Number(v);
    if (!Number.isFinite(x)) return null;
    const m = Math.pow(10, d);
    return Math.round(x * m) / m;
}
function avg(arr) {
    if (!Array.isArray(arr) || !arr.length) return null;
    const vals = arr.map(Number).filter(Number.isFinite);
    if (!vals.length) return null;
    return vals.reduce((a, b) => a + b, 0) / vals.length;
}
function safeText(v, fb = "unknown") {
    if (v === null || v === undefined || v === "") return fb;
    return String(v);
}
function setNum(obj, key, val, digits = null) {
    if (!Number.isFinite(Number(val))) return;
    obj[key] = digits == null ? Number(val) : round(val, digits);
}
function getPersistent(key, fb = null) {
    const v = flow.get(key, "persistent");
    return v === undefined ? fb : v;
}
function setPersistent(key, val) {
    flow.set(key, val, "persistent");
}

function getSafeTimezone() {
    let tz = (global.get("addon_timezone") || "UTC").toString().trim();
    if (!tz) tz = "UTC";
    try {
        new Intl.DateTimeFormat("en-CA", { timeZone: tz }).format(new Date());
    } catch (e) {
        tz = "UTC";
    }
    return tz;
}

function localDayKey(d = new Date()) {
    const tz = getSafeTimezone();
    const parts = new Intl.DateTimeFormat("en-CA", {
        timeZone: tz,
        year: "numeric",
        month: "2-digit",
        day: "2-digit"
    }).formatToParts(d);

    const get = (t) => parts.find(p => p.type === t)?.value;
    return `${get("year")}-${get("month")}-${get("day")}`;
}

function localMonthKey(d = new Date()) {
    const tz = getSafeTimezone();
    const parts = new Intl.DateTimeFormat("en-CA", {
        timeZone: tz,
        year: "numeric",
        month: "2-digit"
    }).formatToParts(d);

    const get = (t) => parts.find(p => p.type === t)?.value;
    return `${get("year")}-${get("month")}`;
}

function localYearKey(d = new Date()) {
    const tz = getSafeTimezone();
    const parts = new Intl.DateTimeFormat("en-CA", {
        timeZone: tz,
        year: "numeric"
    }).formatToParts(d);

    const get = (t) => parts.find(p => p.type === t)?.value;
    return `${get("year")}`;
}

function sanitizeEnergyGap(v, totalLoad, pctFloor = 0.01, absFloor = 0.05) {
    let x = Math.max(0, nz(v));
    const load = Math.max(0, nz(totalLoad));
    const dynamicFloor = Math.max(absFloor, load * pctFloor);
    if (x < dynamicFloor) x = 0;
    return x;
}

// --------------------------------------------------
// Battery user config (premium)
// --------------------------------------------------
const sysV = Number(
    global.get(`inverter_${inv}.battery_system_voltage`) ??
    global.get("config.batterySystemVoltage") ??
    global.get("battery_system_voltage") ??
    48
);

const batteryCapacityAh = n(
    global.get(`inverter_${inv}.battery_capacity_ah`) ??
    global.get("battery_capacity_ah")
);

const batteryTotalCapacityKwh = n(
    global.get(`inverter_${inv}.battery_total_capacity_kwh`) ??
    global.get("battery_total_capacity_kwh")
);

// --------------------------------------------------
// Stats premium persistantes
// --------------------------------------------------
const statsKey = `premium_stats_inv${inv}`;
let stats = context.get(statsKey) || flow.get(statsKey, "persistent");

if (!stats || typeof stats !== "object") {
    stats = {
        dayKey: "",
        monthKey: "",
        yearKey: "",
        lastTs: now,
        battery: {
            restSamples: [],
            loadSamples: [],
            lowVoltageEventsToday: 0,
            nearLowVoltageMinutesToday: 0,
            heavyDischargeMinutesToday: 0,
            lastLowVoltageFlag: false,
            highCrateMinutesToday: 0,
            veryHighCrateMinutesToday: 0,
            highRelativePowerMinutesToday: 0,
            veryHighRelativePowerMinutesToday: 0
        },
        inverter: {
            highTempMinutesToday: 0,
            severeTempMinutesToday: 0,
            bypassMinutesToday: 0,
            faultMinutesToday: 0,
            load70MinutesToday: 0,
            load85MinutesToday: 0,
            load95MinutesToday: 0
        },
        energy: {
            gridToLoadTodayCalc: 0,
            solarToLoadTodayCalc: 0,
            gridSeenToday: false,
            gridSeenMonth: false,
            gridSeenYear: false
        }
    };
}

stats.battery = stats.battery || {};
stats.inverter = stats.inverter || {};
stats.energy = stats.energy || {};

if (!Array.isArray(stats.battery.restSamples)) stats.battery.restSamples = [];
if (!Array.isArray(stats.battery.loadSamples)) stats.battery.loadSamples = [];

if (typeof stats.energy.gridSeenToday !== "boolean") stats.energy.gridSeenToday = false;
if (typeof stats.energy.gridSeenMonth !== "boolean") stats.energy.gridSeenMonth = false;
if (typeof stats.energy.gridSeenYear !== "boolean") stats.energy.gridSeenYear = false;
if (!Number.isFinite(Number(stats.energy.gridToLoadTodayCalc))) stats.energy.gridToLoadTodayCalc = 0;
if (!Number.isFinite(Number(stats.energy.solarToLoadTodayCalc))) stats.energy.solarToLoadTodayCalc = 0;

// --------------------------------------------------
// Reset journalier / mensuel / annuel
// --------------------------------------------------
const tz = getSafeTimezone();
const dayKey = localDayKey(new Date());
const monthKey = localMonthKey(new Date());
const yearKey = localYearKey(new Date());

if (stats.dayKey !== dayKey) {
    stats.dayKey = dayKey;
    stats.lastTs = now;

    stats.battery.restSamples = [];
    stats.battery.loadSamples = [];
    stats.battery.lowVoltageEventsToday = 0;
    stats.battery.nearLowVoltageMinutesToday = 0;
    stats.battery.heavyDischargeMinutesToday = 0;
    stats.battery.lastLowVoltageFlag = false;
    stats.battery.highCrateMinutesToday = 0;
    stats.battery.veryHighCrateMinutesToday = 0;
    stats.battery.highRelativePowerMinutesToday = 0;
    stats.battery.veryHighRelativePowerMinutesToday = 0;

    stats.inverter.highTempMinutesToday = 0;
    stats.inverter.severeTempMinutesToday = 0;
    stats.inverter.bypassMinutesToday = 0;
    stats.inverter.faultMinutesToday = 0;
    stats.inverter.load70MinutesToday = 0;
    stats.inverter.load85MinutesToday = 0;
    stats.inverter.load95MinutesToday = 0;

    stats.energy.gridToLoadTodayCalc = 0;
    stats.energy.solarToLoadTodayCalc = 0;
    stats.energy.gridSeenToday = false;
}

if (stats.monthKey !== monthKey) {
    stats.monthKey = monthKey;
    stats.energy.gridSeenMonth = false;
}

if (stats.yearKey !== yearKey) {
    stats.yearKey = yearKey;
    stats.energy.gridSeenYear = false;
}

// --------------------------------------------------
// Delta temps
// --------------------------------------------------
let dtSec = (now - Number(stats.lastTs || now)) / 1000;
if (!Number.isFinite(dtSec) || dtSec < 0) dtSec = 0;
if (dtSec > 300) dtSec = 300;
stats.lastTs = now;

const dtH = dtSec / 3600;
const dtMin = dtSec / 60;

// --------------------------------------------------
// Valeurs source
// --------------------------------------------------
const loadPower = Math.max(0, nz(
    state.ac_output_active_power ??
    state.output_active_power ??
    state.output_power ??
    state.load_power
));

const loadPct = clamp(nz(state.output_load_percent), 0, 100);

const pv1Power = Math.max(0, nz(state.pv1_power));
const pv2Power = Math.max(0, nz(state.pv2_power));
const pvTotalPowerRaw = Math.max(0, nz(state.pv_total_power, pv1Power + pv2Power));

// seuil nuit / micro-prod
const solarReallyProducing = pvTotalPowerRaw > 5;
const pvTotalPower = solarReallyProducing ? pvTotalPowerRaw : 0;

const batteryVoltage = nz(state.battery_voltage);
const batteryChargeCurrent = Math.max(0, nz(state.battery_charging_current ?? state.battery_charge_current));
const batteryDischargeCurrent = Math.max(0, nz(state.battery_discharge_current));

const batteryChargePower = Math.max(
    0,
    nz(state.battery_charge ?? state.battery_charge_power, batteryVoltage * batteryChargeCurrent)
);

const batteryDischargePower = Math.max(
    0,
    Math.abs(nz(state.battery_discharge ?? state.battery_discharge_power, batteryVoltage * batteryDischargeCurrent))
);

const gridVoltage = Math.max(0, nz(state.grid_voltage ?? state.ac_input_voltage ?? state.input_voltage));
const gridPowerInstant = Math.max(0, nz(state.grid_power ?? state.grid_to_load_power));

const heatsinkTemp = n(
    state.inverter_heat_sink_temp ??
    state.heatsink_temp ??
    state.inverter_temp
);

const loadToday = Math.max(0, nz(state.load_energy_day_kwh ?? state.load_today));

// si Daily a forcé le solaire à 0 après minuit, on le respecte ici
const pvForcedZeroAfterMidnight = state.diag?.pv_force_zero_after_midnight === true;

const solarTodayRaw = Math.max(0, nz(state.pv_energy_day_kwh ?? state.solar_today ?? state.pv_today));
const solarToday = pvForcedZeroAfterMidnight ? 0 : solarTodayRaw;

const batteryDischargeToday = Math.max(0, nz(state.battery_discharge_day_kwh ?? state.battery_discharge_today));

const loadMonth = Math.max(0, nz(state.load_energy_month_kwh));
const solarMonth = Math.max(0, nz(state.pv_energy_month_kwh));
const batteryDischargeMonth = Math.max(0, nz(state.battery_discharge_month_kwh));

const loadYear = Math.max(0, nz(state.load_energy_year_kwh));
const solarYear = Math.max(0, nz(state.pv_energy_year_kwh));
const batteryDischargeYear = Math.max(0, nz(state.battery_discharge_year_kwh));

const gridDaySource = safeText(state.diag?.grid_energy_day_source, "").trim().toLowerCase();
const gridMonthSource = safeText(state.diag?.grid_energy_month_source, "").trim().toLowerCase();
const gridYearSource = safeText(state.diag?.grid_energy_year_source, "").trim().toLowerCase();

const gridTodayRaw = n(state.grid_energy_day_kwh ?? state.grid_today);
const gridMonthRaw = n(state.grid_energy_month_kwh);
const gridYearRaw = n(state.grid_energy_year_kwh);

const hasGridTodayValue = gridTodayRaw !== null && gridTodayRaw >= 0;
const hasGridMonthValue = gridMonthRaw !== null && gridMonthRaw >= 0;
const hasGridYearValue = gridYearRaw !== null && gridYearRaw >= 0;

const gridTodayValue = hasGridTodayValue ? Math.max(0, gridTodayRaw) : null;
const gridMonthValue = hasGridMonthValue ? Math.max(0, gridMonthRaw) : null;
const gridYearValue = hasGridYearValue ? Math.max(0, gridYearRaw) : null;

let opMode = safeText(
    state.operation_mode_code ?? state.operation_mode ?? state.qmod_mode,
    ""
).trim().toUpperCase();

if (opMode === "LINE") opMode = "L";
else if (opMode === "BATTERY") opMode = "B";
else if (opMode === "BYPASS") opMode = "Y";
else if (opMode === "FAULT") opMode = "F";
else if (opMode === "CHARGE") opMode = "C";

const gridPresent = gridVoltage >= 150 || gridPowerInstant > 20;

if (gridPresent || (hasGridTodayValue && gridTodayValue > 0.01)) {
    stats.energy.gridSeenToday = true;
}
if (gridPresent || (hasGridMonthValue && gridMonthValue > 0.05) || (hasGridTodayValue && gridTodayValue > 0.01)) {
    stats.energy.gridSeenMonth = true;
}
if (gridPresent || (hasGridYearValue && gridYearValue > 0.10) || (hasGridMonthValue && gridMonthValue > 0.05) || (hasGridTodayValue && gridTodayValue > 0.01)) {
    stats.energy.gridSeenYear = true;
}

const underVoltage = n(
    state.params?.qpiri?.battery_under_voltage ??
    state.battery_under_voltage ??
    state.under_voltage
);

const returnGridVoltage = n(
    state.params?.qpiri?.battery_recharge_voltage ??
    state.return_grid_voltage ??
    state.return_to_grid_voltage
);

// --------------------------------------------------
// 1) ENERGY MIX
// --------------------------------------------------

// instantané : solaire interdit la nuit
let solarToLoadPower = solarReallyProducing ? Math.min(loadPower, pvTotalPower) : 0;

let gridToLoadPower = Math.max(0, loadPower - solarToLoadPower);
if (!gridPresent || opMode === "B" || opMode === "F") gridToLoadPower = 0;

// cumuls estimés
stats.energy.solarToLoadTodayCalc += (solarToLoadPower * dtH) / 1000;
stats.energy.gridToLoadTodayCalc += (gridToLoadPower * dtH) / 1000;

// today
let gridToLoadToday = 0;
let energyFlowCalcQuality = "estimated";

// solaire journalier :
// - on garde la sécurité juste après minuit
// - mais on NE remet PAS à 0 la contribution solaire du jour simplement parce qu'il fait nuit
let solarToLoadToday = pvForcedZeroAfterMidnight
    ? 0
    : Math.max(0, Math.min(loadToday, solarToday));

// sécurité complémentaire : si une micro-valeur négative ou incohérente apparaît
if (!Number.isFinite(solarToLoadToday) || solarToLoadToday < 0) {
    solarToLoadToday = 0;
}

const batteryToLoadToday = Math.max(0, batteryDischargeToday);

if (hasGridTodayValue) {
    gridToLoadToday = Math.max(0, gridTodayValue);
    energyFlowCalcQuality = (gridDaySource === "inverter") ? "native" : "calculated";
} else if (stats.energy.gridSeenToday && loadToday > 0) {
    gridToLoadToday = Math.max(0, loadToday - solarToLoadToday - batteryToLoadToday);
    gridToLoadToday = sanitizeEnergyGap(gridToLoadToday, loadToday, 0.01, 0.03);
    energyFlowCalcQuality = "estimated";
} else {
    gridToLoadToday = 0;
    energyFlowCalcQuality = "no_grid_seen_today";
}

let sumToday = solarToLoadToday + batteryToLoadToday + gridToLoadToday;
if (loadToday > 0 && sumToday > loadToday) {
    const factor = loadToday / sumToday;
    solarToLoadToday *= factor;
    gridToLoadToday *= factor;
}

// batterie inchangée
let batteryToLoadTodayFinal = Math.max(0, batteryToLoadToday);
let gridToLoadTodayFinal = Math.max(0, gridToLoadToday);

sumToday = solarToLoadToday + batteryToLoadTodayFinal + gridToLoadTodayFinal;
if (loadToday > 0 && sumToday > loadToday) {
    const factor = loadToday / sumToday;
    solarToLoadToday *= factor;
    batteryToLoadTodayFinal *= factor;
    gridToLoadTodayFinal *= factor;
}

let solarSupplyTodayPct = 0;
let batterySupplyTodayPct = 0;
let gridSupplyTodayPct = 0;
let selfSufficiencyTodayPct = 0;
let gridDependencyTodayPct = 0;

if (loadToday > 0.001) {
    solarSupplyTodayPct = clamp((solarToLoadToday / loadToday) * 100, 0, 100);
    batterySupplyTodayPct = clamp((batteryToLoadTodayFinal / loadToday) * 100, 0, 100);
    gridSupplyTodayPct = clamp((gridToLoadTodayFinal / loadToday) * 100, 0, 100);

    const totalPct = solarSupplyTodayPct + batterySupplyTodayPct + gridSupplyTodayPct;
    if (Math.abs(totalPct - 100) > 0.2) {
        gridSupplyTodayPct = clamp(gridSupplyTodayPct + (100 - totalPct), 0, 100);
    }

    selfSufficiencyTodayPct = clamp(solarSupplyTodayPct + batterySupplyTodayPct, 0, 100);
    gridDependencyTodayPct = clamp(gridSupplyTodayPct, 0, 100);
}

if (!stats.energy.gridSeenToday && !(hasGridTodayValue && gridTodayValue > 0.01)) {
    gridSupplyTodayPct = 0;
    selfSufficiencyTodayPct = loadToday > 0.001 ? 100 : 0;
    gridDependencyTodayPct = 0;
}

// month
const solarToLoadMonth = Math.max(0, Math.min(loadMonth, solarMonth));
let gridToLoadMonth = 0;

if (hasGridMonthValue) {
    gridToLoadMonth = Math.max(0, gridMonthValue);
} else if (stats.energy.gridSeenMonth && loadMonth > 0) {
    gridToLoadMonth = Math.max(0, loadMonth - solarToLoadMonth - batteryDischargeMonth);
    gridToLoadMonth = sanitizeEnergyGap(gridToLoadMonth, loadMonth, 0.01, 0.10);
}

let selfSufficiencyMonthPct = null;
let gridDependencyMonthPct = null;

if (loadMonth > 0.001) {
    selfSufficiencyMonthPct = clamp(((solarToLoadMonth + batteryDischargeMonth) / loadMonth) * 100, 0, 100);
    gridDependencyMonthPct = clamp((gridToLoadMonth / loadMonth) * 100, 0, 100);
}

if (!stats.energy.gridSeenMonth && !(hasGridMonthValue && gridMonthValue > 0.05)) {
    gridDependencyMonthPct = 0;
    if (loadMonth > 0.001) selfSufficiencyMonthPct = 100;
}

// year
const solarToLoadYear = Math.max(0, Math.min(loadYear, solarYear));
let gridToLoadYear = 0;

if (hasGridYearValue) {
    gridToLoadYear = Math.max(0, gridYearValue);
} else if (stats.energy.gridSeenYear && loadYear > 0) {
    gridToLoadYear = Math.max(0, loadYear - solarToLoadYear - batteryDischargeYear);
    gridToLoadYear = sanitizeEnergyGap(gridToLoadYear, loadYear, 0.01, 0.25);
}

let selfSufficiencyYearPct = null;
let gridDependencyYearPct = null;

if (loadYear > 0.001) {
    selfSufficiencyYearPct = clamp(((solarToLoadYear + batteryDischargeYear) / loadYear) * 100, 0, 100);
    gridDependencyYearPct = clamp((gridToLoadYear / loadYear) * 100, 0, 100);
}

if (!stats.energy.gridSeenYear && !(hasGridYearValue && gridYearValue > 0.10)) {
    gridDependencyYearPct = 0;
    if (loadYear > 0.001) selfSufficiencyYearPct = 100;
}

// persistance
const persistBase = `inv${inv}_premium_energy`;

if (Number.isFinite(selfSufficiencyTodayPct)) setPersistent(`${persistBase}_self_today`, selfSufficiencyTodayPct);
if (Number.isFinite(selfSufficiencyMonthPct)) setPersistent(`${persistBase}_self_month`, selfSufficiencyMonthPct);
if (Number.isFinite(selfSufficiencyYearPct)) setPersistent(`${persistBase}_self_year`, selfSufficiencyYearPct);

if (Number.isFinite(gridDependencyTodayPct)) setPersistent(`${persistBase}_grid_today`, gridDependencyTodayPct);
if (Number.isFinite(gridDependencyMonthPct)) setPersistent(`${persistBase}_grid_month`, gridDependencyMonthPct);
if (Number.isFinite(gridDependencyYearPct)) setPersistent(`${persistBase}_grid_year`, gridDependencyYearPct);

if (!Number.isFinite(selfSufficiencyTodayPct)) selfSufficiencyTodayPct = getPersistent(`${persistBase}_self_today`, 0);
if (!Number.isFinite(selfSufficiencyMonthPct)) selfSufficiencyMonthPct = getPersistent(`${persistBase}_self_month`, 0);
if (!Number.isFinite(selfSufficiencyYearPct)) selfSufficiencyYearPct = getPersistent(`${persistBase}_self_year`, 0);

if (!Number.isFinite(gridDependencyTodayPct)) gridDependencyTodayPct = getPersistent(`${persistBase}_grid_today`, 0);
if (!Number.isFinite(gridDependencyMonthPct)) gridDependencyMonthPct = getPersistent(`${persistBase}_grid_month`, 0);
if (!Number.isFinite(gridDependencyYearPct)) gridDependencyYearPct = getPersistent(`${persistBase}_grid_year`, 0);

setNum(state, "grid_to_load_today", gridToLoadTodayFinal, 2);
setNum(state, "grid_to_load_month", gridToLoadMonth, 2);
setNum(state, "grid_to_load_year", gridToLoadYear, 2);

setNum(state, "solar_supply_today_pct", solarSupplyTodayPct, 1);
setNum(state, "battery_supply_today_pct", batterySupplyTodayPct, 1);
setNum(state, "grid_supply_today_pct", gridSupplyTodayPct, 1);

setNum(state, "self_sufficiency_today_pct", selfSufficiencyTodayPct, 1);
setNum(state, "self_sufficiency_month_pct", selfSufficiencyMonthPct, 1);
setNum(state, "self_sufficiency_year_pct", selfSufficiencyYearPct, 1);

setNum(state, "grid_dependency_today_pct", gridDependencyTodayPct, 1);
setNum(state, "grid_dependency_month_pct", gridDependencyMonthPct, 1);
setNum(state, "grid_dependency_year_pct", gridDependencyYearPct, 1);

state.energy_flow_calc_quality = energyFlowCalcQuality;

// --------------------------------------------------
// 2) BATTERY HEALTH
// --------------------------------------------------
const battery = stats.battery;

const lowLoad = loadPower <= 150 && batteryDischargePower <= 120;
const underLoad = loadPower >= 250 || batteryDischargePower >= 150;

if (batteryVoltage > 0) {
    if (lowLoad) {
        battery.restSamples.push(batteryVoltage);
        if (battery.restSamples.length > 20) battery.restSamples.shift();
    }
    if (underLoad) {
        battery.loadSamples.push(batteryVoltage);
        if (battery.loadSamples.length > 20) battery.loadSamples.shift();
    }
}

const restVoltageAvg = avg(battery.restSamples);
const loadVoltageAvg = avg(battery.loadSamples);
const voltageSag = (restVoltageAvg != null && loadVoltageAvg != null)
    ? Math.max(0, restVoltageAvg - loadVoltageAvg)
    : null;

let lowVoltageFlag = false;
if (underVoltage != null && batteryVoltage > 0) {
    lowVoltageFlag = batteryVoltage <= (underVoltage + 0.2);
}

if (lowVoltageFlag && !battery.lastLowVoltageFlag) {
    battery.lowVoltageEventsToday = nz(battery.lowVoltageEventsToday) + 1;
}
battery.lastLowVoltageFlag = lowVoltageFlag;

if (lowVoltageFlag && dtMin > 0) {
    battery.nearLowVoltageMinutesToday += dtMin;
}
if (batteryDischargePower > 300 && dtMin > 0) {
    battery.heavyDischargeMinutesToday += dtMin;
}

let cRate = null;
if (batteryCapacityAh && batteryCapacityAh > 0) {
    cRate = batteryDischargeCurrent / batteryCapacityAh;
    if (cRate >= 0.3) battery.highCrateMinutesToday += dtMin;
    if (cRate >= 0.6) battery.veryHighCrateMinutesToday += dtMin;
}

let relativePowerRatio = null;
const nominalBatteryPower = batteryTotalCapacityKwh && batteryTotalCapacityKwh > 0
    ? batteryTotalCapacityKwh * 1000
    : (batteryCapacityAh && batteryCapacityAh > 0 ? batteryCapacityAh * sysV : null);

if (nominalBatteryPower && nominalBatteryPower > 0) {
    relativePowerRatio = batteryDischargePower / nominalBatteryPower;
    if (relativePowerRatio >= 0.25) battery.highRelativePowerMinutesToday += dtMin;
    if (relativePowerRatio >= 0.45) battery.veryHighRelativePowerMinutesToday += dtMin;
}

let batteryHealthScore = 100;
let batteryHealthReason = "good";
let batteryStressState = "low";

if (voltageSag != null) {
    if (voltageSag >= 4.0) batteryHealthScore -= 35;
    else if (voltageSag >= 3.0) batteryHealthScore -= 25;
    else if (voltageSag >= 2.0) batteryHealthScore -= 15;
    else if (voltageSag >= 1.2) batteryHealthScore -= 8;
}

batteryHealthScore -= Math.min(20, nz(battery.lowVoltageEventsToday) * 4);
batteryHealthScore -= Math.min(20, nz(battery.nearLowVoltageMinutesToday) * 0.15);
batteryHealthScore -= Math.min(10, nz(battery.heavyDischargeMinutesToday) * 0.05);
batteryHealthScore -= Math.min(10, nz(battery.highCrateMinutesToday) * 0.03);
batteryHealthScore -= Math.min(12, nz(battery.veryHighCrateMinutesToday) * 0.05);
batteryHealthScore -= Math.min(8, nz(battery.highRelativePowerMinutesToday) * 0.02);
batteryHealthScore -= Math.min(10, nz(battery.veryHighRelativePowerMinutesToday) * 0.04);

batteryHealthScore = clamp(Math.round(batteryHealthScore), 0, 100);

let batteryHealthState = "GOOD";
if (batteryHealthScore >= 85) batteryHealthState = "EXCELLENT";
else if (batteryHealthScore >= 70) batteryHealthState = "GOOD";
else if (batteryHealthScore >= 50) batteryHealthState = "MEDIUM";
else if (batteryHealthScore >= 30) batteryHealthState = "LOW";
else batteryHealthState = "CRITICAL";

if (batteryHealthScore < 30) batteryHealthReason = "critical_voltage_stress";
else if (nz(battery.lowVoltageEventsToday) >= 3) batteryHealthReason = "repeated_low_voltage";
else if (voltageSag != null && voltageSag >= 3.0) batteryHealthReason = "high_voltage_sag";
else if (nz(battery.nearLowVoltageMinutesToday) >= 30) batteryHealthReason = "near_low_voltage";
else batteryHealthReason = "good";

if (batteryHealthScore < 35) batteryStressState = "high";
else if (batteryHealthScore < 60) batteryStressState = "moderate";
else batteryStressState = "low";

setNum(state, "battery_health_score", batteryHealthScore, 0);
state.battery_health_state = batteryHealthState;
state.battery_health_reason = batteryHealthReason;
state.battery_stress_state = batteryStressState;

// --------------------------------------------------
// 3) INVERTER HEALTH
// --------------------------------------------------
const inverter = stats.inverter;

if (heatsinkTemp != null && dtMin > 0) {
    if (heatsinkTemp >= 75) inverter.highTempMinutesToday += dtMin;
    if (heatsinkTemp >= 85) inverter.severeTempMinutesToday += dtMin;
}

if ((opMode === "Y" || opMode === "L") && dtMin > 0) inverter.bypassMinutesToday += dtMin;
if (opMode === "F" && dtMin > 0) inverter.faultMinutesToday += dtMin;

if (loadPct >= 70 && dtMin > 0) inverter.load70MinutesToday += dtMin;
if (loadPct >= 85 && dtMin > 0) inverter.load85MinutesToday += dtMin;
if (loadPct >= 95 && dtMin > 0) inverter.load95MinutesToday += dtMin;

let inverterHealthScore = 100;
inverterHealthScore -= Math.min(20, nz(inverter.highTempMinutesToday) * 0.10);
inverterHealthScore -= Math.min(25, nz(inverter.severeTempMinutesToday) * 0.20);
inverterHealthScore -= Math.min(30, nz(inverter.faultMinutesToday) * 1.50);
inverterHealthScore -= Math.min(15, nz(inverter.load85MinutesToday) * 0.06);
inverterHealthScore -= Math.min(20, nz(inverter.load95MinutesToday) * 0.10);

inverterHealthScore = clamp(Math.round(inverterHealthScore), 0, 100);

let inverterHealthState = "GOOD";
if (inverterHealthScore >= 85) inverterHealthState = "EXCELLENT";
else if (inverterHealthScore >= 70) inverterHealthState = "GOOD";
else if (inverterHealthScore >= 50) inverterHealthState = "MEDIUM";
else if (inverterHealthScore >= 30) inverterHealthState = "LOW";
else inverterHealthState = "CRITICAL";

let inverterStressState = "low";
if (
    nz(inverter.faultMinutesToday) >= 5 ||
    nz(inverter.severeTempMinutesToday) >= 30 ||
    nz(inverter.load95MinutesToday) >= 60
) {
    inverterStressState = "high";
} else if (
    nz(inverter.highTempMinutesToday) >= 60 ||
    nz(inverter.load85MinutesToday) >= 120 ||
    nz(inverter.load70MinutesToday) >= 180
) {
    inverterStressState = "moderate";
}

setNum(state, "inverter_health_score", inverterHealthScore, 0);
state.inverter_health_state = inverterHealthState;
state.inverter_stress_state = inverterStressState;

// --------------------------------------------------
// 4) ENERGY AUTONOMY SCORE
// --------------------------------------------------
let energyAutonomyScore =
    (selfSufficiencyTodayPct * 0.40) +
    (inverterHealthScore * 0.30) +
    ((100 - gridDependencyTodayPct) * 0.20);

if (inverterStressState === "low") energyAutonomyScore += 10;
else if (inverterStressState === "moderate") energyAutonomyScore += 6;
else if (inverterStressState === "high") energyAutonomyScore += 3;

energyAutonomyScore = clamp(Math.round(energyAutonomyScore), 0, 100);

let energyAutonomyState = "LOW";
if (energyAutonomyScore >= 85) energyAutonomyState = "EXCELLENT";
else if (energyAutonomyScore >= 70) energyAutonomyState = "HIGH";
else if (energyAutonomyScore >= 50) energyAutonomyState = "GOOD";
else if (energyAutonomyScore >= 30) energyAutonomyState = "MEDIUM";

setNum(state, "energy_autonomy_score", energyAutonomyScore, 0);
state.energy_autonomy_state = energyAutonomyState;

setPersistent(`${persistBase}_autonomy_score`, energyAutonomyScore);
setPersistent(`${persistBase}_autonomy_state`, energyAutonomyState);

// --------------------------------------------------
// 5) DIAG premium
// --------------------------------------------------
state.diag = state.diag || {};
state.diag.premium_day_key = dayKey;
state.diag.premium_timezone = tz;
state.diag.premium_grid_energy_day_source = gridDaySource || "unknown";
state.diag.premium_solar_really_producing = solarReallyProducing;
state.diag.premium_pv_forced_zero_after_midnight = pvForcedZeroAfterMidnight;

setNum(state.diag, "premium_voltage_sag", voltageSag, 2);
setNum(state.diag, "premium_rest_voltage_avg", restVoltageAvg, 2);
setNum(state.diag, "premium_load_voltage_avg", loadVoltageAvg, 2);

setNum(state.diag, "premium_battery_low_voltage_events_today", stats.battery.lowVoltageEventsToday, 0);
setNum(state.diag, "premium_battery_near_low_voltage_minutes_today", stats.battery.nearLowVoltageMinutesToday, 0);
setNum(state.diag, "premium_battery_high_crate_minutes_today", stats.battery.highCrateMinutesToday, 0);
setNum(state.diag, "premium_battery_very_high_crate_minutes_today", stats.battery.veryHighCrateMinutesToday, 0);
setNum(state.diag, "premium_battery_high_relative_power_minutes_today", stats.battery.highRelativePowerMinutesToday, 0);
setNum(state.diag, "premium_battery_very_high_relative_power_minutes_today", stats.battery.veryHighRelativePowerMinutesToday, 0);

setNum(state.diag, "premium_inverter_high_temp_minutes_today", stats.inverter.highTempMinutesToday, 0);
setNum(state.diag, "premium_inverter_fault_minutes_today", stats.inverter.faultMinutesToday, 0);
setNum(state.diag, "premium_inverter_load70_minutes_today", stats.inverter.load70MinutesToday, 0);
setNum(state.diag, "premium_inverter_load85_minutes_today", stats.inverter.load85MinutesToday, 0);
setNum(state.diag, "premium_inverter_load95_minutes_today", stats.inverter.load95MinutesToday, 0);

state.diag.premium_battery_stress_mode = batteryStressState;
if (cRate != null) setNum(state.diag, "premium_battery_c_rate", cRate, 3);
if (relativePowerRatio != null) setNum(state.diag, "premium_battery_relative_power_ratio", relativePowerRatio, 3);

state.diag.premium_grid_seen_today = stats.energy.gridSeenToday;
state.diag.premium_grid_seen_month = stats.energy.gridSeenMonth;
state.diag.premium_grid_seen_year = stats.energy.gridSeenYear;

// --------------------------------------------------
// Save
// --------------------------------------------------
context.set(statsKey, stats);
flow.set(statsKey, stats, "persistent");

msg.payload = state;
return msg;

const fs = global.get("fs");
const path = global.get("path");

const FILE = "/config/smart_voltronic_energy_store.json";

function ensureObj(v) {
  return v && typeof v === "object" && !Array.isArray(v) ? v : {};
}

function safeGet(key, store) {
  try {
    return flow.get(key, store);
  } catch (e) {
    return null;
  }
}

function totalStatsValue(stats) {
  if (!stats || typeof stats !== "object") return 0;

  let sum = 0;
  for (const bucket of ["day", "month", "year", "total"]) {
    const b = stats[bucket];
    if (!b || typeof b !== "object") continue;

    for (const k of ["pv", "load", "grid", "battCharge", "battDischarge"]) {
      const n = Number(b[k]);
      if (Number.isFinite(n) && n > 0) sum += n;
    }
  }

  return sum;
}

let data = {
  version: 1,
  migrated_at: new Date().toISOString(),
  inverters: {}
};

try {
  if (fs.existsSync(FILE)) {
    data = JSON.parse(fs.readFileSync(FILE, "utf8"));
    if (!data.inverters) data.inverters = {};
  }
} catch (e) {
  data = { version: 1, migrated_at: new Date().toISOString(), inverters: {} };
}

let migrated = [];
let skipped = [];

for (let inv = 1; inv <= 3; inv++) {
  const invKey = `inverter_${inv}`;
  const oldKey = `inv${inv}_energy_stats`;

  const oldStats =
    safeGet(oldKey, "persistent") ||
    safeGet(oldKey) ||
    null;

  if (!oldStats || typeof oldStats !== "object") {
    skipped.push(`${invKey}: no_old_stats`);
    continue;
  }

  const fileStats = data.inverters?.[invKey]?.stats || null;

  const oldScore = totalStatsValue(oldStats);
  const fileScore = totalStatsValue(fileStats);

  // Si l'ancien contexte contient plus de valeurs que le fichier,
  // on répare le fichier même s'il existe déjà.
  if (oldScore > fileScore) {
    data.inverters[invKey] = {
      ...(data.inverters[invKey] || {}),
      stats: oldStats,
      migrated_from: oldKey,
      migrated_at: new Date().toISOString(),
      migration_reason: fileStats ? "repaired_zero_or_lower_file_store" : "initial_migration"
    };

    migrated.push(`${invKey}: ${fileScore} -> ${oldScore}`);
  } else {
    skipped.push(`${invKey}: file_ok`);
  }
}

try {
  fs.mkdirSync(path.dirname(FILE), { recursive: true });
  fs.writeFileSync(FILE, JSON.stringify(data, null, 2), "utf8");

  node.status({
    fill: migrated.length ? "green" : "blue",
    shape: "dot",
    text: migrated.length
      ? `Migrated/Repaired: ${migrated.length}`
      : "No migration needed"
  });
} catch (e) {
  node.error("Energy migration write error: " + e.message, msg);
  return null;
}

msg.payload = {
  ok: true,
  migrated,
  skipped
};

return msg;

// =======================
// MQTT DISCOVERY - VOLTRONIC (SAFE TEMPLATES)
// VERSION PAR ONDULEUR
// Compatible serial + gateway/tcp
//
// QBMS / Q1 simplifiés
// Entités fixées
// Premium calc révisé
//
// A CHANGER SELON LE NOEUD :
//   const inv = 1;   -> onduleur 1
//   const inv = 2;   -> onduleur 2
//   const inv = 3;   -> onduleur 3
// =======================

const inv = 1; // <-- CHANGER ICI : 1 / 2 / 3

const HA_PREFIX = "homeassistant";
const BASE_TOPIC = "voltronic";

// =======================
// Helpers
// =======================
function cleanString(v) {
  return String(v ?? "").trim();
}

function isTwoChoiceOutputPriorityEnabled(inv, cfg) {
  return (
    global.get(`inverter_${inv}.output_priority_2choices`) === true ||
    cfg?.outputPriorityTwoChoices === true
  );
}

function stableObjectId(objectId) {
  return `voltronic_inv${inv}_${objectId}`;
}

function entityDomainFromTopic(topic) {
  const parts = String(topic || "").split("/");
  return parts.length >= 2 ? parts[1] : "sensor";
}

// =======================
// Premium status
// =======================
const premiumActive = global.get("premium.active") === true;

// =======================
// Battery system voltage (24/48)
// =======================
const sysV = Number(
  global.get("config.batterySystemVoltage") ||
  global.get("battery_system_voltage") ||
  48
);
const is24 = (sysV === 24);

const V_RANGES = is24 ? {
  bulk: { min: 24, max: 30, step: 0.1 },
  float: { min: 24, max: 30, step: 0.1 },
  returnGrid: { min: 22, max: 25.5, step: 0.5 },
  reDischarge: { min: 24, max: 29, step: 0.5 },
  under: { min: 20, max: 27, step: 0.5 }
} : {
  bulk: { min: 40, max: 65, step: 0.1 },
  float: { min: 40, max: 65, step: 0.1 },
  returnGrid: { min: 40, max: 65, step: 0.1 },
  reDischarge: { min: 40, max: 65, step: 0.1 },
  under: { min: 40, max: 65, step: 0.1 }
};

// =======================
// Config inverter depuis parse options
// =======================
const invCfgAll = global.get("config.invCfg") || {};
const enabledInvs = Array.isArray(global.get("config.invertersList"))
  ? global.get("config.invertersList").map(Number).filter(n => [1, 2, 3].includes(n))
  : [];

const cfg = invCfgAll[inv] || {};
const enabled = enabledInvs.includes(inv);

// display mode
const displayMode = String(
  global.get(`inverter_${inv}.display_mode`) ||
  cfg.displayMode ||
  "modern"
).trim();

const outputPriorityTwoChoices = isTwoChoiceOutputPriorityEnabled(inv, cfg);

// signature de config pour ce discovery
const signature = JSON.stringify({
  enabled,
  transport: cfg.transport || "",
  serialPort: cfg.serialPort || "",
  gwHost: cfg.gwHost || "",
  gwPort: cfg.gwPort || "",
  batterySystemVoltage: sysV,
  displayMode,
  outputPriorityTwoChoices,
  premiumActive,
  discoveryVersion: "premium_calc_v3_autonomy_score_q1_no_converter_temps_normal_bms_diag"
});

const lastSigKey = `inv${inv}_discovery_signature`;
const topicsKey = `inv${inv}_discovery_topics`;
const lastSig = flow.get(lastSigKey);
const changed = (lastSig !== signature);

// -----------------------
// Jinja helpers (SAFE)
// -----------------------
const jNum = (path, fallback = 0) => `{{ ${path} | default(${fallback}, true) }}`;
const jStr = (path, fallback = "unknown") => `{{ ${path} | default('${fallback}', true) }}`;
const jDeep = (expr) => `{{ ${expr} }}`;

// Common deep roots
const QPIRI = `value_json.get('params', {}).get('qpiri', {})`;
