// MQTT DISCOVERY - VOLTRONIC (SAFE TEMPLATES)
// VERSION PAR ONDULEUR
// Compatible serial + gateway/tcp
//
// QBMS / Q1 simplifiés
// Entités fixées
// Premium calc révisé
//
// A CHANGER SELON LE NOEUD :
//   const inv = 1;   -> onduleur 1
//   const inv = 2;   -> onduleur 2
//   const inv = 3;   -> onduleur 3
// =======================

const inv = 3; // <-- CHANGER ICI : 1 / 2 / 3

const HA_PREFIX = "homeassistant";
const BASE_TOPIC = "voltronic";

// =======================
// Helpers
// =======================
function cleanString(v) {
  return String(v ?? "").trim();
}

function isTwoChoiceOutputPriorityEnabled(inv, cfg) {
  return (
    global.get(`inverter_${inv}.output_priority_2choices`) === true ||
    cfg?.outputPriorityTwoChoices === true
  );
}

function stableObjectId(objectId) {
  return `voltronic_inv${inv}_${objectId}`;
}

function entityDomainFromTopic(topic) {
  const parts = String(topic || "").split("/");
  return parts.length >= 2 ? parts[1] : "sensor";
}

// =======================
// Premium status
// =======================
const premiumActive = global.get("premium.active") === true;

// =======================
// Battery system voltage (24/48)
// =======================
const sysV = Number(
  global.get("config.batterySystemVoltage") ||
  global.get("battery_system_voltage") ||
  48
);
const is24 = (sysV === 24);

const V_RANGES = is24 ? {
  bulk: { min: 24, max: 30, step: 0.1 },
  float: { min: 24, max: 30, step: 0.1 },
  returnGrid: { min: 22, max: 25.5, step: 0.5 },
  reDischarge: { min: 24, max: 29, step: 0.5 },
  under: { min: 20, max: 27, step: 0.5 }
} : {
  bulk: { min: 40, max: 65, step: 0.1 },
  float: { min: 40, max: 65, step: 0.1 },
  returnGrid: { min: 40, max: 65, step: 0.1 },
  reDischarge: { min: 40, max: 65, step: 0.1 },
  under: { min: 40, max: 65, step: 0.1 }
};

// =======================
// Config inverter depuis parse options
// =======================
const invCfgAll = global.get("config.invCfg") || {};
const enabledInvs = Array.isArray(global.get("config.invertersList"))
  ? global.get("config.invertersList").map(Number).filter(n => [1, 2, 3].includes(n))
  : [];

const cfg = invCfgAll[inv] || {};
const enabled = enabledInvs.includes(inv);

// display mode
const displayMode = String(
  global.get(`inverter_${inv}.display_mode`) ||
  cfg.displayMode ||
  "modern"
).trim();

const outputPriorityTwoChoices = isTwoChoiceOutputPriorityEnabled(inv, cfg);

// signature de config pour ce discovery
const signature = JSON.stringify({
  enabled,
  transport: cfg.transport || "",
  serialPort: cfg.serialPort || "",
  gwHost: cfg.gwHost || "",
  gwPort: cfg.gwPort || "",
  batterySystemVoltage: sysV,
  displayMode,
  outputPriorityTwoChoices,
  premiumActive,
  discoveryVersion: "premium_calc_v3_autonomy_score_q1_no_converter_temps_normal_bms_diag"
});

const lastSigKey = `inv${inv}_discovery_signature`;
const topicsKey = `inv${inv}_discovery_topics`;
const lastSig = flow.get(lastSigKey);
const changed = (lastSig !== signature);

// -----------------------
// Jinja helpers (SAFE)
// -----------------------
const jNum = (path, fallback = 0) => `{{ ${path} | default(${fallback}, true) }}`;
const jStr = (path, fallback = "unknown") => `{{ ${path} | default('${fallback}', true) }}`;
const jDeep = (expr) => `{{ ${expr} }}`;

// Common deep roots
const QPIRI = `value_json.get('params', {}).get('qpiri', {})`;
const QDOP = `value_json.get('params', {}).get('qdop', {})`;
const QBMS = `value_json.get('bms', {})`;
const Q1 = `value_json.get('q1', {})`;

// Topics inverter
const base = `${BASE_TOPIC}/${inv}`;
const state_topic = `${base}/state`;
const availability_topic = `${base}/availability`;
const set_base = `${base}/set`;

const device = {
  identifiers: [`voltronic_inv_${inv}`],
  name: `Voltronic Inverter ${inv}`,
  manufacturer: "Voltronic",
  model: "Axpert/Voltronic"
};

const publishedTopics = [];

// =======================
// Display mode helpers
// =======================
function isLegacyMode(mode) {
  return String(mode || "").startsWith("legacy");
}

function getOutputPriorityOptions(mode, twoChoices) {
  if (twoChoices) {
    if (isLegacyMode(mode)) return ["SUB", "SBU"];
    return ["SolarUtilityBat", "SolarBatUtility"];
  }
  if (isLegacyMode(mode)) return ["USB", "SUB", "SBU"];
  return ["UtilitySolarBat", "SolarUtilityBat", "SolarBatUtility"];
}

function getOutputPriorityValueTpl(mode, twoChoices) {
  if (twoChoices) {
    if (isLegacyMode(mode)) {
      return `{% set v = ${QPIRI}.get('output_source_priority') %}
{% if v in ['SUB','SBU'] %}{{ v }}
{% elif v in ['SolarUtilityBat'] %}SUB
{% elif v in ['SolarBatUtility'] %}SBU
{% else %}{{ {0:'SUB',1:'SBU',2:'SBU',3:'SBU'}.get((${QPIRI}.get('output_source_priority_code', 0) | int), 'SUB') }}{% endif %}`;
    }
    return `{% set v = ${QPIRI}.get('output_source_priority') %}
{% if v in ['SolarUtilityBat','SolarBatUtility'] %}{{ v }}
{% elif v in ['SUB'] %}SolarUtilityBat
{% elif v in ['SBU'] %}SolarBatUtility
{% else %}{{ {0:'SolarUtilityBat',1:'SolarBatUtility',2:'SolarBatUtility',3:'SolarBatUtility'}.get((${QPIRI}.get('output_source_priority_code', 0) | int), 'SolarUtilityBat') }}{% endif %}`;
  }

  if (isLegacyMode(mode)) {
    return `{% set v = ${QPIRI}.get('output_source_priority') %}
{% if v in ['USB','SUB','SBU'] %}{{ v }}
{% elif v == 'UtilitySolarBat' %}USB
{% elif v == 'SolarUtilityBat' %}SUB
{% elif v == 'SolarBatUtility' %}SBU
{% else %}{{ {0:'USB',1:'SUB',2:'SBU',3:'SBU'}.get((${QPIRI}.get('output_source_priority_code', 0) | int), 'SBU') }}{% endif %}`;
  }

  return `{% set v = ${QPIRI}.get('output_source_priority') %}
{% if v in ['UtilitySolarBat','SolarUtilityBat','SolarBatUtility'] %}{{ v }}
{% elif v == 'USB' %}UtilitySolarBat
{% elif v == 'SUB' %}SolarUtilityBat
{% elif v == 'SBU' %}SolarBatUtility
{% else %}{{ {0:'UtilitySolarBat',1:'SolarUtilityBat',2:'SolarBatUtility',3:'SolarBatUtility'}.get((${QPIRI}.get('output_source_priority_code', 0) | int), 'SolarBatUtility') }}{% endif %}`;
}

function getChargerPriorityOptions(mode) {
  if (isLegacyMode(mode)) return ["CSO", "SNU", "OSO"];
  return ["Solar first", "Solar + Utility", "Only solar"];
}

function getChargerPriorityValueTpl(mode) {
  if (isLegacyMode(mode)) {
    return `{% set v = ${QPIRI}.get('charger_source_priority') %}
{% if v in ['CSO','SNU','OSO'] %}{{ v }}
{% elif v == 'Solar first' %}CSO
{% elif v == 'Solar + Utility' %}SNU
{% elif v == 'Only solar' %}OSO
{% else %}{{ {0:'CSO',1:'SNU',2:'OSO',3:'OSO'}.get((${QPIRI}.get('charger_source_priority_code', 0) | int), 'CSO') }}{% endif %}`;
  }

  return `{% set v = ${QPIRI}.get('charger_source_priority') %}
{% if v in ['Solar first','Solar + Utility','Only solar'] %}{{ v }}
{% elif v == 'CSO' %}Solar first
{% elif v == 'SNU' %}Solar + Utility
{% elif v == 'OSO' %}Only solar
{% else %}{{ {0:'Solar first',1:'Solar + Utility',2:'Only solar',3:'Only solar'}.get((${QPIRI}.get('charger_source_priority_code', 0) | int), 'Solar first') }}{% endif %}`;
}

