function evalFixed(unit = "") {
    return `
EVAL:function(val) {
  val = Number(val || 0);
  if (!isFinite(val)) val = 0;
  return val.toFixed(2)${unit ? ` + " ${unit}"` : ""};
}`;
}

function evalLegend(unit = "") {
    return `
EVAL:function(seriesName, opts) {
  const val = Number((opts && opts.w && opts.w.globals && opts.w.globals.series && opts.w.globals.series[opts.seriesIndex]) || 0);
  return seriesName + ": " + val.toFixed(2)${unit ? ` + " ${unit}"` : ""};
}`;
}

function evalTotal(unit = "") {
    return `
EVAL:function(w) {
  const totals = Array.isArray(w?.globals?.seriesTotals) ? w.globals.seriesTotals : [];
  const total = totals.reduce((sum, v) => sum + Number(v || 0), 0);
  return total.toFixed(2)${unit ? ` + " ${unit}"` : ""};
}`;
}

