function cardStyle(kind = "neutral", extra = "") {
    if (!HAS_CARD_MOD) return {};

    const accent = accentColor(kind);

    return {
        card_mod: {
            style: `
                ha-card {
                    background: var(--ha-card-background, var(--card-background-color));
                    color: var(--primary-text-color);
                    border-radius: 24px;
                    border: 1px solid var(--divider-color);
                    box-shadow:
                        0 6px 18px rgba(0,0,0,0.10),
                        0 1px 2px rgba(0,0,0,0.06);
                    overflow: hidden;
                    position: relative;
                    ${extra}
                }

                ha-card::before {
                    content: "";
                    position: absolute;
                    top: 0;
                    left: 0;
                    right: 0;
                    height: 4px;
                    background: ${accent};
                    opacity: 0.95;
                    z-index: 1;
                }

                .card-header,
                .primary,
                .name,
                .value,
                .state {
                    color: var(--primary-text-color) !important;
                }

                .secondary,
                .secondary-text {
                    color: var(--secondary-text-color) !important;
                }
            `
        }
    };
}

function sectionBandStyle(kind = "neutral", extra = "") {
    if (!HAS_CARD_MOD) return {};

    const accent = accentColor(kind);

    return {
        card_mod: {
            style: `
                ha-card {
                    background: var(--ha-card-background, var(--card-background-color));
                    color: var(--primary-text-color);
                    border-radius: 22px;
