                    position: relative;
                    ${extra}
                }

                ha-card::before {
                    content: "";
                    position: absolute;
                    top: 0;
                    left: 0;
                    bottom: 0;
                    width: 5px;
                    background: ${accent};
                    opacity: 0.95;
                    z-index: 1;
                }

                ha-card h1,
                ha-card h2,
                ha-card h3,
                ha-card strong {
                    color: var(--primary-text-color) !important;
