function powerHistory(inv) {
    if (HAS_APEXCHARTS) {
        return {
            type: "custom:apexcharts-card",
            graph_span: "24h",
            span: { start: "day" },
            header: {
                show: true,
                title: `${t.power_history} ${inv}`,
                show_states: true,
                colorize_states: true
            },
            apex_config: {
                chart: {
                    height: 390,
                    toolbar: { show: false },
                    zoom: { enabled: false }
                },
                legend: {
                    show: true,
                    position: "bottom",
                    fontSize: "12px",
                    labels: {
                        colors: "var(--primary-text-color)"
                    },
                    formatter: evalLegend("W")
                },
                stroke: {
                    width: [3, 3, 2, 3],
                    curve: "smooth"
                },
                fill: {
                    type: ["solid", "gradient", "solid", "gradient"],
                    opacity: [0.10, 0.22, 0.08, 0.20],
                    gradient: {
                        shade: "dark",
                        type: "vertical",
                        shadeIntensity: 0.15,
                        inverseColors: false,
                        opacityFrom: 0.30,
                        opacityTo: 0.02,
                        stops: [0, 90, 100]
                    }
                },
                colors: ["#f59e0b", "#38bdf8", "#ef4444", "#a855f7"],
                grid: {
                    borderColor: "var(--divider-color)",
                    strokeDashArray: 3
                },
                dataLabels: {
                    enabled: false
                },
                markers: {
                    size: 0,
                    hover: { size: 5 }
                },
                tooltip: {
                    shared: false,
                    intersect: false,
                    theme: "dark",
                    y: {
                        formatter: evalFixed("W")
                    }
                },
                yaxis: {
                    decimalsInFloat: 2,
                    labels: {
                        style: {
                            colors: "var(--secondary-text-color)"
                        },
                        formatter: `
EVAL:function(val) {
  val = Number(val || 0);
  if (!isFinite(val)) val = 0;
  return val.toFixed(2);
}`
                    }
                },
                xaxis: {
                    labels: {
                        style: {
                            colors: "var(--secondary-text-color)"
                        }
                    }
                }
            },
            all_series_config: {
                float_precision: 2,
