// -------------------------
// Build dashboard
// -------------------------
const invs = enabledInverters();

if (!invs.length) {
    node.warn(t.no_inverter);
    return null;
}

const overviewViewCards = [];
const energyViewCards = [];
const parameterViewCards = [];
const healthDiagViewCards = [];

const warning = missingCardsWarning();
if (warning) {
    overviewViewCards.push(warning);
}

for (const inv of invs) {
    overviewViewCards.push(overviewCards(inv));
    energyViewCards.push(energyCards(inv));
    parameterViewCards.push(parameterCards(inv));
    healthDiagViewCards.push(healthDiagCards(inv));
}

const dashboard = {
    dashboard_meta: {
        url_path: "smart-voltronic",
        title: "Smart Voltronic",
        icon: "mdi:solar-power",
        show_in_sidebar: true
    },
    config: {
        views: [
            {
                title: t.view_overview,
                path: "overview",
                icon: "mdi:home-analytics",
                cards: overviewViewCards
            },
            {
                title: t.view_energy,
                path: "energy",
                icon: "mdi:chart-box",
                cards: energyViewCards
            },
            {
                title: t.view_parameters,
                path: "parameters",
                icon: "mdi:tune",
                cards: parameterViewCards
            },
            {
                title: t.view_health_diag,
                path: "health-diag",
                icon: "mdi:stethoscope",
                cards: healthDiagViewCards
            }
        ]
    }
};

if (customCardsInstalled) {
    node.log(`Dashboard premium généré [lang=${lang}]`);
} else {
    node.warn(`Dashboard premium généré en mode dégradé [lang=${lang}]`);
}

msg.payload = JSON.stringify(dashboard, null, 2);
