<script>
let WS=null, HA_TOKEN=null, STATES={}, PERIOD='day', ECO_PERIOD='daily';
let RENDERED_INV_COUNT=0, RENDERED_BMS_COUNT=0;

const E={
  pv:['sensor.voltronic_global_pv_power','sensor.voltronic_global_pv_total_power'],
  load:['sensor.voltronic_global_load_power','sensor.voltronic_global_ac_output_active_power'],
  grid:['sensor.voltronic_global_grid_power'],
  charge:['sensor.voltronic_global_battery_charge_power','sensor.voltronic_global_battery_charge'],
  discharge:['sensor.voltronic_global_battery_discharge_power','sensor.voltronic_global_battery_discharge'],
  soc:['sensor.voltronic_global_battery_soc','sensor.voltronic_global_battery_capacity'],
  battV:['sensor.voltronic_global_battery_voltage'],
  pvDay:['sensor.voltronic_global_pv_today_kwh','sensor.voltronic_global_pv_energy_day_kwh','sensor.voltronic_global_pv_today'],
  loadDay:['sensor.voltronic_global_load_today_kwh','sensor.voltronic_global_load_energy_day_kwh','sensor.voltronic_global_load_today'],
  gridDay:['sensor.voltronic_global_grid_today_kwh','sensor.voltronic_global_grid_energy_day_kwh','sensor.voltronic_global_grid_today'],
  chargeDay:['sensor.voltronic_global_battery_charge_today_kwh','sensor.voltronic_global_battery_charge_day_kwh','sensor.voltronic_global_battery_charge_today'],
  dischargeDay:['sensor.voltronic_global_battery_discharge_today_kwh','sensor.voltronic_global_battery_discharge_day_kwh','sensor.voltronic_global_battery_discharge_today'],
  pvMonth:['sensor.voltronic_global_pv_month_kwh','sensor.voltronic_global_pv_energy_month_kwh','sensor.voltronic_global_pv_month'],
  loadMonth:['sensor.voltronic_global_load_month_kwh','sensor.voltronic_global_load_energy_month_kwh','sensor.voltronic_global_load_month'],
  gridMonth:['sensor.voltronic_global_grid_month_kwh','sensor.voltronic_global_grid_energy_month_kwh','sensor.voltronic_global_grid_month'],
  chargeMonth:['sensor.voltronic_global_battery_charge_month_kwh','sensor.voltronic_global_battery_charge_month'],
  dischargeMonth:['sensor.voltronic_global_battery_discharge_month_kwh','sensor.voltronic_global_battery_discharge_month'],
  pvYear:['sensor.voltronic_global_pv_year_kwh','sensor.voltronic_global_pv_energy_year_kwh','sensor.voltronic_global_pv_year'],
  loadYear:['sensor.voltronic_global_load_year_kwh','sensor.voltronic_global_load_energy_year_kwh','sensor.voltronic_global_load_year'],
  gridYear:['sensor.voltronic_global_grid_year_kwh','sensor.voltronic_global_grid_energy_year_kwh','sensor.voltronic_global_grid_year'],
  chargeYear:['sensor.voltronic_global_battery_charge_year_kwh','sensor.voltronic_global_battery_charge_year'],
  dischargeYear:['sensor.voltronic_global_battery_discharge_year_kwh','sensor.voltronic_global_battery_discharge_year'],
  pvTotal:['sensor.voltronic_global_pv_total_kwh','sensor.voltronic_global_pv_energy_total_kwh','sensor.voltronic_global_pv_total'],
  loadTotal:['sensor.voltronic_global_load_total_kwh','sensor.voltronic_global_load_energy_total_kwh','sensor.voltronic_global_load_total'],
  gridTotal:['sensor.voltronic_global_grid_total_kwh','sensor.voltronic_global_grid_energy_total_kwh','sensor.voltronic_global_grid_total'],
  chargeTotal:['sensor.voltronic_global_battery_charge_total_kwh','sensor.voltronic_global_battery_charge_total'],
  dischargeTotal:['sensor.voltronic_global_battery_discharge_total_kwh','sensor.voltronic_global_battery_discharge_total'],
  solarPct:['sensor.voltronic_global_solar_supply_today_pct','sensor.voltronic_global_solar_supply_today'],
  batPct:['sensor.voltronic_global_battery_supply_today_pct','sensor.voltronic_global_battery_supply_today'],
  gridPct:['sensor.voltronic_global_grid_supply_today_pct','sensor.voltronic_global_grid_supply_today'],
  gridDep:['sensor.voltronic_global_grid_dependency_today_pct','sensor.voltronic_global_grid_dependency_today'],
  autonomy:['sensor.voltronic_global_energy_autonomy_score'],
  autonomyState:['sensor.voltronic_global_energy_autonomy_state'],
  count:['sensor.voltronic_global_inverter_count']
};

function $(id){return document.getElementById(id)}
function n(v){const x=parseFloat(v);return Number.isFinite(x)?x:0}
function bad(v){return v==null||['unknown','unavailable','none',''].includes(String(v).toLowerCase())}
function valid(id){return STATES[id]&&!bad(STATES[id].state)}
function state(ids,d='--'){for(const id of ids){if(valid(id))return STATES[id].state}return d}
function num(ids){return n(state(ids,0))}
function set(id,v){const e=$(id);if(e)e.textContent=v}
function sensor(i,s){return \`sensor.voltronic_inv\${i}_\${s}\`}
function number(i,s){return \`number.voltronic_inv\${i}_param_\${s}\`}
function select(i,s){return \`select.voltronic_inv\${i}_param_\${s}\`}
function invNum(i,s,a=[]){return num([sensor(i,s),...a.map(x=>sensor(i,x))])}
function invState(i,s,a=[]){return state([sensor(i,s),...a.map(x=>sensor(i,x))])}
function bmsEntity(i,slug){return \`sensor.bms_\${i}_\${slug}\`}
function bmsState(i,slug,def='--'){return state([bmsEntity(i,slug)],def)}
function bmsNum(i,slug){return n(bmsState(i,slug,0))}
function fmt(v,d=2){return Number.isFinite(v)?v.toFixed(d):'--'}
function pctSafe(v,total){return total>0?(v/total*100):0}
function entityAttr(id,attr,def=null){return STATES[id]?.attributes?.[attr] ?? def}

function moreInfo(entityId){
