}
function liveEcoFallback(period,key){
  const now=new Date();
  const isCurrent=(period==='daily' && key===dayKey(now)) || (period==='monthly' && key===monthKey(now)) || (period==='yearly' && key===yearKey(now));
  if(!isCurrent) return null;
  if(period==='daily'){
    const total=ecoVal('sensor.smart_energy_finance_day_savings_vs_no_solar');
    const battery=ecoVal('sensor.smart_energy_finance_battery_day_savings') || ecoVal('sensor.smart_energy_finance_battery_day_discharge_value');
    const solar=Math.max(0,total-battery);
    return {solar,battery,total:total || solar+battery};
  }
  if(period==='monthly'){
    const total=ecoVal('sensor.smart_energy_finance_month_savings_vs_no_solar');
    const battery=ecoVal('sensor.smart_energy_finance_battery_month_savings') || ecoVal('sensor.smart_energy_finance_battery_month_discharge_value');
    const solar=Math.max(0,total-battery);
    return {solar,battery,total:total || solar+battery};
  }
  const total=ecoVal('sensor.smart_energy_finance_year_savings_vs_no_solar');
  const battery=ecoVal('sensor.smart_energy_finance_battery_year_savings') || ecoVal('sensor.smart_energy_finance_battery_year_discharge_value');
  const solar=Math.max(0,total-battery);
