function updateBms(){
  const ids=getBmsIds(); let totalSoc=0,socCount=0,totalPower=0,totalCurrent=0,totalVolt=0,voltCount=0,maxDelta=0,online=0;
  for(const i of ids){const soc=bmsNum(i,'soc_pourcentage'), p=bmsNum(i,'puissance_totale'), a=bmsNum(i,'courant_total'), v=bmsNum(i,'tension_totale_volt'), d=bmsNum(i,'cell_voltage_delta'); if(soc>0){totalSoc+=soc;socCount++;online++} if(v>0){totalVolt+=v;voltCount++} totalPower+=p; totalCurrent+=a; maxDelta=Math.max(maxDelta,d)}
  set('bms_count_side',online||ids.length); const avgSoc=socCount?totalSoc/socCount:0, avgVolt=voltCount?totalVolt/voltCount:0;
  const nav=$('bms_subnav'); if(nav)nav.innerHTML=\`<button class="bms-subtab \${BMS_VIEW==='overview'?'active':''}" data-bms-overview="1" onclick="event.preventDefault();event.stopPropagation();setBmsView('overview')">Vue globale</button>\`;
  const sum=$('bms_summary'); if(sum)sum.innerHTML=[card('Batteries online',online||ids.length,'/ '+ids.length,'bat'),card('SOC moyen',Math.round(avgSoc),'%','bat'),card('Puissance totale',Math.round(totalPower),'W',totalPower>=0?'bat':'red'),card('Courant total',totalCurrent.toFixed(1),'A',totalCurrent>=0?'bat':'red'),card('Tension moyenne',avgVolt.toFixed(2),'V','gridc'),card('Delta max',maxDelta.toFixed(3),'V',maxDelta>0.020?'orange':'load')].join('');
  const box=$('bms_cards'); if(!box)return; if(window.__svEditing && box.contains(document.activeElement)) return;
  if(BMS_VIEW==='overview' || !ids.includes(Number(BMS_VIEW))){box.className='bms-wall'; box.innerHTML=ids.map(i=>renderBmsMiniCard(i)).join(''); return}
  box.className=''; box.innerHTML=bmsDetail(Number(BMS_VIEW));
}
