function findAccessToken(obj, depth=0){
  if(!obj || depth>8) return null;
  if(typeof obj === 'string'){
    const t=obj.trim();
    if(t.length>40 && (t.split('.').length>=2 || t.startsWith('eyJ'))) return t;
    return null;
  }
  if(typeof obj !== 'object') return null;
  for(const k of ['access_token','accessToken','token','llat']){
    if(typeof obj[k] === 'string' && obj[k].length>30) return obj[k];
  }
  for(const v of Object.values(obj)){
    const found=findAccessToken(v, depth+1);
    if(found) return found;
  }
  return null;
}
function getTokenOriginalHaStorage(){
  try{
    for(const k of Object.keys(localStorage||{})){
      if(String(k).toLowerCase().includes('hasstokens')){
        try{
          const raw=JSON.parse(localStorage.getItem(k));
          if(raw?.access_token) return raw.access_token;
          if(raw?.data){
            const first=Object.values(raw.data)[0];
            if(first?.access_token) return first.access_token;
            const found=findAccessToken(first); if(found) return found;
          }
          const found=findAccessToken(raw); if(found) return found;
        }catch(e){}
      }
    }
  }catch(e){}
  return null;
}
function getTokenFromStorageArea(store){
  try{
    if(!store) return null;
    const manual=store.getItem('smart_voltronic_ha_token') || store.getItem('sv_ha_token');
    if(manual && manual.length>30) return manual.trim();
    const keys=[];
    for(let i=0;i<store.length;i++) keys.push(store.key(i));
    keys.sort((a,b)=>{
      const aa=String(a).toLowerCase(), bb=String(b).toLowerCase();
      return (bb.includes('hass')||bb.includes('token'))-(aa.includes('hass')||aa.includes('token'));
    });
    for(const k of keys){
      try{
        const val=store.getItem(k);
        if(!val) continue;
        const lk=String(k).toLowerCase();
        if(lk.includes('hass') || lk.includes('token') || String(val).includes('access_token') || String(val).includes('accessToken')){
          let raw=val;
          try{ raw=JSON.parse(val); }catch(e){}
          const found=findAccessToken(raw);
          if(found) return found;
        }
      }catch(e){}
    }
  }catch(e){}
  return null;
}
async function getTokenFromHassConnection(){
  const candidates=[];
  try{candidates.push(window.hassConnection)}catch(e){}
  try{if(window.parent && window.parent!==window) candidates.push(window.parent.hassConnection)}catch(e){}
  try{candidates.push(window.hass?.connection)}catch(e){}
  try{if(window.parent && window.parent!==window) candidates.push(window.parent.hass?.connection)}catch(e){}
  for(const c of candidates){
    try{
      const resolved=(c && typeof c.then==='function') ? await c : c;
      if(!resolved) continue;
      const found=findAccessToken(resolved); if(found) return found;
      const auth=resolved?.conn?.options?.auth || resolved?.options?.auth || resolved?.auth;
      if(auth){
        if(typeof auth.accessToken==='string') return auth.accessToken;
        if(typeof auth.accessToken==='function'){
          const t=await auth.accessToken(); if(t) return t;
        }
        const foundAuth=findAccessToken(auth); if(foundAuth) return foundAuth;
      }
    }catch(e){}
  }
  return null;
}
function tokenFromUrl(){
  try{
    const u=new URL(location.href);
    const q=u.searchParams.get('token') || u.searchParams.get('ha_token');
    if(q && q.length>30) return q.trim();
    const m=String(location.hash||'').match(/(?:token|ha_token)=([^&]+)/i);
    if(m) return decodeURIComponent(m[1]).trim();
  }catch(e){}
  return null;
}
async function getToken(){
  const t = tokenFromUrl()
    || getTokenOriginalHaStorage()
    || getTokenFromStorageArea(window.localStorage)
    || getTokenFromStorageArea(window.sessionStorage)
    || (()=>{try{return getTokenFromStorageArea(window.parent?.localStorage)}catch(e){return null}})()
    || (()=>{try{return getTokenFromStorageArea(window.parent?.sessionStorage)}catch(e){return null}})()
    || await getTokenFromHassConnection();
  if(t){
    try{ localStorage.setItem('smart_voltronic_ha_token', t); }catch(e){}
  }
  return t;
}
