  function findEntity(candidates,wordSets,domain){for(const id of candidates){if(state(id))return id}const ids=Object.keys(states());for(const words of wordSets){const hit=ids.find(id=>(!domain||id.startsWith(domain+'.'))&&words.every(w=>hay(id).includes(low(w))));if(hit)return hit}return candidates[0]}
  function first(ids,wordSets=[],domain){return findEntity(ids,wordSets,domain)}
